// ---------------------------------------------------------------------------
// Sprint 11 — Real per-student accounts (name + PIN) instead of name-only.
//
// Supabase Anonymous Auth has no way to "log back in" to the same identity
// from a different device with just a name, so each account is a real
// email/password Supabase Auth user under the hood — the "email" is just
// `<name>@chaachaa-angkrit-app.com` (never a real mailbox) and the "password" is
// the student's 4-digit PIN. This gives every student a stable, unique
// auth.uid() that Postgres Row-Level-Security can lock their data to,
// instead of the old plain-text `username` column anyone could read/write.
// ---------------------------------------------------------------------------
// Typography constants — change font here, takes effect everywhere in this file
const FONT_ENGLISH = "'Poppins', sans-serif";   // language being learned (English)
const FONT_THAI    = "'Sarabun', sans-serif";    // students' native language (Thai)

const AUTH_DOMAIN         = "chaachaa-angkrit-app.com"; // NOTE: fake per-student email domain, never
                                                     // actually sent to. Must NOT be a reserved/
                                                     // special-use TLD (.local, .test, .example,
                                                     // .invalid, .internal, etc) — Supabase Auth
                                                     // rejects those as "invalid" on signUp.
const LEGACY_AUTH_DOMAINS = ["chaachaa-angrueit-app.com"]; // Pre-rename domain (Angrueit → Angkrit).
                                                     // Accounts created before the rename still have
                                                     // this as their real Supabase Auth email domain —
                                                     // kept as a login fallback so those students
                                                     // aren't locked out. New accounts always use
                                                     // AUTH_DOMAIN above.
const PIN_PASSWORD_PREFIX = "chaa-pin-"; // pads the 4-digit PIN past Supabase's min password length
const ACCOUNT_PREFIX      = "account:";  // shared_kv account:<slug> -> { createdAt } (marks "PIN already set")

function slugifyUsername(username) {
  return (username || "")
    .normalize("NFD").replace(/[\u0300-\u036f]/g, "") // strip accents
    .trim().toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-+|-+$/g, "") || "user";
}
function usernameToEmail(username, domain = AUTH_DOMAIN) { return `${slugifyUsername(username)}@${domain}`; }
function pinToPassword(pin)        { return `${PIN_PASSWORD_PREFIX}${pin}`; }

function sessionStorageKey(slug) { return `sb-session:${slug}`; }
function saveSession(slug, session) {
  if (!session) return;
  try {
    localStorage.setItem(sessionStorageKey(slug), JSON.stringify({
      access_token: session.access_token, refresh_token: session.refresh_token,
    }));
  } catch (e) {}
}

// Resume a previously-authenticated student on this device without asking
// for their PIN again (until they explicitly log out).
async function restoreSession(username) {
  const slug = slugifyUsername(username);
  let raw;
  try { raw = localStorage.getItem(sessionStorageKey(slug)); } catch (e) { return null; }
  if (!raw) return null;
  try {
    const { access_token, refresh_token } = JSON.parse(raw);
    const client = await getSupabaseClient();
    const { data, error } = await client.auth.setSession({ access_token, refresh_token });
    if (error || !data?.user) return null;
    setStorageAuthState(data.user, username);
    saveSession(slug, data.session);
    return data.user;
  } catch (e) { return null; }
}

// Sign in (existing account) or sign up (first time this name sets a PIN).
// Throws a user-facing error message on failure (wrong PIN, etc).
async function authenticateAccount(username, pin) {
  const client = await getSupabaseClient();
  const email  = usernameToEmail(username);
  const password = pinToPassword(pin);
  const slug   = slugifyUsername(username);

  const hasAccount = await storageGet(`${ACCOUNT_PREFIX}${slug}`, true);

  if (hasAccount) {
    let signInResult = await client.auth.signInWithPassword({ email, password });

    // Accounts created before the Angkrit rename live under LEGACY_AUTH_DOMAINS
    // instead of AUTH_DOMAIN — retry with each before giving up (see ADR on the
    // Angrueit → Angkrit migration in docs/decisions.md).
    if (signInResult.error || !signInResult.data?.user) {
      for (const domain of LEGACY_AUTH_DOMAINS) {
        const legacyResult = await client.auth.signInWithPassword({
          email: usernameToEmail(username, domain), password,
        });
        if (!legacyResult.error && legacyResult.data?.user) { signInResult = legacyResult; break; }
      }
    }

    const { data, error } = signInResult;
    if (error || !data?.user) throw new Error("PIN ไม่ถูกต้องสำหรับชื่อนี้");
    setStorageAuthState(data.user, username);
    saveSession(slug, data.session);
    return data.user;
  }

  // New name (or a legacy pre-PIN account) — create the real account now.
  const { data, error } = await client.auth.signUp({ email, password });

  if (error || !data?.user) {
    // The account:<slug> marker in shared_kv can get out of sync with the
    // real Supabase Auth users table (e.g. the marker write failed/was lost,
    // or the account was created through a different path before the marker
    // existed). In that case Auth already knows this email but our marker
    // says "never seen" — signUp then fails with "User already registered".
    //
    // Recover by trying to sign in instead: if the PIN the student just
    // typed happens to match the existing account, log them in and backfill
    // the missing marker so this doesn't happen again. If it doesn't match,
    // we genuinely don't know the original PIN — tell the student their
    // account already exists so they try their real PIN, instead of the
    // confusing raw Supabase error.
    const alreadyRegistered = /already registered|already exists/i.test(error?.message || "");
    if (alreadyRegistered) {
      const retry = await client.auth.signInWithPassword({ email, password });
      if (!retry.error && retry.data?.user) {
        setStorageAuthState(retry.data.user, username);
        saveSession(slug, retry.data.session);
        await storageSet(`${ACCOUNT_PREFIX}${slug}`, { createdAt: Date.now() }, true); // backfill marker
        return retry.data.user;
      }
      throw new Error("ชื่อนี้มีอยู่แล้ว — กรุณาใส่ PIN เดิมของคุณ");
    }
    throw new Error("Could not create your account: " + (error?.message || "unknown error"));
  }

  setStorageAuthState(data.user, username);
  saveSession(slug, data.session);
  await storageSet(`${ACCOUNT_PREFIX}${slug}`, { createdAt: Date.now() }, true);

  // Claim any pre-existing rows saved under this exact name before PINs
  // existed (old anonymous system), so returning students keep their history.
  try {
    await client.from("personal_kv")
      .update({ user_id: data.user.id })
      .eq("username", username)
      .is("user_id", null);
  } catch (e) { /* best-effort, ignore */ }

  return data.user;
}

