// #699 — maps each class code prefix to its CEFR level name
const CODE_TO_LEVEL = {
  S0: "Pre-A1", S1: "Pre-A1",
  S2: "A1",     S3: "A1",
  S4: "A2",     S5: "A2",
  S6: "B1",     S7: "B1",  S8: "B1",
  S9: "B2",     S10: "B2",
  S11: "C1",    S12: "C1",
  S13: "C2",    S14: "C2",
};
function codeToLevel(classCode) {
  if (!classCode) return null;
  const prefix = classCode.match(/^(S\d+)/)?.[1];
  return CODE_TO_LEVEL[prefix] || null;
}
// #793 — resolves cefrLevel from stored meta first; S0/S1 hardcoded as Pre-A1
function resolveCodeLevel(code, metaMap = {}) {
  const prefix = code?.match(/^(S\d+)/)?.[1];
  if (prefix === "S0" || prefix === "S1") return "Pre-A1";
  return metaMap[code]?.cefrLevel || null;
}
