// #526 — versioning system: vite injects "X.Y.Z|hash"; we format with codename
const _APP_VERSION_RAW = import.meta.env.VITE_APP_VERSION || "0.2.0|dev";
const _APP_CODENAMES   = ["", "Siamese", "Ragdoll", "Bengal", "Maine Coon", "Abyssinian", "Persian", "Sphynx", "Scottish Fold", "Birman", "Norwegian Forest", "Burmese", "Tonkinese", "Balinese", "Savannah", "Turkish Angora", "Russian Blue", "Korat", "Chartreux", "Havana Brown", "Singapura", "Khao Manee", "Devon Rex", "Cornish Rex", "Siberian", "Manx"];
function _buildAppVersion(raw) {
  const [ver, hash] = raw.split("|");
  const minor = parseInt((ver || "0.2.0").split(".")[1] || "0", 10);
  const major  = parseInt((ver || "0.2.0").split(".")[0] || "0", 10);
  const name   = _APP_CODENAMES[minor] || `v${minor}`;
  return major >= 1
    ? `${name} Version - ${ver} - ${hash}`
    : `${ver} - Project ${name} - ${hash}`;
}
const APP_VERSION = _buildAppVersion(_APP_VERSION_RAW); // #526
const SECURITY_QUESTION_KEY   = (slug) => `security-question:${slug}`; // shared: { question, answerHash } — #518

// #518 — fixed list of recovery questions
