// #518 — SHA-256 hex of answer (trimmed + lowercased), computed client-side
async function hashAnswer(answer) {
  const buf = await crypto.subtle.digest("SHA-256", new TextEncoder().encode(answer.trim().toLowerCase()));
  return Array.from(new Uint8Array(buf)).map(b => b.toString(16).padStart(2, "0")).join("");
}

// Save or update security question for the current student (shared_kv, keyed by slug)
async function saveSecurityQuestion(username, question, answer) {
  const slug = username.trim().toLowerCase();
  const answerHash = await hashAnswer(answer);
  await storageSet(SECURITY_QUESTION_KEY(slug), { question, answerHash }, true);
}

// Load security question text for any username (shared_kv — readable without login)
// Returns { question } or null if not set.
async function loadSecurityQuestion(username) {
  const slug = username.trim().toLowerCase();
  const stored = await storageGet(SECURITY_QUESTION_KEY(slug), true);
  if (!stored?.question) return null;
  return { question: stored.question };
}

// ---------------------------------------------------------------------------
// Sprint 9.2 — Achievement engine
// ---------------------------------------------------------------------------
async function runAchievementEngine(stats, rewardOverrides, { onRareTicket, onEpicTicket, onAvatarPrize } = {}) {
  const prev    = await storageGet(UNLOCKED_ACH_KEY, false) || [];
  const prevSet = new Set(prev);
  const current = getUnlockedIds(stats);
  const newOnes = current
    .filter(id => !prevSet.has(id))
    .map(id => ACHIEVEMENTS.find(a => a.id === id))
    .filter(Boolean);
  const merged = [...new Set([...prev, ...current])];
  await storageSet(UNLOCKED_ACH_KEY, merged, false);
  // Issue #231/#234 — credit Meowtongs for everything unlocked in this pass,
  // using the teacher's override when one is set for that achievement.
  const coinsEarned = newOnes.reduce((sum, a) => sum + getAchievementValue(a, rewardOverrides), 0);
  if (coinsEarned > 0) await creditCoins(coinsEarned, "Achievement unlocked");
  // Issue #499 — award Moonrise Tickets for achievements carrying ticket: "rare"
  const rareTicketsEarned = newOnes.filter(a => a.ticket === "rare").length;
  if (rareTicketsEarned > 0) {
    const tickets = (await storageGet("gacha-tickets", false)) || {};
    await storageSet("gacha-tickets", { ...tickets, rare: (tickets.rare || 0) + rareTicketsEarned }, false);
    await onRareTicket?.(rareTicketsEarned);
  }
  // Issue #557 — Starlight Tickets for achievements carrying ticket: "epic"
  const epicTicketsEarned = newOnes.filter(a => a.ticket === "epic").length;
  if (epicTicketsEarned > 0) {
    const tickets = (await storageGet("gacha-tickets", false)) || {};
    await storageSet("gacha-tickets", { ...tickets, epic: (tickets.epic || 0) + epicTicketsEarned }, false);
    await onEpicTicket?.(epicTicketsEarned);
  }
  // Issue #556 — Avatar prize for achievements carrying avatarPrize: "<id>"
  const avatarPrizes = newOnes.filter(a => a.avatarPrize).map(a => a.avatarPrize);
  for (const avatarId of avatarPrizes) {
    await onAvatarPrize?.(avatarId);
  }
  return { newOnes, total: merged.length, merged, coinsEarned, rareTicketsEarned, epicTicketsEarned, avatarPrizes };
}

