const ACH_CAT_LABELS = { streak: "Streak", vocab: "Vocabulary", sunday: "Sunday Test", practice: "Practice", path: "Lesson Path", exam: "Exam", pronunciation: "Pronunciation", special: "Special", secret: "Secret", level: "Level", berserk: "Berserk Mode", calligrapher: "Calligraphy" };
const ACH_CAT_ICONS = { streak: "🔥", vocab: "📖", sunday: "📅", practice: "✏️", path: "🗺️", exam: "📝", pronunciation: "🎙️", special: "⭐", secret: "🔮", level: "📊", berserk: "⚡", calligrapher: "🖌️" };

// Issue #234 — teacher-editable Meowtongs reward per achievement, defaulting
// to the difficulty-scaled `value` above. Shared KV: { [achievementId]: number }.
const ACHIEVEMENT_REWARD_OVERRIDES_KEY = "achievement-reward-overrides";

function getAchievementValue(achievement, overrides) {
  const ov = overrides?.[achievement.id];
  return (typeof ov === "number" && ov >= 0) ? ov : (achievement.value || 0);
}

async function getAchievementRewardOverrides() {
  return (await storageGet(ACHIEVEMENT_REWARD_OVERRIDES_KEY, true)) || {};
}

// Compute all stats needed for achievement checks
function computeAchievementStats(progMap, streak, stHistory, sessionsCompleted, profile, extra = {}) {
  const { examHistory = [], gachaTickets = {}, words = [], berserkStars = {}, berserkAttempts = 0, calligraphyProg = {}, wordCalligraphyProg = {}, pathStats = {}, onboardingMeta = null, visitedEventsTab = false, visitedProgressTab = false, dailyRewardTickets = null, usedDailyDouble = false, comboCount = 0, perfectSessions = 0, loginBonusTotal = 0, loginBonusWeekFull = false, loginBonusGotStarlight = false, loginBonusStreakDays = 0 } = extra;
  const vals    = Object.values(progMap);
  const perfect = stHistory.filter(s => {
    const rs = Object.values(s.results || {});
    return rs.length > 0 && rs.every(r => r.correct);
  }).length;
  // Issue #237 — pronunciation mastery: words with an average STT score >= 90.
  const pronMasteredCount = words.length
    ? computePronStats(progMap, words).filter(p => p.avgScore >= 90).length
    : 0;
  const streakBest  = streak?.best  || 0;
  const streakCount = streak?.count || 0;
  return {
    streakBest:          streakBest || streakCount,
    wordsAttempted:      vals.filter(p => p.count > 0).length,
    wordsMastered:       vals.filter(p => p.srsInterval >= 14).length,
    sundayTestCount:     stHistory.length,
    perfectSundayTests:  perfect,
    sessionsCompleted:   sessionsCompleted || 0,
    // Issue #180 — Collector achievement needs to see which avatars are owned
    unlockedAvatars:     profile?.unlockedAvatars || [],
    // Issue #237 — Exam Master: any passed exam / any 100% exam, any level.
    examPassedAny:       examHistory.some(e => e.passed),
    examPerfectAny:      examHistory.some(e => e.pct === 100),
    // Issue #237 — Pronunciation: 10 words with avg STT score 90%+.
    pronMasteredCount,
    // Issue #237 — Comeback: once had a 7+ day streak, it broke, and the
    // student rebuilt at least 3 days of a new one since.
    comebackAchieved:    streakBest >= 7 && streakCount >= 3 && streakCount < streakBest,
    // Issue #237 — Gacha: acquired at least one ticket (rare or epic), ever.
    gachaTicketAcquired: ((gachaTickets.rare || 0) + (gachaTickets.epic || 0)) >= 1,
    // Issue #45.1 — Level Completed: true once the student has ever advanced
    // past the starting level (Pre-A1). LEVELS is declared later in this file
    // as a module-level const — safe to reference here since this function
    // only ever runs post-module-eval, well after LEVELS is assigned.
    levelUpAny: LEVELS.indexOf(profile?.level || "Pre-A1") >= 1,
    // Issue #45.2 — Pre-A1 -> A1-specific, keyed off examHistory's per-level
    // attemptNumber (already recorded by recordExamAttempt since #43 — no
    // new tracking needed). Exam entries carry `level` = the level BEING
    // tested (i.e. "Pre-A1" is the exam that, if passed, advances to A1).
    examPreA1FirstAttemptPass: examHistory.some(e => e.level === "Pre-A1" && e.attemptNumber === 1 && e.passed),
    examPreA1FirstAttemptFail: examHistory.some(e => e.level === "Pre-A1" && e.attemptNumber === 1 && !e.passed),
    // Issue #52.4 — Berserk Mode achievements.
    berserkAttempts:      berserkAttempts || 0,
    berserkEasyCleared:   !!berserkStars.easy,
    berserkMediumCleared: !!berserkStars.medium,
    berserkHardCleared:   !!berserkStars.hard,
    // Issue #358 — Calligraphy achievements, sourced from calligraphyProgMap
    // (#62). "Passed" = at least 1 successful full-character trace; scope is
    // the 44 consonants only for now (vowels/tones are stretch goal #63/#356).
    calligraphyCharsPassed:     Object.values(calligraphyProg).filter(p => (p?.passes || 0) >= 1).length,
    calligraphyAlphabetComplete: Object.keys(ENGLISH_STROKES).every(ch => (calligraphyProg[ch]?.passes || 0) >= 1),
    // Issue #415 — word-level writing achievements
    wordCalligraphyWordsAttempted: Object.values(wordCalligraphyProg).filter(p => (p?.attempts || 0) >= 1).length,
    wordCalligraphyWordsPassed:    Object.values(wordCalligraphyProg).filter(p => (p?.passes   || 0) >= 1).length,
    // Issue #499 — Lesson Path achievements
    pathLessonsCompleted:    pathStats.lessonsCompleted   || 0,
    pathSectionsCompleted:   pathStats.sectionsCompleted  || 0,
    pathListeningCorrect:    pathStats.listeningCorrect   || 0,
    pathMatchCorrect:        pathStats.matchCorrect       || 0,
    pathTipsRead:            pathStats.tipsRead           || 0,
    pathPerfectLessons:      pathStats.perfectLessons     || 0,
    pathListenWriteCorrect:  pathStats.listenWriteCorrect || 0,
    pathMiddleConsonants2Done: !!pathStats.middleConsonants2Done,
    // #703 — consonant milestone achievements
    pathLowClassDone:      !!pathStats.lowClassDone,
    pathHighClassDone:     !!pathStats.highClassDone,
    pathFirstMasteryDone:  !!pathStats.firstMasteryDone,
    pathReplayPerfectDone: !!pathStats.replayPerfectDone,
    // #508 — onboarding tour secret achievements
    tourCompletedFull: !!(onboardingMeta?.done && onboardingMeta?.skipped === false),
    tourCompletedSkip: !!(onboardingMeta?.done && onboardingMeta?.skipped === true),
    // #556/#557 — tab exploration secret achievements
    visitedEventsTab,
    visitedProgressTab,
    // Issue #677 — daily reward achievements
    dailyRewardTickets,
    usedDailyDouble,
    // #701 — gameplay mechanic achievements
    comboCount:      extra.comboCount      || 0,
    perfectSessions: extra.perfectSessions || 0,
    // #702 — login bonus achievements
    loginBonusTotal:      extra.loginBonusTotal      || 0,
    loginBonusWeekFull:   extra.loginBonusWeekFull   || false,
    loginBonusGotStarlight: extra.loginBonusGotStarlight || false,
    loginBonusStreakDays: extra.loginBonusStreakDays  || 0,
  };
}

// Returns array of achievement ids that are currently unlocked
function getUnlockedIds(stats) {
  return ACHIEVEMENTS.filter(a => a.check(stats)).map(a => a.id);
}

// ---------------------------------------------------------------------------
// Sprint 9.4 — Weekly challenges
// ---------------------------------------------------------------------------
const WEEKLY_DONE_KEY = (wk) => `weekly-done:${wk}`;

// ISO week key: "2026-W27"
function getCurrentWeekKey() {
  const d = new Date();
  const utc = new Date(Date.UTC(d.getFullYear(), d.getMonth(), d.getDate()));
  utc.setUTCDate(utc.getUTCDate() + 4 - (utc.getUTCDay() || 7));
  const ys = new Date(Date.UTC(utc.getUTCFullYear(), 0, 1));
  const wn = Math.ceil((((utc - ys) / 86400000) + 1) / 7);
  return `${utc.getUTCFullYear()}-W${String(wn).padStart(2, "0")}`;
}

// #613 — weekly study time helpers
function getWeeklyStudyMs(log = []) {
  const weekDates = new Set(getCurrentWeekDates());
  return (log || []).filter(e => weekDates.has(e.date)).reduce((s, e) => s + (e.durationMs || 0), 0);
}
function fmtStudyTime(ms) {
  const totalMin = Math.floor(ms / 60000);
  const h = Math.floor(totalMin / 60);
  const m = totalMin % 60;
  if (h === 0) return `${m}m`;
  return m === 0 ? `${h}h` : `${h}h ${m}m`;
}

// All Mon–Sun dates of the current week as "YYYY-MM-DD"
function getCurrentWeekDates() {
  const now = new Date();
  const day = now.getDay() || 7;
  const mon = new Date(now);
  mon.setDate(now.getDate() - day + 1);
  return Array.from({ length: 7 }, (_, i) => {
    const d = new Date(mon);
    d.setDate(mon.getDate() + i);
    return `${d.getFullYear()}-${pad2(d.getMonth()+1)}-${pad2(d.getDate())}`;
  });
}

