// Issue #235 — teacher-created challenges, no deploy needed. Each criterion
// type maps 1:1 to a numeric field already produced by computeWeeklyStats /
// computeMonthWeeklyStats, so "system suggests possibilities" = pick one of
// these instead of writing a free-form condition.
const WEEKLY_CRITERIA = [
  { key: "wPracticeDays",   label: "Practice this many different days this week",              unit: "days"    },
  { key: "wWordsCount",     label: "Practice this many different words this week",             unit: "words"   },
  { key: "wSundayScore",    label: "Score this % or higher on the Sunday Test this week",      unit: "%"       },
  { key: "wordsMastered",   label: "Have this many words reach 14-day SRS",                   unit: "words"   },
  // Group 1-3 criteria (#858)
  { key: "wPathLessons",    label: "Complete this many Path Mode lessons this week",           unit: "lessons" },
  { key: "wPathAccuracy",   label: "Reach this % accuracy or higher in Path Mode this week",  unit: "%"       },
  { key: "wEnergySpent",    label: "Spend this much energy in Path Mode this week",            unit: "energy"  },
  { key: "weekStudyMin",    label: "Accumulate this many minutes of study time this week",     unit: "min"     },
  { key: "wReplayPerfect",  label: "Replay this many completed lessons with 100% this week",  unit: "lessons" },
  { key: "wListeningPct",   label: "Reach this % Listening accuracy or higher this week",     unit: "%"       },
  { key: "wWritingPct",     label: "Reach this % Writing accuracy or higher this week",       unit: "%"       },
  { key: "wPerfectLessons", label: "Get this many perfect lessons in Path Mode this week",    unit: "lessons" },
  { key: "wGachaPulls",     label: "Make this many gacha pulls this week",                    unit: "pulls"   },
  { key: "wCoinsEarned",    label: "Earn this many coins this week",                          unit: "coins"   },
];
const MONTHLY_CRITERIA = [
  { key: "weeksAllThreeDone",   label: "Close the Triple Crown in this many different weeks this month", unit: "weeks"      },
  { key: "totalChallengesDone", label: "Complete this many weekly challenges this month (any week)",     unit: "challenges" },
  // #859/#860 — daily-log based monthly criteria
  { key: "mGACoins",       label: "Earn this many coins during Golden Abundance this month",     unit: "coins" },
  { key: "mOvernightCoins",label: "Accumulate this many coins from Overnight Interest this month", unit: "coins" },
];

const CUSTOM_CHALLENGES_KEY  = "custom-challenges";   // shared KV: { weekly: [...], monthly: [...] }
const CHALLENGE_SCHEDULE_KEY = "challenge-schedule";  // shared KV: #854 teacher scheduler
let _customWeeklyChallengeCache  = [];
let _customMonthlyChallengeCache = [];
let _challengeScheduleCache      = null; // { weeks:{[wk]:{challenges:[{id,reward}],weekReward}}, months:{[mk]:{challengeId,streakGate}} }

async function refreshChallengeScheduleCache() {
  _challengeScheduleCache = (await storageGet(CHALLENGE_SCHEDULE_KEY, true)) || { weeks: {}, months: {} };
  return _challengeScheduleCache;
}

function getMonthStreakGate(monthKey) {
  return _challengeScheduleCache?.months?.[monthKey]?.streakGate ?? MONTHLY_CAT_GATE_STREAK;
}

function slugifyChallengeTitle(title) {
  return (title || "")
    .normalize("NFD").replace(/[\u0300-\u036f]/g, "")
    .trim().toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-+|-+$/g, "") || "challenge";
}

function buildCustomChallengeEntry(kind, raw) {
  const criteria = kind === "weekly" ? WEEKLY_CRITERIA : MONTHLY_CRITERIA;
  const crit = criteria.find(c => c.key === raw.criterion);
  return {
    id: raw.id,
    emoji: raw.emoji || "🎯",
    title: raw.title,
    desc: raw.desc || (crit ? `${crit.label.replace("this many", raw.threshold).replace("this % or higher", `${raw.threshold}%+`)}` : raw.title),
    color: "#2F6E5C",
    criterion: raw.criterion,
    threshold: raw.threshold,
    isCustom: true,
    check: s => (s[raw.criterion] || 0) >= raw.threshold,
  };
}

async function getCustomChallenges() {
  return (await storageGet(CUSTOM_CHALLENGES_KEY, true)) || { weekly: [], monthly: [] };
}

async function refreshCustomChallengeCache() {
  const data = await getCustomChallenges();
  _customWeeklyChallengeCache = (data.weekly || []).map(r => buildCustomChallengeEntry("weekly", r));
  _customMonthlyChallengeCache = (data.monthly || []).map(r => buildCustomChallengeEntry("monthly", r));
  return data;
}

// Issue #235 — "does not allow duplicates": same id, OR same criterion+threshold,
// checked against both the hardcoded pool and every other custom challenge of
// that kind. Throws a teacher-facing Error, same convention as validateCustomAvatarData.
function validateCustomChallengeData(kind, data, { existingId } = {}) {
  if (!data?.title?.trim()) throw new Error("Title is required.");
  const criteria = kind === "weekly" ? WEEKLY_CRITERIA : MONTHLY_CRITERIA;
  const crit = criteria.find(c => c.key === data.criterion);
  if (!crit) throw new Error("Choose a valid criterion.");
  const threshold = Number(data.threshold);
  if (!Number.isFinite(threshold) || threshold <= 0) throw new Error("Enter a valid threshold greater than 0.");
  const hardcodedPool = kind === "weekly" ? CHALLENGE_POOL : MONTHLY_CHALLENGE_POOL;
  const customPool = kind === "weekly" ? _customWeeklyChallengeCache : _customMonthlyChallengeCache;
  const id = existingId || `custom_${kind}_${slugifyChallengeTitle(data.title)}`;
  const dupId = hardcodedPool.some(c => c.id === id) || customPool.some(c => c.id === id && c.id !== existingId);
  if (dupId) throw new Error(`A challenge with id "${id}" already exists — try a different title.`);
  const dupCriterion = [...hardcodedPool, ...customPool].some(c =>
    c.id !== existingId && c.criterion === data.criterion && Number(c.threshold) === threshold
  );
  if (dupCriterion) throw new Error("A challenge with this exact criterion and threshold already exists.");
  return id;
}

async function addCustomChallenge(kind, data) {
  const id = validateCustomChallengeData(kind, data);
  const store = await getCustomChallenges();
  const entry = { id, title: data.title.trim(), desc: data.desc?.trim() || "", emoji: data.emoji || "🎯", criterion: data.criterion, threshold: Number(data.threshold) };
  const next = { ...store, [kind]: [...(store[kind] || []), entry] };
  await storageSet(CUSTOM_CHALLENGES_KEY, next, true);
  await refreshCustomChallengeCache();
  return entry;
}

async function removeCustomChallenge(kind, id) {
  const store = await getCustomChallenges();
  const next = { ...store, [kind]: (store[kind] || []).filter(c => c.id !== id) };
  await storageSet(CUSTOM_CHALLENGES_KEY, next, true);
  await refreshCustomChallengeCache();
}

// Pick 3 challenges for a given week (deterministic rotation, no duplicates)
// #861 — reconstruct a challenge from an inline custom slot (no pool entry needed)
function resolveScheduledChallenge(sc, fullPool) {
  const base = fullPool.find(c => c.id === sc.id);
  if (base) return { ...base, customReward: sc.reward || null };
  // inline custom (built via Custom Builder, not in any pool)
  if (sc.criterion && sc.threshold != null) {
    return {
      id: sc.id,
      emoji: sc.emoji || "🎯",
      title: sc.title || "Custom Challenge",
      desc: sc.desc || sc.title || "Custom Challenge",
      color: "#2F6E5C",
      criterion: sc.criterion,
      threshold: Number(sc.threshold),
      isCustom: true,
      check: s => (s[sc.criterion] || 0) >= Number(sc.threshold),
      customReward: sc.reward || null,
    };
  }
  return null;
}

function getWeekChallenges(weekKey) {
  // #854 — teacher schedule takes priority over automatic rotation
  const scheduled = _challengeScheduleCache?.weeks?.[weekKey];
  if (scheduled?.challenges?.length === 3) {
    const fullPool = [...CHALLENGE_POOL, ..._customWeeklyChallengeCache];
    const resolved = scheduled.challenges.map(sc => resolveScheduledChallenge(sc, fullPool)).filter(Boolean);
    if (resolved.length === 3) return resolved;
  }
  // fallback — automatic rotation
  const wn  = parseInt(weekKey.split("-W")[1], 10);
  const pool = [...CHALLENGE_POOL.filter(c => c.id !== "wc_c3"), ..._customWeeklyChallengeCache];
  const picks = [];
  for (let offset = 0; picks.length < 3; offset++) {
    const c = pool[(wn * 7 + offset * 3) % pool.length];
    if (!picks.find(p => p.id === c.id)) picks.push(c);
  }
  return picks;
}

// Compute weekly stats from existing data
function computeWeeklyStats(progMap, stHistory, achStats, {
  gachaWeekLog = [], coinsWeekLog = [],
  sessionTimeLog = [], energySpendLog = [],
  pathLessonsLog = [], pathAccuracyLog = [], pathSkillLog = [], pathReplayLog = [],
} = {}) {
  const weekSet = new Set(getCurrentWeekDates());
  const entries = Object.values(progMap);

  const wPracticeDays = new Set(
    entries.filter(p => p.lastDate && weekSet.has(p.lastDate)).map(p => p.lastDate)
  ).size;

  const wWordsCount = entries.filter(p => p.lastDate && weekSet.has(p.lastDate)).length;

  const weekTests  = stHistory.filter(s => weekSet.has(s.date));
  const wSundayDone  = weekTests.length > 0;
  const wSundayScore = weekTests.length > 0
    ? Math.max(...weekTests.map(s => {
        const r = Object.values(s.results || {});
        return r.length ? Math.round(r.filter(x => x.correct).length / r.length * 100) : 0;
      }))
    : 0;

  // #855 — gacha pulls this week
  const wGachaPulls = gachaWeekLog
    .filter(e => weekSet.has(e.date))
    .reduce((s, e) => s + (e.pulls || 0), 0);

  // #856 — coins earned this week
  const wCoinsEarned = coinsWeekLog
    .filter(e => weekSet.has(e.date))
    .reduce((s, e) => s + (e.amount || 0), 0);

  // #858 Group 1 — Path lessons, accuracy, energy
  const wPathLessons = pathLessonsLog
    .filter(e => weekSet.has(e.date))
    .reduce((s, e) => s + (e.count || 0), 0);

  const weekAccEntries = pathAccuracyLog.filter(e => weekSet.has(e.date));
  const accCorrect = weekAccEntries.reduce((s, e) => s + (e.correct || 0), 0);
  const accTotal   = weekAccEntries.reduce((s, e) => s + (e.total   || 0), 0);
  const wPathAccuracy   = accTotal > 0 ? Math.round(accCorrect / accTotal * 100) : 0;
  const wPerfectLessons = weekAccEntries.filter(e => (e.total || 0) > 0 && e.correct === e.total).length;

  const wEnergySpent = energySpendLog
    .filter(e => weekSet.has(e.date))
    .reduce((s, e) => s + (e.amount || 0), 0);

  // #858 Group 2 — Study time, replays
  const weekStudyMin = Math.round(
    sessionTimeLog
      .filter(e => weekSet.has(e.date))
      .reduce((s, e) => s + (e.durationMs || 0), 0) / 60000
  );

  const wReplayPerfect = pathReplayLog
    .filter(e => weekSet.has(e.date))
    .reduce((s, e) => s + (e.count || 0), 0);

  // #858 Group 3 — Listening / Writing accuracy
  const weekSkillEntries = pathSkillLog.filter(e => weekSet.has(e.date));
  const listenCorrect = weekSkillEntries.reduce((s, e) => s + (e.listenCorrect || 0), 0);
  const listenTotal   = weekSkillEntries.reduce((s, e) => s + (e.listenTotal   || 0), 0);
  const writeCorrect  = weekSkillEntries.reduce((s, e) => s + (e.writeCorrect  || 0), 0);
  const writeTotal    = weekSkillEntries.reduce((s, e) => s + (e.writeTotal    || 0), 0);
  const wListeningPct = listenTotal > 0 ? Math.round(listenCorrect / listenTotal * 100) : 0;
  const wWritingPct   = writeTotal  > 0 ? Math.round(writeCorrect  / writeTotal  * 100) : 0;

  return {
    wPracticeDays, wWordsCount, wSundayDone, wSundayScore,
    wordsMastered: achStats.wordsMastered,
    wGachaPulls, wCoinsEarned,
    wPathLessons, wPathAccuracy, wPerfectLessons, wEnergySpent,
    weekStudyMin, wReplayPerfect,
    wListeningPct, wWritingPct,
    wAllDone: false, // filled in after checking the 3 challenges
  };
}

// ---------------------------------------------------------------------------
// Issue #181 — "Gatinho do Mês" monthly challenge (built on top of Weekly
// Challenges, Sprint 9.4 — weekly challenges themselves are unchanged).
// ---------------------------------------------------------------------------
function getMonthKey(d = new Date()) {
  return `${d.getFullYear()}-${pad2(d.getMonth() + 1)}`;
}

// Issue #384 — first moment (local midnight) of the month AFTER `monthKey`,
// i.e. the exact instant the Cat of the Month's acquisition window closes.
// `monthKey` is "YYYY-MM" (1-indexed month); `new Date(year, month, 1)`
// with the un-decremented month index already lands on day 1 of the next
// calendar month (Date's month param is 0-indexed), so no manual +1 needed.
function getMonthKeyEnd(monthKey) {
  const [y, m] = monthKey.split("-").map(Number);
  return new Date(y, m, 1, 0, 0, 0, 0);
}

// "3d 14h" / "6h" / "Ending soon" — deliberately coarse (days+hours, no
// minutes) since this is a heads-up, not a precise timer.
function formatCountdown(targetDate, now = new Date()) {
  const diffMs = targetDate.getTime() - now.getTime();
  if (diffMs <= 0) return "Ending soon";
  const totalHours = Math.floor(diffMs / (1000 * 60 * 60));
  const days = Math.floor(totalHours / 24);
  const hours = totalHours % 24;
  return days > 0 ? `${days}d ${hours}h` : `${hours}h`;
}

// Same ISO-week math as getCurrentWeekKey, generalized to any date, and also
// returning the week's Thursday — used to decide which calendar month a
// given week "belongs to" (ISO convention: a week belongs to the month/year
// containing its Thursday, exactly like ISO week-numbering assigns a week
// to a year via its Thursday).
function getISOWeekInfoForDate(d) {
  const utc = new Date(Date.UTC(d.getFullYear(), d.getMonth(), d.getDate()));
  utc.setUTCDate(utc.getUTCDate() + 4 - (utc.getUTCDay() || 7));
  const ys = new Date(Date.UTC(utc.getUTCFullYear(), 0, 1));
  const wn = Math.ceil((((utc - ys) / 86400000) + 1) / 7);
  return { weekKey: `${utc.getUTCFullYear()}-W${String(wn).padStart(2, "0")}`, thursday: utc };
}

// All ISO week keys that belong to a given "YYYY-MM" month (via the
// Thursday-ownership rule above) — used to aggregate WEEKLY_DONE_KEY across
// a whole month without any new per-week bookkeeping.
function getWeekKeysForMonth(monthKey) {
  const [y, m] = monthKey.split("-").map(Number); // m is 1-12
  const first = new Date(y, m - 1, 1);
  const last  = new Date(y, m, 0);
  const keys  = new Set();
  for (let d = new Date(first); d <= last; d.setDate(d.getDate() + 1)) {
    const { weekKey, thursday } = getISOWeekInfoForDate(d);
    if (thursday.getUTCFullYear() === y && thursday.getUTCMonth() === m - 1) keys.add(weekKey);
  }
  return [...keys];
}

// Aggregates WEEKLY_DONE_KEY across every week owned by monthKey. Each week
// always offers exactly 3 non-wc_c3 challenges (see getWeekChallenges), so
// "all 3 done" and "done count" are directly comparable across weeks.
async function computeMonthWeeklyStats(monthKey) {
  const weekKeys = getWeekKeysForMonth(monthKey);
  let weeksAllThreeDone = 0, totalChallengesDone = 0, weeksWithAtLeastOne = 0;
  for (const wk of weekKeys) {
    const done = await storageGet(WEEKLY_DONE_KEY(wk), false) || [];
    totalChallengesDone += done.length;
    if (done.length >= 3) weeksAllThreeDone++;
    if (done.length >= 1) weeksWithAtLeastOne++;
  }
  return { weeksAllThreeDone, totalChallengesDone, weeksWithAtLeastOne, totalWeeks: weekKeys.length };
}

// #859/#860 — sum daily-log entries for a given "YYYY-MM" month
async function computeMonthlyLogStats(monthKey) {
  const [y, m] = monthKey.split("-").map(Number);
  const prefix = `${y}-${String(m).padStart(2, "0")}`;
  const [gaLog, overnightLog] = await Promise.all([
    storageGet(GA_COINS_LOG_KEY, false),
    storageGet(OVERNIGHT_COINS_LOG_KEY, false),
  ]);
  const monthFilter = e => (e.date || "").startsWith(prefix);
  const mGACoins       = (gaLog || []).filter(monthFilter).reduce((s, e) => s + (e.amount || 0), 0);
  const mOvernightCoins = (overnightLog || []).filter(monthFilter).reduce((s, e) => s + (e.amount || 0), 0);
  return { mGACoins, mOvernightCoins };
}

// Issue #181 pool — the 2nd, "sorteado" criterion on top of the mandatory
// 14-day streak gate (see computeAndSaveStreak's MONTH_STREAK_BEST_KEY).
// Issue #375 — criterion/threshold added (same idea as #374) so the mc-card
// can show numeric progress on the 2nd (drawn) criterion, not just the
// mandatory streak gate. mc_nozero compares two stats (weeksWithAtLeastOne
// vs totalWeeks) instead of one vs a fixed threshold, so it's left without
// criterion/threshold — the mc-card falls back to showing that pair directly.
const MONTHLY_CHALLENGE_POOL = [
  { id: "mc_2weeks",  desc: "Complete all 3 weekly challenges in at least 2 different weeks this month",
    criterion: "weeksAllThreeDone", threshold: 2, check: s => s.weeksAllThreeDone >= 2 },
  { id: "mc_6total",  desc: "Complete at least 6 weekly challenges (any week) this month",
    criterion: "totalChallengesDone", threshold: 6, check: s => s.totalChallengesDone >= 6 },
  { id: "mc_crown1",  desc: "Close the Triple Crown at least once this month",
    criterion: "weeksAllThreeDone", threshold: 1, check: s => s.weeksAllThreeDone >= 1 },
  { id: "mc_nozero",  desc: "Complete at least 1 weekly challenge in every week this month",
    check: s => s.totalWeeks > 0 && s.weeksWithAtLeastOne === s.totalWeeks },
  // #859 — Golden Abundance monthly challenge
  { id: "mc_ga_coins", emoji: "✨", desc: "Earn 1000+ coins during the Golden Abundance event this month",
    criterion: "mGACoins", threshold: 1000, check: s => (s.mGACoins || 0) >= 1000 },
  // #860 — Overnight Interest monthly challenge
  { id: "mc_overnight", emoji: "💤", desc: "Accumulate 500+ coins from Overnight Interest this month",
    criterion: "mOvernightCoins", threshold: 500, check: s => (s.mOvernightCoins || 0) >= 500 },
];

// Deterministic pick of 1 monthly criterion per monthKey (same rotation
// spirit as getWeekChallenges, but drawing 1 instead of 3).
function getMonthChallenge(monthKey) {
  // #854/#861/#863 — teacher schedule takes priority over automatic rotation
  const scheduled = _challengeScheduleCache?.months?.[monthKey];
  if (scheduled) {
    // #863 — multi-challenge: challengeIds[] (up to 3). Legacy single challengeId also handled.
    const ids = scheduled.challengeIds?.length ? scheduled.challengeIds : (scheduled.challengeId ? [scheduled.challengeId] : []);
    if (ids.length > 0) {
      const pool = [...MONTHLY_CHALLENGE_POOL, ..._customMonthlyChallengeCache];
      const resolved = ids.map(id => {
        const found = pool.find(c => c.id === id);
        if (found) return found;
        // inline custom
        if (scheduled.criterion && scheduled.threshold != null) {
          return { id, emoji: scheduled.emoji || "🎯", desc: scheduled.title || "Custom Monthly Challenge", criterion: scheduled.criterion, threshold: Number(scheduled.threshold), isCustom: true, check: s => (s[scheduled.criterion] || 0) >= Number(scheduled.threshold) };
        }
        return null;
      }).filter(Boolean);
      if (resolved.length > 0) return resolved[0]; // getMonthChallenge returns first for backward compat
    }
  }
  // fallback — automatic rotation
  const pool = [...MONTHLY_CHALLENGE_POOL, ..._customMonthlyChallengeCache];
  const [y, m] = monthKey.split("-").map(Number);
  const idx = (y * 12 + m) % pool.length;
  return pool[idx];
}

// #863 — returns ALL monthly challenges (1–3) for a given month key
function getMonthChallenges(monthKey) {
  const scheduled = _challengeScheduleCache?.months?.[monthKey];
  if (scheduled) {
    const ids = scheduled.challengeIds?.length ? scheduled.challengeIds : (scheduled.challengeId ? [scheduled.challengeId] : []);
    if (ids.length > 0) {
      const pool = [...MONTHLY_CHALLENGE_POOL, ..._customMonthlyChallengeCache];
      const resolved = ids.map(id => {
        const found = pool.find(c => c.id === id);
        if (found) return found;
        if (scheduled.criterion && scheduled.threshold != null)
          return { id, emoji: scheduled.emoji || "🎯", desc: scheduled.title || "Custom Monthly Challenge", criterion: scheduled.criterion, threshold: Number(scheduled.threshold), isCustom: true, check: s => (s[scheduled.criterion] || 0) >= Number(scheduled.threshold) };
        return null;
      }).filter(Boolean);
      if (resolved.length > 0) return resolved;
    }
  }
  return [getMonthChallenge(monthKey)]; // fallback single
}

const MONTH_STREAK_BEST_KEY = (mk) => `month-streak-best:${mk}`; // personal: highest streak.count reached within that month
const MONTHLY_CAT_GATE_STREAK = 10; // reduced from 14 for July 2026 — students lost days due to updates

// ---------------------------------------------------------------------------
// Issue #351.1 — "Solstice Ticket" special banner schedule + featured config.
// Genshin/HSR-style limited banner built on top of the Gatinho do Mês system
// (#181): each banner runs a short window around a "magic date" (dd/mm where
// day === month, e.g. 8/8, 9/9) and features the Cat of the Month from the
// PREVIOUS month (that month's own cat is still mid-challenge) + 2 rate-up
// Rares. Ships starting with the August 2026 banner — July's window is
// already in progress and explicitly excluded (Bruno, 2026-07-09).
// ---------------------------------------------------------------------------

// Confirmed against Bruno's full table (2026-07-08) — every one of the 12
// regular monthly windows is exactly "day=month, month=month" ± 2 days.
function getMagicDateWindow(monthNum, year) {
  const magic = new Date(year, monthNum - 1, monthNum); // e.g. month 1 -> Jan 1st; rolls correctly across year boundaries via Date's own arithmetic
  const start = new Date(magic); start.setDate(start.getDate() - 2);
  const end   = new Date(magic); end.setDate(end.getDate() + 2);
  return { start, end };
}

// Manual, non-formulaic override — the App Birthday special (28/06–04/07,
// every year), sitting between June's and July's regular windows without
// overlapping either.
const BIRTHDAY_BANNER_WINDOW = { startMonth: 6, startDay: 28, endMonth: 7, endDay: 4 };

function dateOnly(d) { return new Date(d.getFullYear(), d.getMonth(), d.getDate()).getTime(); }
function dateInWindow(d, start, end) { const t = dateOnly(d); return t >= dateOnly(start) && t <= dateOnly(end); }

// Launch guard — banners start with 2026-08; anything before that (namely
// the in-progress July window) never counts as "launched". String compare
// works because both regular ("YYYY-MM") and birthday ("YYYY-birthday")
// keys sort correctly against "2026-08" lexically.
const BANNER_LAUNCH_KEY = "2026-08";
function isBannerLaunched(bannerKey) { return bannerKey >= BANNER_LAUNCH_KEY; }

// Cat of the Month for `monthKey` M is automatically the featured Legendary
// for the M+2 banner. Corrected 2026-07-09 (owner decision) from the
// originally-shipped M+1 rule documented in #351/#377 — M+1 would still be
// mid-contest by the time its own banner window opens (the following
// month's streak challenge only wraps at month-end), so the catch-up
// window needs a full extra month of buffer: M+2 guarantees M's challenge
// has been over and settled for a while before it's offered again here.
function getFeaturedBannerKeyForMonthCat(monthKey) {
  const [y, m] = monthKey.split("-").map(Number); // m is 1-indexed
  const zeroIdx = (m - 1) + 2; // M+2, 0-indexed, may overflow past 11
  const targetY = y + Math.floor(zeroIdx / 12);
  const targetM = (zeroIdx % 12) + 1;
  return `${targetY}-${pad2(targetM)}`;
}

// Returns { bannerKey, windowStart, windowEnd, featuredMonthKey } for the
// banner active on `date`, or null if none is running. featuredMonthKey is
// null for the Birthday special (no M-1 rule applies — teacher picks the
// featured Legendary manually for that one, same admin config as the Rares).
function getActiveBanner(date = new Date()) {
  const year = date.getFullYear();

  const bStart = new Date(year, BIRTHDAY_BANNER_WINDOW.startMonth - 1, BIRTHDAY_BANNER_WINDOW.startDay);
  const bEnd   = new Date(year, BIRTHDAY_BANNER_WINDOW.endMonth - 1, BIRTHDAY_BANNER_WINDOW.endDay);
  if (dateInWindow(date, bStart, bEnd)) {
    return { bannerKey: `${year}-birthday`, windowStart: bStart, windowEnd: bEnd, featuredMonthKey: null };
  }

  // Check neighboring years too — January's window starts in December of
  // the previous year, December's can spill into next January.
  for (const y of [year - 1, year, year + 1]) {
    for (let m = 1; m <= 12; m++) {
      const { start, end } = getMagicDateWindow(m, y);
      if (dateInWindow(date, start, end)) {
        const bannerKey = `${y}-${pad2(m)}`;
        // M-2 rule (corrected 2026-07-09, see getFeaturedBannerKeyForMonthCat
        // above for the full rationale) — was M-1 (m - 2, 0-indexed) at launch.
        const prevMonthDate = new Date(y, m - 3, 1); // month m-2, 0-indexed
        const featuredMonthKey = getMonthKey(prevMonthDate);
        return { bannerKey, windowStart: start, windowEnd: end, featuredMonthKey };
      }
    }
  }
  return null;
}

// Teacher-configured featured Rares per banner (up to 2), shared KV so it's
// visible/editable from the admin panel, same storage pattern as every
// other teacher config in this app (enabledClassCodes, custom-challenges…).
const BANNER_FEATURED_RARES_KEY      = (bannerKey) => `banner-featured-rares:${bannerKey}`;
const BANNER_ART_KEY                 = (bannerKey) => `gacha-banner-art:${bannerKey}`;
const BANNER_ART_H_KEY               = (bannerKey) => `gacha-banner-art-h:${bannerKey}`;
const BANNER_ART_V_KEY               = (bannerKey) => `gacha-banner-art-v:${bannerKey}`;

async function getBannerArt(bannerKey) {
  return (await storageGet(BANNER_ART_KEY(bannerKey), true)) || null;
}
async function setBannerArt(bannerKey, url) {
  return storageSet(BANNER_ART_KEY(bannerKey), url || null, true);
}
async function getBannerArtOriented(bannerKey) {
  const [h, v, legacy] = await Promise.all([
    storageGet(BANNER_ART_H_KEY(bannerKey), true),
    storageGet(BANNER_ART_V_KEY(bannerKey), true),
    storageGet(BANNER_ART_KEY(bannerKey), true),
  ]);
  return { horizontal: h || null, vertical: v || null, legacy: legacy || null };
}
async function setBannerArtOriented(bannerKey, { horizontal, vertical }) {
  await Promise.all([
    storageSet(BANNER_ART_H_KEY(bannerKey), horizontal || null, true),
    storageSet(BANNER_ART_V_KEY(bannerKey), vertical || null, true),
  ]);
}

async function getBannerFeaturedRares(bannerKey) {
  return (await storageGet(BANNER_FEATURED_RARES_KEY(bannerKey), true)) || [];
}

async function setBannerFeaturedRares(bannerKey, avatarIds) {
  if (!Array.isArray(avatarIds) || avatarIds.length > 2) throw new Error("Pick up to 2 Rare avatars.");
  const catalog = getFullAvatarCatalog();
  for (const id of avatarIds) {
    const av = catalog.find((a) => a.id === id);
    if (!av || av.rarity !== "rare") throw new Error(`${id} is not a Rare avatar.`);
  }
  return storageSet(BANNER_FEATURED_RARES_KEY(bannerKey), avatarIds, true);
}

// Deterministic fallback (seeded by bannerKey, so it's stable across
// reloads instead of re-rolling every render) — same rotation spirit as
// getMonthChallenge/getWeekChallenges — used when the teacher hasn't
// configured 2 featured Rares for this banner in time.
function getFallbackFeaturedRares(bannerKey, catalog = getFullAvatarCatalog()) {
  const rares = catalog.filter((a) => a.rarity === "rare");
  if (rares.length <= 2) return rares.map((a) => a.id);
  let seed = 0;
  for (const ch of bannerKey) seed = (seed * 31 + ch.charCodeAt(0)) >>> 0;
  const idx1 = seed % rares.length;
  let idx2 = Math.floor(seed / 256) % rares.length;
  if (idx2 === idx1) idx2 = (idx2 + 1) % rares.length;
  return [rares[idx1].id, rares[idx2].id];
}

// What #351.3's draw engine actually uses — teacher's picks first, filled
// in with the deterministic fallback if fewer than 2 were configured.
async function getEffectiveBannerFeaturedRares(bannerKey) {
  const configured = await getBannerFeaturedRares(bannerKey);
  const merged = [...configured];
  for (const id of getFallbackFeaturedRares(bannerKey)) {
    if (merged.length >= 2) break;
    if (!merged.includes(id)) merged.push(id);
  }
  return merged.slice(0, 2);
}

// Issue #379 — every regular monthly banner gets its featured Legendary for
// free from the M-1 Cat of the Month rule (#377's featuredMonthKey). Only
// the Birthday special has no such rule and needs its own admin override —
// #377's own comment already flagged this ("teacher picks featured
// Legendary manually for that one, same admin config as the Rares"), it
// just hadn't been built yet. Same shared-KV + deterministic-fallback shape
// as getBannerFeaturedRares/getFallbackFeaturedRares above, just for a
// single Legendary instead of up to 2 Rares.
const BANNER_FEATURED_LEGENDARY_KEY = (bannerKey) => `banner-featured-legendary:${bannerKey}`;

async function getBannerFeaturedLegendaryOverride(bannerKey) {
  return await storageGet(BANNER_FEATURED_LEGENDARY_KEY(bannerKey), true);
}

async function setBannerFeaturedLegendary(bannerKey, avatarId) {
  const catalog = getFullAvatarCatalog();
  const av = catalog.find((a) => a.id === avatarId);
  if (!av || av.rarity !== "legendary") throw new Error(`${avatarId} is not a Legendary avatar.`);
  return storageSet(BANNER_FEATURED_LEGENDARY_KEY(bannerKey), avatarId, true);
}

function getFallbackFeaturedLegendary(bannerKey, catalog = getFullAvatarCatalog()) {
  const legendaries = catalog.filter((a) => a.rarity === "legendary");
  if (legendaries.length === 0) return null;
  let seed = 0;
  for (const ch of bannerKey) seed = (seed * 31 + ch.charCodeAt(0)) >>> 0;
  return legendaries[seed % legendaries.length];
}

// featuredMonthKey is null only for the Birthday banner (#377) — every
// regular monthly banner always resolves via the Cat of the Month directly,
// never touching the override/fallback path at all.
async function getEffectiveBannerFeaturedLegendary(bannerKey, featuredMonthKey, catalog = getFullAvatarCatalog()) {
  if (featuredMonthKey) return getMonthlyCatAvatar(featuredMonthKey, catalog);
  const overrideId = await getBannerFeaturedLegendaryOverride(bannerKey);
  if (overrideId) {
    const av = catalog.find((a) => a.id === overrideId);
    if (av) return av;
  }
  return getFallbackFeaturedLegendary(bannerKey, catalog);
}

// ---------------------------------------------------------------------------
// Issue #551/#552 — Events tab data layer
// ---------------------------------------------------------------------------

// Golden Abundance window: 3rd Sunday @ 06:00 → 4th Sunday @ 22:00 local time.
// Returns the nearest window that hasn't fully passed yet (current or next).
function getGoldenAbundanceWindow(date) {
  function getNthSunday(year, month, n) {
    let count = 0;
    for (let d = 1; d <= 31; d++) {
      const day = new Date(year, month, d);
      if (day.getMonth() !== month) break;
      if (day.getDay() === 0 && ++count === n) return day;
    }
    return null;
  }
  const year = date.getFullYear();
  const month = date.getMonth();
  for (let i = 0; i < 3; i++) {
    const m = (month + i) % 12;
    const y = month + i >= 12 ? year + 1 : year;
    const sun3 = getNthSunday(y, m, 3);
    const sun4 = getNthSunday(y, m, 4);
    if (!sun3 || !sun4) continue;
    const start = new Date(sun3); start.setHours(6, 0, 0, 0);
    const end   = new Date(sun4); end.setHours(22, 0, 0, 0);
    if (end > date) return { start, end };
  }
  return null;
}

function isGoldenAbundanceActive() {
  const w = getGoldenAbundanceWindow(new Date());
  if (!w) return false;
  const now = new Date();
  return now >= w.start && now <= w.end;
}

const EVENT_FORCE_KEY    = (id) => `event-force-visible:${id}`;
const EVENT_BANNER_H_KEY = (id) => `event-banner-h:${id}`;
const EVENT_BANNER_V_KEY = (id) => `event-banner-v:${id}`;

// Returns the next banner that hasn't ended yet (active OR upcoming).
// getActiveBanner only matches dates INSIDE a window; this also catches
// windows that start in the future, so the Solstice Banner appears in
// "Upcoming Events" between two windows (e.g. Jul 13 → Aug 6 gap).
function getNextOrActiveBanner(date = new Date()) {
  const active = getActiveBanner(date);
  if (active) return active;
  // Scan forward up to 6 months to find the next window
  const year = date.getFullYear();
  const candidates = [];
  for (const y of [year, year + 1]) {
    for (let m = 1; m <= 12; m++) {
      const { start, end } = getMagicDateWindow(m, y);
      const key = `${y}-${pad2(m)}`;
      if (end > date && isBannerLaunched(key)) {
        candidates.push({ bannerKey: key, windowStart: start, windowEnd: end, featuredMonthKey: null });
      }
    }
  }
  candidates.sort((a, b) => a.windowStart - b.windowStart);
  return candidates[0] || null;
}

// Returns all event occurrences for the next 6 months, each with a unique id.
// Multiple entries per event type allow the teacher to configure banners in
// advance; active-event filters elsewhere (Home grid, popup) are unaffected
// because they already filter by window dates.
function getEventsRegistry(now = new Date()) {
  const events = [];
  const cutoff = new Date(now.getFullYear(), now.getMonth() + 6, now.getDate());

  // Solstice Banners — every launched window that hasn't fully ended yet
  const seenBanners = new Set();
  const activeB = getActiveBanner(now);
  if (activeB && !seenBanners.has(activeB.bannerKey)) {
    seenBanners.add(activeB.bannerKey);
    events.push({
      id: `gacha-banner-${activeB.bannerKey}`,
      name: "Solstice Ticket",
      subtitle: "Legendary Avatar Event",
      color: "#E8557A", icon: "🎫",
      category: "GACHA",
      calendarImg: "/tickets/solstice-ticket.png",
      calendarImgSide: "right",
      calendarGradient: "linear-gradient(135deg, #F3889C 0%, #3F0916 100%)",
      window: { start: activeB.windowStart, end: activeB.windowEnd },
      bannerKey: activeB.bannerKey,
      useLegacyBannerArt: true,
    });
  }
  for (const y of [now.getFullYear(), now.getFullYear() + 1]) {
    // Birthday banner
    const bStart = new Date(y, BIRTHDAY_BANNER_WINDOW.startMonth - 1, BIRTHDAY_BANNER_WINDOW.startDay);
    const bEnd   = new Date(y, BIRTHDAY_BANNER_WINDOW.endMonth   - 1, BIRTHDAY_BANNER_WINDOW.endDay);
    const bKey   = `${y}-birthday`;
    if (bEnd > now && bStart < cutoff && isBannerLaunched(bKey) && !seenBanners.has(bKey)) {
      seenBanners.add(bKey);
      events.push({
        id: `gacha-banner-${bKey}`,
        name: "Solstice Ticket",
        subtitle: "Legendary Avatar Event",
        color: "#E8557A", icon: "🎫",
        category: "GACHA",
        calendarImg: "/tickets/solstice-ticket.png",
        calendarImgSide: "right",
        calendarGradient: "linear-gradient(135deg, #F3889C 0%, #3F0916 100%)",
        window: { start: bStart, end: bEnd },
        bannerKey: bKey,
        useLegacyBannerArt: true,
      });
    }
    // Regular monthly banners
    for (let m = 1; m <= 12; m++) {
      const { start, end } = getMagicDateWindow(m, y);
      const key = `${y}-${pad2(m)}`;
      if (end > now && start < cutoff && isBannerLaunched(key) && !seenBanners.has(key)) {
        seenBanners.add(key);
        events.push({
          id: `gacha-banner-${key}`,
          name: "Solstice Ticket",
          subtitle: "Legendary Avatar Event",
          color: "#E8557A", icon: "🎫",
          category: "GACHA",
          calendarImg: "/tickets/solstice-ticket.png",
          calendarImgSide: "right",
          calendarGradient: "linear-gradient(135deg, #F3889C 0%, #3F0916 100%)",
          window: { start, end },
          bannerKey: key,
          useLegacyBannerArt: true,
        });
      }
    }
  }

  // Golden Abundance — every occurrence in the next 6 months
  const year = now.getFullYear();
  for (let i = 0; i <= 7; i++) {
    const probeMonth = (now.getMonth() + i) % 12;
    const probeYear  = now.getMonth() + i >= 12 ? year + 1 : year;
    const sun3 = (() => {
      let count = 0;
      for (let d = 1; d <= 31; d++) {
        const day = new Date(probeYear, probeMonth, d);
        if (day.getMonth() !== probeMonth) break;
        if (day.getDay() === 0 && ++count === 3) return day;
      }
      return null;
    })();
    const sun4 = (() => {
      let count = 0;
      for (let d = 1; d <= 31; d++) {
        const day = new Date(probeYear, probeMonth, d);
        if (day.getMonth() !== probeMonth) break;
        if (day.getDay() === 0 && ++count === 4) return day;
      }
      return null;
    })();
    if (!sun3 || !sun4) continue;
    const start = new Date(sun3); start.setHours(6, 0, 0, 0);
    const end   = new Date(sun4); end.setHours(22, 0, 0, 0);
    if (end <= now || start >= cutoff) continue;
    const gaKey = `${probeYear}-${pad2(probeMonth + 1)}`;
    events.push({
      id: `golden-abundance-${gaKey}`,
      name: "Golden Abundance",
      subtitle: "Double Rewards Week",
      color: "#D4AF37", icon: "✨",
      category: "ECONOMY",
      calendarImg: "/coins/catcoin.png",
      calendarImgSide: "left",
      calendarGradient: "linear-gradient(135deg, #B08521 0%, #3D2200 100%)",
      calendarBorder: "#E8A33D",
      recurringBannerKey: "golden-abundance",
      window: { start, end },
    });
  }

  events.sort((a, b) => (a.window?.start || 0) - (b.window?.start || 0));
  return events;
}

// Bundles the full featured set (Legendary + up to 2 Rares) for whichever
// banner is active right now — shared by the draw engine (openBannerTicket)
// and the "Open ticket" odds preview in GachaTicketModal, so both always
// agree on exactly which avatars are featured.
async function getActiveBannerFeaturedAvatars(date = new Date()) {
  const banner = getActiveBanner(date);
  if (!banner) return null;
  const catalog = getFullAvatarCatalog();
  const legendary = await getEffectiveBannerFeaturedLegendary(banner.bannerKey, banner.featuredMonthKey, catalog);
  const rareIds = await getEffectiveBannerFeaturedRares(banner.bannerKey);
  const rares = rareIds.map((id) => catalog.find((a) => a.id === id)).filter(Boolean);
  return { banner, legendary: legendary || null, rares };
}

// Issue #379 — pure table builder, shared by the actual roll (openBannerTicket)
// and the odds preview (GachaTicketModal), so they can never drift apart.
// 3 shapes per #351's locked decisions:
//  - Legendary still available: it's the jackpot (2%), the 2 featured Rares
//    share a smaller rate-up slice (8%, folded into avatar_rare if none of
//    them are available either), rest is avatar/coin filler.
//  - Legendary already owned, >=1 featured Rare still available: the
//    featured Rare(s) BECOME the jackpot (decision 4 — "jackpot passa a
//    valer só pelos Rares featured restantes").
//  - Nothing featured left (Legendary + both Rares owned): decision 5 —
//    plain Common/Uncommon/Rare fallback pool, Epic never included, no
//    jackpot possible this banner (jackpotKey: null — pity still climbs via
//    updateGachaPity, just never gets boosted since there's nothing to
//    boost toward; see openBannerTicket's guaranteedNextBanner flag).
function buildBannerRollTable(legendaryAvailable, availableRareCount) {
  if (legendaryAvailable) {
    return availableRareCount > 0
      ? { table: [["jackpot_legendary", 2], ["featured_rare", 8], ["avatar_rare", 10], ["avatar_uncommon", 15], ["coins_2000", 15], ["coins_1500", 20], ["coins_1000", 20], ["coins_750", 10]], jackpotKey: "jackpot_legendary" }
      : { table: [["jackpot_legendary", 2], ["avatar_rare", 18], ["avatar_uncommon", 15], ["coins_2000", 15], ["coins_1500", 20], ["coins_1000", 20], ["coins_750", 10]], jackpotKey: "jackpot_legendary" };
  }
  if (availableRareCount > 0) {
    return { table: [["featured_rare", 10], ["avatar_rare", 10], ["avatar_uncommon", 15], ["coins_2000", 15], ["coins_1500", 20], ["coins_1000", 20], ["coins_750", 10]], jackpotKey: "featured_rare" };
  }
  return { table: [["avatar_rare", 20], ["avatar_uncommon", 30], ["avatar_common", 30], ["coins_1000", 10], ["coins_750", 10]], jackpotKey: null };
}

// Opens 1 Solstice Ticket. Only valid while a banner is active and launched
// — outside the window the only valid action on a held ticket is the #380
// conversion (not this roll). Returns:
//  - { ok:false, reason: "no-ticket" | "banner-inactive" }
//  - { ok:true, avatar, coins, newCoins, profile, guaranteedNextBanner,
//      pityCount } — same shape as openRareTicket/openEpicTicket.
// guaranteedNextBanner is only ever true in the decision-5 fallback (no
// jackpotKey at all): it means hard-pity was JUST reached this pull with
// nothing featured left to grant this banner, so — per #351 decision 4 —
// the persisted counter guarantees a hit the moment a FUTURE banner ships a
// new featured set the student doesn't already own.
async function openBannerTicket(profile, { simulate = false } = {}) {
  const tickets = simulate ? { banner: 1 } : await getGachaTickets();
  if (!simulate && (tickets.banner || 0) <= 0) return { ok: false, reason: "no-ticket" };

  const featured = await getActiveBannerFeaturedAvatars(new Date());
  if (!featured || !isBannerLaunched(featured.banner.bannerKey)) return { ok: false, reason: "banner-inactive" };

  const owned = new Set(profile.unlockedAvatars || []);
  const legendaryAvailable = !!featured.legendary && !owned.has(featured.legendary.id);
  const availableRares = featured.rares.filter((a) => !owned.has(a.id));

  let { table, jackpotKey } = buildBannerRollTable(legendaryAvailable, availableRares.length);

  let pityCount = 0;
  if (!simulate) {
    const pity = await getGachaPity();
    pityCount = pity.banner || 0;
    if (jackpotKey) table = applyPityBoost(table, jackpotKey, pityCount, GACHA_PITY.banner.softStart, GACHA_PITY.banner.hardCap);
  }

  const key = rollWeightedTable(table);
  let coinReward = 0;
  let avatar = null;
  if (key === "jackpot_legendary") avatar = featured.legendary;
  else if (key === "featured_rare") avatar = availableRares[Math.floor(Math.random() * availableRares.length)] || null;
  else if (key === "avatar_rare") avatar = pickRandomUnownedAvatar("rare", profile);
  else if (key === "avatar_uncommon") avatar = pickRandomUnownedAvatar("uncommon", profile);
  else if (key === "avatar_common") avatar = pickRandomUnownedAvatar("common", profile);
  else coinReward = parseInt(key.split("_")[1], 10);

  // Defensive net, same spirit as Rare/Epic — an avatar-flavored key should
  // never resolve empty given how the table above is chosen, but never
  // strand a roll with nothing to show; also doubles as the natural
  // "everything owned" cashback with no special-case needed.
  if ((key === "jackpot_legendary" || key === "featured_rare" || key.startsWith("avatar_")) && !avatar) {
    coinReward = (coinReward || 0) + BANNER_TICKET_PRICE;
  }
  const hitJackpot = !!jackpotKey && key === jackpotKey && !!avatar;

  if (!simulate) {
    await storageSet(GACHA_TICKETS_KEY, { ...tickets, banner: tickets.banner - 1 }, false);
    { const _u = getCurrentUsername(); if (_u) mirrorStudentWallet(_u).catch(() => {}); }
  }

  let updatedProfile = profile;
  if (avatar) {
    updatedProfile = { ...profile, unlockedAvatars: [...(profile.unlockedAvatars || []), avatar.id] };
    if (!simulate) {
      await storageSet(KEYS.profile, updatedProfile, false);
      await mirrorUnlockedAvatarsToRoster(profile.username, updatedProfile.unlockedAvatars, profile);
      appendStudentEvent(profile.username, { type: "avatar", desc: `Unlocked ${avatar.name}`, icon: "🐱" }).catch(() => {});
    }
  }
  const newCoins = (!simulate && coinReward) ? await creditCoins(coinReward, "Gacha Solstice Ticket reward") : null;

  const nextPityCount = hitJackpot ? 0 : pityCount + 1;
  if (!simulate) {
    await updateGachaPity("banner", hitJackpot);
    await appendGachaHistoryEntry({ kind: "banner", key, avatarId: avatar?.id || null, coins: coinReward || 0, rarity: avatar?.rarity || null });
  }

  return {
    ok: true, avatar: avatar || null, coins: coinReward || 0, newCoins,
    profile: simulate ? profile : updatedProfile, simulate,
    pityCount: simulate ? undefined : nextPityCount,
    guaranteedNextBanner: !simulate && !jackpotKey && nextPityCount >= GACHA_PITY.banner.hardCap,
  };
}

// Issue #380 — fee/cashback for converting a stalled (post-window) Solstice
// Ticket into a Rare or Starlight Ticket. #351's context: "Fora da janela ativa,
// Solstice Tickets nao abertos ficam parados no inventario ... ate o aluno
// decidir converter" — the ticket itself can't be rolled once its banner
// window closes (openBannerTicket requires an active+launched banner), so
// this is the only way to get value out of one held past its window.
const BANNER_CONVERT_EPIC_FEE = 350;      // -> Starlight Ticket, student pays this (#510)
const BANNER_CONVERT_RARE_CASHBACK = 600; // -> Moonrise Ticket, student receives this (#510)

// Converts 1 unopened Solstice Ticket into either an Starlight Ticket (kind:
// "epic", 700-coin fee) or a Moonrise Ticket (kind: "rare", 400-coin cashback).
// Deliberately NOT a roll: doesn't touch GACHA_PITY's persistent "banner"
// track (#351 decision 3 — must survive untouched across windows) and the
// Rare/Starlight Ticket credited here enters the inventory "clean", same as any
// other bought ticket — no pity progress carried over either direction.
// `coins` is the caller's current balance (same convention as
// buyGachaTicket), only needed to pre-check the Epic fee.
async function convertBannerTicket(kind, coins) {
  if (kind !== "epic" && kind !== "rare") return { ok: false, reason: "invalid-kind" };
  const tickets = await getGachaTickets();
  if ((tickets.banner || 0) <= 0) return { ok: false, reason: "no-ticket" };
  if (kind === "epic" && (coins || 0) < BANNER_CONVERT_EPIC_FEE) {
    return { ok: false, reason: "insufficient-coins", price: BANNER_CONVERT_EPIC_FEE };
  }

  const updated = { ...tickets, banner: tickets.banner - 1, [kind]: (tickets[kind] || 0) + 1 };
  await storageSet(GACHA_TICKETS_KEY, updated, false);

  const coinDelta = kind === "epic" ? -BANNER_CONVERT_EPIC_FEE : BANNER_CONVERT_RARE_CASHBACK;
  const reason = kind === "epic"
    ? "Solstice Ticket conversion fee (-> Starlight Ticket)"
    : "Solstice Ticket conversion cashback (-> Moonrise Ticket)";
  const newCoins = await creditCoins(coinDelta, reason);

  // Not a roll against a table — logged as its own history kind/key so it
  // never gets mistaken for a real Solstice pull in the Wish History (#381).
  await appendGachaHistoryEntry({ kind: "banner", key: `convert_${kind}`, avatarId: null, coins: coinDelta, rarity: null });

  return { ok: true, tickets: updated, newCoins, convertedTo: kind, coinDelta };
}

// #718 — opens 1 Dawn Ticket (Hearthbound event). Returns same shape as
// openBannerTicket. Hard pity at 45 → guaranteed Legendary (GACHA_PITY.dawn).
// Cashback when featured avatar already owned: Legendary→+1 Solstice, Epic→+1 Starlight, Rare→+1 Moonrise.
async function openDawnTicket(profile, { simulate = false } = {}) {
  const dawnCount = simulate ? 1 : ((await storageGet(HEARTHBOUND_TICKETS_KEY, false)) || 0);
  if (!simulate && dawnCount <= 0) return { ok: false, reason: "no-ticket" };

  const featured = await getHearthboundFeatured();
  const owned = new Set(profile.unlockedAvatars || []);

  // Build weighted roll table (100 total)
  const legendaryAvail = !!featured.legendary && !owned.has(featured.legendary?.id);
  const epic1Avail     = !!featured.epic1     && !owned.has(featured.epic1?.id);
  const epic2Avail     = !!featured.epic2     && !owned.has(featured.epic2?.id);
  const rareAvail      = !!featured.rare      && !owned.has(featured.rare?.id);

  const table = [
    ["legendary_event", 2.25],
    ["epic1_event",     3.25],
    ["epic2_event",     3.25],
    ["rare_event",      4.25],
    ["avatar_rare",     1.25],
    ["avatar_uncommon",  5],
    ["avatar_common",    5],
    ["coins_500",       21],
    ["coins_750",       20],
    ["coins_1000",      14.75],
    ["coins_1200",       8],
    ["coins_1500",       5],
    ["coins_1750",       4],
    ["coins_2000",       3],
  ];
  const jackpotKey = "legendary_event";

  let pityCount = 0;
  let boostedTable = table;
  if (!simulate) {
    const pity = await getGachaPity();
    pityCount = pity.dawn || 0;
    boostedTable = applyPityBoost(table, jackpotKey, pityCount, GACHA_PITY.dawn.softStart, GACHA_PITY.dawn.hardCap);
  }

  const key = rollWeightedTable(boostedTable);
  let coinReward   = 0;
  let avatar       = null;
  let cashbackKind = null; // "banner" | "epic" | "rare" — ticket cashback for owned featured

  if (key === "legendary_event") {
    if (legendaryAvail) {
      avatar = featured.legendary;
    } else {
      cashbackKind = "banner"; // Legendary owned → Solstice Ticket
    }
  } else if (key === "epic1_event") {
    if (epic1Avail) {
      avatar = featured.epic1;
    } else {
      cashbackKind = "epic"; // Epic1 owned → Starlight Ticket
    }
  } else if (key === "epic2_event") {
    if (epic2Avail) {
      avatar = featured.epic2;
    } else {
      cashbackKind = "epic"; // Epic2 owned → Starlight Ticket
    }
  } else if (key === "rare_event") {
    if (rareAvail) {
      avatar = featured.rare;
    } else {
      cashbackKind = "rare"; // Rare owned → Moonrise Ticket
    }
  } else if (key === "avatar_rare")     { avatar = pickRandomUnownedAvatar("rare",     profile); }
  else if (key === "avatar_uncommon")   { avatar = pickRandomUnownedAvatar("uncommon",  profile); }
  else if (key === "avatar_common")     { avatar = pickRandomUnownedAvatar("common",    profile); }
  else coinReward = parseInt(key.split("_")[1], 10);

  // Fallback coin when pool avatar is nil (all owned)
  if (key.startsWith("avatar_") && !avatar && !cashbackKind) coinReward = BANNER_TICKET_PRICE;

  const hitJackpot = key === jackpotKey && !!avatar;

  // Consume ticket
  if (!simulate) {
    await storageSet(HEARTHBOUND_TICKETS_KEY, Math.max(0, dawnCount - 1), false);
    { const _u = getCurrentUsername(); if (_u) mirrorStudentWallet(_u).catch(() => {}); }
  }

  // Unlock avatar or credit coins
  let updatedProfile = profile;
  if (avatar && !simulate) {
    updatedProfile = { ...profile, unlockedAvatars: [...(profile.unlockedAvatars || []), avatar.id] };
    await storageSet(KEYS.profile, updatedProfile, false);
    await mirrorUnlockedAvatarsToRoster(profile.username, updatedProfile.unlockedAvatars, profile);
  }
  // Cashback ticket grant
  let cashbackTickets = null;
  if (cashbackKind && !simulate) {
    const tickets = await getGachaTickets();
    cashbackTickets = { ...tickets, [cashbackKind]: (tickets[cashbackKind] || 0) + 1 };
    await storageSet(GACHA_TICKETS_KEY, cashbackTickets, false);
  }
  const newCoins = (!simulate && coinReward) ? await creditCoins(coinReward, "Dawn Ticket reward") : null;

  const nextPityCount = hitJackpot ? 0 : pityCount + 1;
  if (!simulate) {
    await updateGachaPity("dawn", hitJackpot);
    await appendGachaHistoryEntry({ kind: "dawn", key, avatarId: avatar?.id || null, coins: coinReward || 0, rarity: avatar?.rarity || null });
  }

  return {
    ok: true, avatar: avatar || null, coins: coinReward || 0, newCoins,
    profile: simulate ? profile : updatedProfile, simulate,
    cashbackKind: cashbackKind || null, cashbackTickets,
    pityCount: simulate ? undefined : nextPityCount,
    dawnRemaining: simulate ? dawnCount : Math.max(0, dawnCount - 1),
  };
}

const PARTS_OF_SPEECH = ["noun", "verb", "adjective", "adverb", "pronoun", "preposition", "conjunction", "interjection", "particle", "classifier", "numeral"];

