function getLast7Days() {
  const days = [];
  for (let i = 6; i >= 0; i--) {
    const d = new Date();
    d.setDate(d.getDate() - i);
    const label = ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'][d.getDay()];
    const key   = `${d.getFullYear()}-${pad2(d.getMonth()+1)}-${pad2(d.getDate())}`;
    days.push({ key, label, isToday: i === 0 });
  }
  return days;
}

async function loadSundayHistory() {
  try {
    const keys = await storageList('st:', false);
    if (!keys.length) return [];
    const sessions = await Promise.all(keys.map(k => storageGet(k, false)));
    return sessions
      .filter(s => s?.completed)
      .sort((a, b) => b.date.localeCompare(a.date))
      .slice(0, 8); // last 8 Sunday Tests
  } catch (e) { return []; }
}

function computeExTypeStats(history) {
  const types = {
    C: { correct: 0, total: 0, label: '🎯 Choose' },
    A: { correct: 0, total: 0, label: '🔊 Listen' },
    T: { correct: 0, total: 0, label: '🧩 Build'  },
    S: { correct: 0, total: 0, label: '🔤 Spell'  },
    W: { correct: 0, total: 0, label: '⌨️ Write'  },
    E: { correct: 0, total: 0, label: '🖼️ Match'  },
    R: { correct: 0, total: 0, label: '🔎 Recognize' },
    D: { correct: 0, total: 0, label: '🎤 Say it'  },
  };
  history.forEach(s => {
    Object.values(s.results || {}).forEach(r => {
      // Issue #103 — migrate legacy "B" exercise results (pre-refactor) into
      // their promoted type using the old bFormat field, so exercise-type
      // breakdowns for past Sunday Tests still render correctly.
      let t = r.exerciseType;
      if (t === "B") {
        t = r.bFormat === "spelling" ? "S" : r.bFormat === "typing" ? "W" : "T";
      }
      if (types[t]) { types[t].total++; if (r.correct) types[t].correct++; }
    });
  });
  return types;
}

// ---------------------------------------------------------------------------
// Issue #74 — Pronunciation stats: aggregate per-word pronunciation scores
// from progMap to find the student's weakest pronunciation words.
// Returns [{ word, avgScore, attempts }] sorted by avgScore ascending.
// ---------------------------------------------------------------------------
function computePronStats(progMap, words) {
  const wordMap = Object.fromEntries(words.map(w => [w.id, w]));
  const entries = Object.entries(progMap)
    .filter(([id, p]) => p.pronScores && p.pronScores.length > 0 && wordMap[id])
    .map(([id, p]) => {
      const scores = p.pronScores;
      const avg = Math.round(scores.reduce((s, x) => s + x, 0) / scores.length);
      return { word: wordMap[id], avgScore: avg, attempts: scores.length, lastScore: scores[scores.length - 1] };
    })
    .sort((a, b) => a.avgScore - b.avgScore); // weakest first
  return entries;
}
