// ---------------------------------------------------------------------------
const ROSTER_PREFIX     = "roster:";             // shared: roster:<username>
// Issue #304 — teacher-facing level-up notification feed. Cross-user by
// nature (student's client writes, teacher's client — a different login
// session — reads), so it lives in shared_kv, capped to the last 50 entries.
const TEACHER_LEVELUP_FEED_KEY = "teacher-levelup-feed";
const TEACHER_LEVELUP_FEED_MAX = 50;

const isTeacher = (profile) => profile?.role === "teacher";

// Sprint 12 — the teacher access code and the role decision now live
// entirely server-side (see supabase-schema/sprint12_teacher_rbac.sql).
// The client never sees the real code — it only calls RPCs and gets back
// true/false, or (for a logged-in teacher) the current code to display.
async function claimTeacherRole(code) {
  const client = await getSupabaseClient();
  const { data, error } = await client.rpc("claim_teacher_role", { p_code: code });
  if (error) return false;
  return !!data;
}

async function ensureStudentProfile(username) {
  const client = await getSupabaseClient();
  await client.rpc("ensure_student_profile", { p_username: username });
}

async function fetchMyRole() {
  const client = await getSupabaseClient();
  const _sbUser = getStorageUser();
  if (!_sbUser) return "student";
  const { data, error } = await client
    .from("account_roles").select("role").eq("user_id", _sbUser.id).maybeSingle();
  if (error || !data) return "student";
  return data.role;
}

async function registerStudent(profile) {
  // Self-register in shared roster so teacher can discover this student.
  //
  // BUG FIX (2026-07-06): this used to write a brand-new object from
  // scratch on every single login (not just the first one). storageSet's
  // shared_kv upsert replaces the ENTIRE stored JSON blob for the key — it
  // does not merge fields — so every re-login was silently wiping out
  // teacher-managed roster fields that live under this same key, most
  // importantly `enabledClassCodes` (a student's released ClassCodes would
  // revert to "locked/default" the next time they logged back in). Now we
  // read the existing entry first and only refresh the identity fields,
  // preserving everything else (enabledClassCodes, etc.) and the original
  // joinedAt.
  const key = `${ROSTER_PREFIX}${profile.username}`;
  const { value: existing, error } = await storageGetSafe(key, true);
  if (error) {
    // Issue #251 — never fall back to `{}` on a failed read here: that's
    // exactly the old bug this function's 2026-07-06 fix addressed, just
    // reappearing through a different door. Skip this write; the next
    // successful login retries it.
    console.error(`[registerStudent] aborting roster write for "${profile.username}" — couldn't read existing record:`, error);
    return;
  }
  // #737 — generate or reuse persistent student code (HMAC-SHA256 of user_id)
  let studentCode = existing?.studentCode;
  if (!studentCode) {
    try {
      const sbUser = getStorageUser();
      if (sbUser?.id) {
        studentCode = await generateStudentCode(sbUser.id);
        // reverse-lookup index: sc:CODE → username (shared, so teacher can query)
        await storageSet(`sc:${studentCode}`, profile.username, true);
      }
    } catch (_) {}
  }

  await storageSet(
    key,
    {
      ...(existing || {}),
      username: profile.username,
      level: profile.level,
      joinedAt: existing?.joinedAt || Date.now(),
      avatar: profile.avatar || existing?.avatar || DEFAULT_AVATAR_ID,
      ...(studentCode ? { studentCode } : {}),
      // #845 — auto-enroll: new students get S0C1 on first registration;
      // existing entries preserve whatever the teacher already configured.
      ...(!existing ? { enabledClassCodes: ["S0C1"] } : {}),
    },
    true
  );
}

async function loadRoster() {
  try {
    const keys = await storageList(ROSTER_PREFIX, true);
    if (!keys.length) return [];
    const entries = await Promise.all(keys.map(k => storageGet(k, true)));
    // Issue #251 — a single roster record missing `username` (e.g. corrupted
    // by a partial overwrite elsewhere) used to throw inside .sort() and get
    // caught by this function's own try/catch, silently returning [] for the
    // ENTIRE class — one bad student wiped everyone off the Teacher Panel.
    // Now: drop only the bad record (and log it) so the rest of the roster
    // still renders.
    const valid = entries.filter(e => e && typeof e.username === "string");
    const corrupted = entries.length - valid.length;
    if (corrupted > 0) {
      console.error(`[loadRoster] dropped ${corrupted} roster record(s) missing a valid "username" field — check for a stale read-merge-write overwrite.`);
    }
    return valid.sort((a, b) => a.username.localeCompare(b.username));
  } catch (e) {
    console.error("[loadRoster] exception:", e);
    return [];
  }
}

// Issue #176 — mirrors a student's unlockedAvatars into their roster entry
// (read-merge-write, same pattern as registerStudent's bug fix above — never
// blind-overwrite the shared blob). Needed so the Teacher Panel gift modal
// can see which avatars a student already owns without any RPC. Called
// everywhere unlockedAvatars changes: the #162 random draw, the #181
// monthly cat, the #168 shop purchase, and a claimed #176 gift itself.
async function mirrorUnlockedAvatarsToRoster(username, unlockedAvatars, profile) {
  // Issue #251 — teacher accounts (e.g. previewing/testing the Gacha) have
  // no business in the student roster. Mirroring for them is exactly how
  // `roster:Khem` (a teacher account) ended up as a stray entry in the
  // roster in the first place — it later got corrupted and crashed the
  // Teacher Panel's roster sort for every real student, not just Khem.
  if (isTeacher(profile)) return;
  const key = `${ROSTER_PREFIX}${username}`;
  // Root cause of the "No students yet" Teacher Panel bug: this used to do
  // `(await storageGet(key, true)) || {}` and write straight through. If
  // that read failed for ANY reason (the storage layer used to swallow
  // errors silently — see #251), `existing` fell back to `{}` and this
  // overwrote the WHOLE roster record with nothing but `{unlockedAvatars}`
  // — wiping username/level/joinedAt/enabledClassCodes. Now: abort the
  // write (log + bail) if the read didn't succeed, and always carry
  // `username` through explicitly since we already have it as a param.
  const { value: existing, error } = await storageGetSafe(key, true);
  if (error) {
    console.error("[mirrorUnlockedAvatarsToRoster] aborting write — couldn't read existing roster record for", username, "-", error);
    return;
  }
  await storageSet(key, { ...(existing || {}), username, unlockedAvatars }, true);
}

// ---------------------------------------------------------------------------
// Issue #304 — teacher-facing level-up notification feed (deferred out of
// #45 on purpose). Read-merge-write on shared_kv, so this MUST use
// storageGetSafe — never `storageGet(...) || []` — same rule established by
// #251/#282 (that exact shortcut already caused 2 data-corruption bugs).
// ---------------------------------------------------------------------------
async function notifyTeacherLevelUp(username, fromLevel, toLevel) {
  const { value: existing, error } = await storageGetSafe(TEACHER_LEVELUP_FEED_KEY, true);
  if (error) {
    console.error("[notifyTeacherLevelUp] aborting — couldn't read existing feed:", error);
    return;
  }
  const feed = Array.isArray(existing) ? existing : [];
  const entry = {
    id:        `${username}-${toLevel}-${Date.now()}`,
    username, fromLevel, toLevel,
    at:        Date.now(),
    seen:      false,
  };
  await storageSet(TEACHER_LEVELUP_FEED_KEY, [entry, ...feed].slice(0, TEACHER_LEVELUP_FEED_MAX), true);
}

async function loadTeacherLevelUpFeed() {
  const { value, error } = await storageGetSafe(TEACHER_LEVELUP_FEED_KEY, true);
  if (error) { console.error("[loadTeacherLevelUpFeed] read failed:", error); return []; }
  return Array.isArray(value) ? value : [];
}

// Marks every entry seen (called once the teacher actually opens the feed).
// No-ops (skips the write) if everything is already seen.
async function markTeacherLevelUpFeedSeen() {
  const { value: existing, error } = await storageGetSafe(TEACHER_LEVELUP_FEED_KEY, true);
  if (error || !Array.isArray(existing) || existing.length === 0) return;
  if (existing.every(e => e.seen)) return;
  await storageSet(TEACHER_LEVELUP_FEED_KEY, existing.map(e => ({ ...e, seen: true })), true);
}

// ---------------------------------------------------------------------------
// Sprint 6.4 — Student stats written to shared storage so teacher can read them
// ---------------------------------------------------------------------------
const STUDENT_STATS_PREFIX = "student-stats:"; // shared: student-stats:<username>

// Issue #57 — `extra` merges additional fields into the shared payload
// without disturbing the existing shape every other reader already expects
// (teacher roster overview, #55's activity polling). Used to mirror
// berserkStars in so the teacher's polling below can detect a newly
// cleared tier the same way it already detects a streak bump.
async function updateSharedStats(profile, progMap, streak, extra = {}) {
  if (isTeacher(profile)) return; // teachers don't write student stats
  const entries  = Object.values(progMap);
  const total    = entries.reduce((s, p) => s + p.count, 0);
  const gotIt    = entries.reduce((s, p) => s + Math.max(0, p.streak), 0); // proxy for got-it total
  const attempted = entries.filter(p => p.count > 0).length;
  const mastered  = entries.filter(p => p.srsInterval >= 14).length;
  // Issue #56 — read-modify-write instead of a blind overwrite: a previous
  // call's mirrored `extra` field (berserkStars from #57, lastSundayTestDate,
  // the new berserk achievement/attempt logs below, ...) must survive a LATER
  // call that doesn't repeat it — otherwise e.g. finishing a plain Practice
  // session right after clearing a Berserk tier would silently wipe that
  // tier's mirrored timestamp off the teacher-visible row. Same storageGetSafe
  // rule as #251/#282: bail out (skip the write) rather than risk building
  // the merge base from a masked read failure.
  const key = `${STUDENT_STATS_PREFIX}${profile.username}`;
  const { value: existing, error } = await storageGetSafe(key, true);
  if (error) { console.error("[updateSharedStats] read failed, skipping write:", error); return; }
  await storageSet(key, {
    ...(existing || {}),
    username:       profile.username,
    level:          profile.level || "Pre-A1",
    streak:         streak?.count || 0,
    totalAnswered:  total,
    wordsAttempted: attempted,
    wordsMastered:  mastered,
    lastActive:     Date.now(),
    ...extra,
  }, true);
}

// ---------------------------------------------------------------------------
// #738 — Student event timeline (shared_kv mirror, written from student side)
// ---------------------------------------------------------------------------
const STUDENT_EVENTS_KEY = (u) => `student-events:${u}`; // shared: [{type,date,desc,icon}] newest-first, max 30
const STUDENT_WALLET_KEY = (u) => `student-wallet:${u}`; // shared: {coins, tickets:{rare,epic,banner}, dawnTickets}

async function appendStudentEvent(username, { type, desc, icon }) {
  const key = STUDENT_EVENTS_KEY(username);
  const { value: existing, error } = await storageGetSafe(key, true);
  if (error) return;
  const prev = Array.isArray(existing) ? existing : [];
  const entry = { type, desc, icon, date: Date.now() };
  const next = [entry, ...prev].slice(0, 30);
  await storageSet(key, next, true);
}

// #758 — appends achievement + milestone timeline events after a runAchievementEngine call
async function appendAchievementTimelineEvents(username, newOnes, prevAchIds) {
  if (!username || !newOnes?.length) return;
  const prevSet = new Set(Array.isArray(prevAchIds) ? prevAchIds : []);
  for (const ach of newOnes) {
    const isMilestone = MILESTONES_DEF.some(m => m.id === ach.id);
    if (isMilestone) {
      appendStudentEvent(username, { type: "milestone", desc: ach.title || "Milestone unlocked", icon: "🏆" }).catch(() => {});
    } else {
      appendStudentEvent(username, { type: "achievement", desc: ach.title || "Achievement unlocked", icon: "⭐" }).catch(() => {});
    }
  }
}

async function mirrorStudentWallet(username) {
  try {
    const [coins, tickets, dawnTickets] = await Promise.all([
      storageGet(COINS_KEY, false),
      storageGet(GACHA_TICKETS_KEY, false),
      storageGet(HEARTHBOUND_TICKETS_KEY, false),
    ]);
    await storageSet(STUDENT_WALLET_KEY(username), {
      coins: coins || 0,
      tickets: tickets || {},
      dawnTickets: dawnTickets || 0,
      mirroredAt: Date.now(),
    }, true);
  } catch (_) {}
}

// ---------------------------------------------------------------------------
// Sprint 6.2 — Class code helpers
// ---------------------------------------------------------------------------
const CLASS_CODES_KEY = "class-codes"; // shared registry of imported class codes

// Auto-suggest a class code from a filename
// "Stage_1_-_Class_1_-_Thai_Vowels.pptx" → "S1C1"
function suggestClassCode(filename) {
  const base = filename.replace(/\.[^.]+$/, "");
  const nums = base.match(/\d+/g);
  if (!nums || nums.length === 0) return "";
  if (nums.length === 1) return `S${nums[0]}`;
  return `S${nums[0]}C${nums[1]}`;
}

// ---------------------------------------------------------------------------
// Sprint 6.3 — Visible words filter (class codes per student)
// ---------------------------------------------------------------------------
// enabledCodes null/undefined = not resolved yet (loading) → defensive fallback, show all
// enabledCodes [] = locked (default for new/unconfigured students, or teacher explicitly cleared) → show nothing
// enabledCodes ["S1C1"] = filter to that code (words without classCode always visible)
function getVisibleWords(words, profile, enabledCodes, studentNodeIndex = null) {
  if (isTeacher(profile)) return words;
  if (enabledCodes == null) return words;
  if (enabledCodes.length === 0) return [];
  const codeSet = new Set(enabledCodes);
  return words.filter(w => {
    if (w.classCode && !codeSet.has(w.classCode)) return false;
    // #844 — words with lessonNodeIndex are locked until the student reaches that node
    if (w.lessonNodeIndex != null && studentNodeIndex != null && w.lessonNodeIndex > studentNodeIndex) return false;
    return true;
  });
}

// Issue #91 — calcLevelProgress: pure function, no UI.
// Calculates student mastery within their current level.
// mastered = srsInterval >= 14 (same threshold as isWordMastered / achievements).
// Pre-#75 records (no level field) fall back to "Pre-A1".
function calcLevelProgress(words, progMap, profile, enabledClassCodes) {
  const level = profile?.level || "Pre-A1";
  const visible = getVisibleWords(words, profile, enabledClassCodes);
  const levelWords = visible.filter(w => (w.level || "Pre-A1") === level);
  if (levelWords.length === 0) {
    return { level, totalWords: 0, practicedWords: 0, masteredWords: 0, percent: 0 };
  }
  const practiced = levelWords.filter(w => (progMap[w.id]?.count || 0) > 0).length;
  const mastered  = levelWords.filter(w => (progMap[w.id]?.srsInterval || 0) >= 14).length;
  return {
    level,
    totalWords:     levelWords.length,
    practicedWords: practiced,
    masteredWords:  mastered,
    percent:        Math.round((mastered / levelWords.length) * 100),
  };
}

