function getPowerById(id) {
  return POWER_CATALOG.find((p) => p.id === id) || null;
}

// Powers a teacher may legally offer for a given avatar/slot combo — Common
// and Uncommon avatars never get a "special" slot (see RARITY_POWER_COOLDOWN,
// which has no `special` entry for those two tiers), so the Phase 2 UI
// should call this rather than showing the full catalog unfiltered.
function getAssignablePowers(mechanic, avatarRarity) {
  if (mechanic === "special" && !RARITY_POWER_COOLDOWN[avatarRarity]?.special) return [];
  return POWER_CATALOG.filter((p) => p.mechanic === mechanic);
}

// ---------------------------------------------------------------------------
// Issue #184 / #214 — teacher-editable avatar → power assignment.
// Shared KV (not hardcoded in AVATAR_CATALOG) because — unlike avatar art —
// this is meant to be curated by the teacher without a code deploy (see
// issue #214 discussion: "deixar o professor cadastrar os poderes"). Read
// with getAvatarPowersConfig(), written with setAvatarPowerAssignment() —
// the Phase 2 teacher screen is the first real caller of the setter; Phase 1
// only ships the schema + helpers.
//
// Shape: { [avatarId]: { simple: powerId|null, special: powerId|null,
//                         passive: powerId|null, passive2: powerId|null } }
// An avatar is expected to use at most one mechanic in practice (either the
// consumable pair or passive(s)), but the shape doesn't hard-enforce
// that — Phase 2's UI is the enforcement point, matching the "trust the
// teacher's judgment, no automatic rarity gating on assignment" decision.
// Issue #287 — dropped passiveWindow: every passive power id now carries
// its own fixed window baked into POWER_CATALOG (see coins_50_morning etc.),
// so there's nothing left to store per-assignment for it. Old records with
// a leftover passiveWindow key are harmless — just unread dead data.
// Issue #295 — added passive2, an optional 2nd passive slot (e.g. pairing a
// positive bonus with a negative drawback for balance on the same avatar).
// Old records simply have no passive2 key, which reads as null — no
// migration needed.
const AVATAR_POWERS_CONFIG_KEY = "avatar-powers-config"; // shared

async function getAvatarPowersConfig() {
  return (await storageGet(AVATAR_POWERS_CONFIG_KEY, true)) || {};
}

async function setAvatarPowerAssignment(avatarId, patch) {
  const cfg = await getAvatarPowersConfig();
  cfg[avatarId] = { ...(cfg[avatarId] || { simple: null, special: null, passive: null }), ...patch };
  await storageSet(AVATAR_POWERS_CONFIG_KEY, cfg, true);
  return cfg[avatarId];
}

// ---------------------------------------------------------------------------
// Issue #184 / #214 — per-student charge state for consumable powers.
// Personal KV: each student's own last-used timestamps, independent of which
// avatar they currently wear (so switching avatars doesn't reset/refresh a
// charge — the cooldown tracks the STUDENT, keyed by slot). Phase 3 wires
// the actual "can I use it right now" / "consume it" logic on top of this;
// Phase 1 only ships the read/write primitives.
//
// Shape: { simple: { lastUsedAt: epochMs|null }, special: { lastUsedAt: epochMs|null } }
const AVATAR_POWER_CHARGES_KEY = "avatar-power-charges"; // personal

async function getPowerCharges() {
  return (await storageGet(AVATAR_POWER_CHARGES_KEY, false)) || { simple: { lastUsedAt: null }, special: { lastUsedAt: null } };
}

async function recordPowerUse(slot) {
  const charges = await getPowerCharges();
  charges[slot] = { lastUsedAt: Date.now() };
  await storageSet(AVATAR_POWER_CHARGES_KEY, charges, false);
  return charges;
}

// Cooldown check — Phase 3 will call this before allowing a consumable power
// to be used. Kept here now since it only needs the rarity table + charge
// state, both already defined above.
function isPowerCharged(slot, avatarRarity, charges) {
  const cooldownDays = RARITY_POWER_COOLDOWN[avatarRarity]?.[slot];
  if (!cooldownDays) return false; // this rarity doesn't get this slot at all
  const lastUsedAt = charges?.[slot]?.lastUsedAt;
  if (!lastUsedAt) return true; // never used — charged from the start
  const msSinceUse = Date.now() - lastUsedAt;
  return msSinceUse >= cooldownDays * 24 * 60 * 60 * 1000;
}

// ---------------------------------------------------------------------------
// Issue #184 / #220 — Fase 3/3: mecanismo genérico de ativação de poderes.
//
// Um poder consumível (simple/special) precisa ser "armado" pelo aluno antes
// de valer para a sessão/janela — diferente dos passivos, que valem sempre
// que o avatar equipado tiver um atribuído. AVATAR_ACTIVE_BOOST_KEY guarda no
// máximo 1 boost ativo por slot (simple e special são independentes, podem
// estar ativos ao mesmo tempo).
//
// Shape: { simple: ActiveBoost|null, special: ActiveBoost|null }
// ActiveBoost: { powerId, armedAt, expiresAt: epochMs|null, consumedByNextSession: boolean }
//   - expiresAt null + consumedByNextSession true  → duration "session"
//   - expiresAt set                                 → duration "3h"/"1day"
//   - expiresAt null + consumedByNextSession false  → duration null (streak
//     freeze / exam retry / gacha discount — consumido pelo evento, não por
//     tempo nem por sessão)
// ---------------------------------------------------------------------------
const AVATAR_ACTIVE_BOOST_KEY = "avatar-active-boosts"; // personal

async function getActiveBoosts() {
  const raw = (await storageGet(AVATAR_ACTIVE_BOOST_KEY, false)) || { simple: null, special: null };
  const now = Date.now();
  let changed = false;
  for (const slot of ["simple", "special"]) {
    const boost = raw[slot];
    if (boost?.expiresAt && now >= boost.expiresAt) { raw[slot] = null; changed = true; }
  }
  if (changed) await storageSet(AVATAR_ACTIVE_BOOST_KEY, raw, false);
  return raw;
}

// Poder(es) atribuído(s) ao avatar que o aluno tem equipado agora.
function getEquippedPowerAssignment(profile, powersConfig) {
  if (!profile?.avatar) return null;
  return (powersConfig || {})[profile.avatar] || null;
}

// Ativa (arma) um poder consumível carregado no slot indicado. Retorna
// { ok: true, boost } ou { ok: false, reason }.
async function activatePower(profile, powersConfig, slot) {
  const assignment = getEquippedPowerAssignment(profile, powersConfig);
  const powerId = assignment?.[slot];
  if (!powerId) return { ok: false, reason: "no_power_assigned" };
  const power = getPowerById(powerId);
  if (!power) return { ok: false, reason: "unknown_power" };

  const avatar = getAvatarById(profile.avatar);
  const charges = await getPowerCharges();
  if (!isPowerCharged(slot, avatar?.rarity, charges)) return { ok: false, reason: "on_cooldown" };

  const activeBoosts = await getActiveBoosts();
  if (activeBoosts[slot]) return { ok: false, reason: "already_active" };

  const armedAt = Date.now();
  let expiresAt = null;
  const durationMs = { "3h": 3 * 60 * 60 * 1000, "1day": 24 * 60 * 60 * 1000 }[power.duration];
  if (durationMs) expiresAt = armedAt + durationMs;

  // #480 — Yaa Dom: grant energy immediately on activation, no persistent boost stored
  if (power.effect.type === "energyGrantOnActivate") {
    await recordPowerUse(slot);
    await addS0Energy(power.effect.value ?? 0);
    return { ok: true, boost: null, energyGranted: power.effect.value ?? 0 };
  }

  const boost = {
    powerId,
    armedAt,
    expiresAt,
    consumedByNextSession: power.duration === "session",
  };
  activeBoosts[slot] = boost;
  await storageSet(AVATAR_ACTIVE_BOOST_KEY, activeBoosts, false);
  await recordPowerUse(slot);
  return { ok: true, boost };
}

// Chamado ao completar uma sessão de Practice/Sunday Test — limpa qualquer
// boost com duration "session" (já foi usado, não deve sobreviver pra
// próxima sessão).
async function consumeSessionBoosts() {
  const activeBoosts = await getActiveBoosts();
  let changed = false;
  for (const slot of ["simple", "special"]) {
    if (activeBoosts[slot]?.consumedByNextSession) { activeBoosts[slot] = null; changed = true; }
  }
  if (changed) await storageSet(AVATAR_ACTIVE_BOOST_KEY, activeBoosts, false);
  return activeBoosts;
}

// Coleta todos os efeitos "ativos agora" (boosts armados + passivo do avatar
// equipado, respeitando janela de horário) num único array de `effect`
// objects — ponto único de leitura pros helpers de efeito abaixo.
function collectActiveEffects(profile, powersConfig, activeBoosts, now = Date.now()) {
  const effects = [];
  const assignment = getEquippedPowerAssignment(profile, powersConfig);

  for (const slot of ["simple", "special"]) {
    const boost = activeBoosts?.[slot];
    if (!boost) continue;
    if (boost.expiresAt && now >= boost.expiresAt) continue;
    const power = getPowerById(boost.powerId);
    if (power) effects.push(power.effect);
  }

  // Issue #295 — up to 2 passives per avatar now (passive + passive2), e.g.
  // a positive coin/countdown bonus paired with a negative drawback for
  // balance. Both read the same way; passive2 is just optional.
  for (const passiveSlot of ["passive", "passive2"]) {
    if (!assignment?.[passiveSlot]) continue;
    const power = getPowerById(assignment[passiveSlot]);
    // Issue #287 — every passive power now carries its own fixed window
    // (morning/afternoon/evening/night/allday); there's no more generic
    // "pick a window at assignment time" power, so this just reads power.window.
    if (power && isPowerTimeWindowActive(power.window, now)) effects.push(power.effect);
  }
  return effects;
}

function isPowerTimeWindowActive(windowKey, now = Date.now()) {
  if (!windowKey || windowKey === "allday") return true;
  const win = POWER_TIME_WINDOWS[windowKey];
  if (!win) return true;
  const hourNow = new Date(now).getHours() + new Date(now).getMinutes() / 60;
  const { startHour, endHour } = win;
  if (endHour <= 24) return hourNow >= startHour && hourNow < endHour;
  // wraps past midnight (e.g. 22:00–06:00 → endHour 30)
  return hourNow >= startHour || hourNow < (endHour - 24);
}

// Soma o bônus extra de Meowtongs (fração, ex.: 0.25 = +25%) de todos os
// efeitos coinsMultiplierBonus ativos agora.
function getCoinsBonusFraction(profile, powersConfig, activeBoosts, now = Date.now()) {
  const effects = collectActiveEffects(profile, powersConfig, activeBoosts, now);
  return effects
    .filter(e => e.type === "coinsMultiplierBonus")
    .reduce((sum, e) => sum + (e.value || 0), 0);
}

// Efeito líquido sobre o countdown do Practice Mode (scope "practice" ou sem
// scope). disableCountdown/pauseCountdown vencem sobre countdownMultiplier
// se coexistirem (não deve acontecer na prática, mas a ordem é essa).
// Issue #295 — countdownMultiplier effects now COMPOUND (multiply together)
// instead of taking the max. Math.max assumed every multiplier was a bonus
// (>1, longer = easier); now that a negative passive (<1, shorter = harder)
// can coexist with a positive one (e.g. avatar has both a +50% window
// passive and the "Not today" -25% passive), max would silently discard
// whichever multiplier is smaller. Multiplying lets both apply at once —
// with a single effect active this is a no-op (1 * value === value).
function getPracticeCountdownEffect(profile, powersConfig, activeBoosts, now = Date.now()) {
  const effects = collectActiveEffects(profile, powersConfig, activeBoosts, now)
    .filter(e => !e.scope || e.scope === "practice");
  const disable = effects.some(e => e.type === "disableCountdown");
  const pause   = effects.some(e => e.type === "pauseCountdown");
  const multiplier = effects
    .filter(e => e.type === "countdownMultiplier")
    .reduce((acc, e) => acc * (e.value || 1), 1);
  // Issue #439 — expose cat name + label for the in-session countdown flag
  const hasEffect = disable || pause || multiplier !== 1;
  const catName = hasEffect ? (getAvatarById(profile?.avatar)?.name || null) : null;
  let label = null;
  if (disable)        label = "No Countdown";
  else if (pause)     label = "Paused Countdown";
  else if (multiplier > 1) label = "Slower Countdown";
  else if (multiplier < 1) label = "Faster Countdown";
  return { disable, pause, multiplier, catName, label };
}

// Issue #439 — human-readable label for a power slot still in cooldown.
function getPowerRechargeLabel(slot, avatarRarity, charges) {
  const cooldownDays = RARITY_POWER_COOLDOWN[avatarRarity]?.[slot];
  if (!cooldownDays) return "Recharging";
  const lastUsedAt = charges?.[slot]?.lastUsedAt;
  if (!lastUsedAt) return "Recharging";
  const remainingMs = cooldownDays * 24 * 60 * 60 * 1000 - (Date.now() - lastUsedAt);
  if (remainingMs <= 0) return "Recharging";
  const days  = Math.floor(remainingMs / (24 * 60 * 60 * 1000));
  const hours = Math.floor((remainingMs % (24 * 60 * 60 * 1000)) / (60 * 60 * 1000));
  const mins  = Math.floor((remainingMs % (60 * 60 * 1000)) / (60 * 1000));
  if (days > 0)  return `Recharges in ${days}d ${hours}h`;
  if (hours > 0) return `Recharges in ${hours}h ${mins}m`;
  return `Recharges in ${mins}m`;
}

// True se algum efeito ativo remove uma alternativa errada agora.
function getRemoveWrongOptionActive(profile, powersConfig, activeBoosts, now = Date.now()) {
  return collectActiveEffects(profile, powersConfig, activeBoosts, now)
    .some(e => e.type === "removeWrongOption");
}

// #480 — Path Mode energy power helpers
function getEnergyCostHalfActive(profile, powersConfig, activeBoosts, now = Date.now()) {
  return collectActiveEffects(profile, powersConfig, activeBoosts, now)
    .some(e => e.type === "energyCostHalf");
}
function getEnergyMaxBonus(profile, powersConfig, activeBoosts, now = Date.now()) {
  return collectActiveEffects(profile, powersConfig, activeBoosts, now)
    .filter(e => e.type === "energyMaxBonus")
    .reduce((sum, e) => sum + (e.value || 0), 0);
}
function getEnergyGrantPerLesson(profile, powersConfig, activeBoosts, now = Date.now()) {
  return collectActiveEffects(profile, powersConfig, activeBoosts, now)
    .filter(e => e.type === "energyGrantPerLesson")
    .reduce((sum, e) => sum + (e.value || 0), 0);
}

// Remove no máximo 1 alternativa errada de um array de opções { correct }
// gerado por buildOptions/buildImageOptions — nunca remove a correta, nunca
// deixa menos de 2 opções.
function applyRemoveWrongOption(options, active) {
  if (!active || !Array.isArray(options) || options.length <= 2) return options;
  const wrongIdx = options.map((o, i) => (o.correct ? -1 : i)).filter(i => i >= 0);
  if (wrongIdx.length === 0) return options;
  const removeIdx = wrongIdx[Math.floor(Math.random() * wrongIdx.length)];
  return options.filter((_, i) => i !== removeIdx);
}

// Total de desconto (fração) em Bilhetes de Gacha de todos os efeitos
// gachaTicketDiscount ativos agora (passivo + consumível empilham).
function getGachaDiscountFraction(profile, powersConfig, activeBoosts, now = Date.now()) {
  const effects = collectActiveEffects(profile, powersConfig, activeBoosts, now);
  return effects
    .filter(e => e.type === "gachaTicketDiscount")
    .reduce((sum, e) => sum + (e.value || 0), 0);
}

// Consome (se houver) um boost gachaTicketDiscount ativo do tipo oneShot —
// chamado depois que a compra do bilhete já foi efetivada com o preço
// descontado.
async function consumeOneShotEffectsAfterPurchase() {
  const activeBoosts = await getActiveBoosts();
  let changed = false;
  for (const slot of ["simple", "special"]) {
    const boost = activeBoosts[slot];
    if (!boost) continue;
    const power = getPowerById(boost.powerId);
    if (power?.effect?.type === "gachaTicketDiscount" && power.effect.oneShot) {
      activeBoosts[slot] = null;
      changed = true;
    }
  }
  if (changed) await storageSet(AVATAR_ACTIVE_BOOST_KEY, activeBoosts, false);
}

// ---------------------------------------------------------------------------
// Issue #184 / #220 — congelar streak (Fase 3).
//
// SALVAGUARDA (decisão travada do owner, ver #184): isto NUNCA pode virar uma
// forma de pular o requisito normal de completar lição/Sunday Test no dia.
// computeAndSaveStreak só roda quando o aluno de fato completa uma sessão
// HOJE — nada muda nisso. A proteção age de forma reativa e só cobre um
// único dia de gap (lastDate == anteontem, nem ontem nem hoje). Gaps de 2+
// dias nunca são cobertos. STREAK_FREEZE_USES_KEY guarda os timestamps dos
// usos dos últimos 7 dias pra respeitar o `maxPerWeek` do poder, além do
// cooldown natural do slot `special`.
// ---------------------------------------------------------------------------
const STREAK_FREEZE_USES_KEY = "streak-freeze-uses"; // personal: epochMs[]

async function tryConsumeStreakFreeze(profile, powersConfig) {
  const assignment = getEquippedPowerAssignment(profile, powersConfig);
  const powerId = assignment?.special;
  const power = powerId ? getPowerById(powerId) : null;
  if (!power || power.effect?.type !== "streakFreeze") return { used: false };

  const avatar = getAvatarById(profile?.avatar);
  const charges = await getPowerCharges();
  if (!isPowerCharged("special", avatar?.rarity, charges)) return { used: false };

  const now = Date.now();
  const weekAgo = now - 7 * 24 * 60 * 60 * 1000;
  const uses = ((await storageGet(STREAK_FREEZE_USES_KEY, false)) || []).filter(t => t > weekAgo);
  const maxPerWeek = power.effect.maxPerWeek ?? 1;
  if (uses.length >= maxPerWeek) return { used: false };

  await storageSet(STREAK_FREEZE_USES_KEY, [...uses, now], false);
  await recordPowerUse("special");
  return { used: true };
}

// ---------------------------------------------------------------------------
// Issue #184 / #220 — retry de exame sem esperar o professor (self-unlock).
// Mesmo flag de roster que o "Unlock exam" do professor já usa (#43) —
// consumir este poder simplesmente liga o mesmo interruptor, sozinho.
// ---------------------------------------------------------------------------
async function tryConsumeExamRetrySkip(profile, powersConfig, setExamForcedForSelf) {
  const assignment = getEquippedPowerAssignment(profile, powersConfig);
  const powerId = assignment?.special;
  const power = powerId ? getPowerById(powerId) : null;
  if (!power || power.effect?.type !== "examRetrySkipCooldown") return { used: false };

  const avatar = getAvatarById(profile?.avatar);
  const charges = await getPowerCharges();
  if (!isPowerCharged("special", avatar?.rarity, charges)) return { used: false };

  await recordPowerUse("special");
  await setExamForcedForSelf?.();
  return { used: true };
}


// Ensures old profiles (created before this field existed) get sane defaults
// without needing a migration — same KV/no-schema philosophy as the rest of
// the app's storage.
function withAvatarDefaults(profile) {
  if (!profile) return profile;
  return {
    avatar: DEFAULT_AVATAR_ID,
    unlockedAvatars: [],
    ...profile,
  };
}

// Sorteia 1 avatar do pool de prêmios que o aluno ainda não possui, adiciona
// a unlockedAvatars, e persiste o profile atualizado. Se o aluno já possui
// todos os avatares do pool, não faz nada (retorna null, sem erro/duplicata).
// Called by unlock-criteria checks (issue #162) — this function only owns
// the draw + persistence mechanism, not when it's triggered.
async function grantRandomPrizeAvatar(profile) {
  const owned = new Set(profile.unlockedAvatars || []);
  const eligible = getPrizePoolAvatars().filter((a) => !owned.has(a.id));
  if (eligible.length === 0) return null;

  const picked = eligible[Math.floor(Math.random() * eligible.length)];
  const updatedProfile = {
    ...profile,
    unlockedAvatars: [...(profile.unlockedAvatars || []), picked.id],
  };
  await storageSet(KEYS.profile, updatedProfile, false);
  await mirrorUnlockedAvatarsToRoster(profile.username, updatedProfile.unlockedAvatars, profile); // Issue #176
  return { avatar: picked, profile: updatedProfile };
}

// ---------------------------------------------------------------------------
// Issue #162 — Phase 1 avatar unlock criteria
// Each criterion, the FIRST time it's met, triggers one random draw from the
// prize pool (via grantRandomPrizeAvatar) — not a fixed avatar per criterion,
// so different students end up with different avatars from day one.
// AVATAR_UNLOCK_KEY tracks which criteria have already fired so a criterion
// never draws twice, even if its condition stays true across future checks.
// ---------------------------------------------------------------------------
const AVATAR_UNLOCK_KEY = "avatar-unlock-criteria"; // personal: array of fired criterion ids

const AVATAR_UNLOCK_CRITERIA = [
  { id: "avatar_streak_1", title: "First Streak",     desc: "Reach a 1-day practice streak",              check: s => s.streakBest >= 1 },
  { id: "avatar_sunday_1", title: "First Sunday Test", desc: "Complete your first Sunday Test",            check: s => s.sundayTestCount >= 1 },
  { id: "avatar_mastery_1",title: "First Mastery",     desc: "Master your first word (SRS 14d+)",          check: s => s.wordsMastered >= 1 },
  { id: "avatar_combo_7st",title: "Full Week Combo",   desc: "7-day streak + a completed Sunday Test",     check: s => s.streakBest >= 7 && s.sundayTestCount >= 1 },
  // Issue #166 — Phase 2 avatar unlock: 50 words mastered (SRS 14d+)
  { id: "avatar_mastery_50",title: "Mastery Fifty",    desc: "Master 50 words (SRS 14d+)",                 check: s => s.wordsMastered >= 50 },
];

// Checks which unlock criteria are newly met, draws one avatar per newly met
// criterion (in order, so unlockedAvatars stays consistent across draws in
// the same call), and persists both the fired-criteria list and the profile.
// Returns { grants: [{ criterion, avatar }], profile } — grants is empty only
// when nothing new fired. Issue #179 — if the prize pool is already exhausted
// when a criterion fires, we still push a grant (avatar: null, exhausted:
// true) so the student gets an acknowledgement instead of the moment
// silently doing nothing; the UI (AvatarUnlockMoment/Toast) renders a
// dedicated "collection complete" message for these.
async function runAvatarUnlockEngine(stats, profile) {
  const prevFired = await storageGet(AVATAR_UNLOCK_KEY, false) || [];
  const prevFiredSet = new Set(prevFired);
  const newlyMet = AVATAR_UNLOCK_CRITERIA.filter(c => !prevFiredSet.has(c.id) && c.check(stats));

  if (newlyMet.length === 0) return { grants: [], profile };

  let currentProfile = profile;
  const grants = [];
  for (const criterion of newlyMet) {
    const result = await grantRandomPrizeAvatar(currentProfile);
    if (result) {
      currentProfile = result.profile;
      grants.push({ criterion, avatar: result.avatar });
    } else {
      // Pool exhausted — still acknowledge the moment (issue #179).
      grants.push({ criterion, avatar: null, exhausted: true });
    }
    // Mark fired either way — the criterion doesn't get another attempt
    // once its condition has been met.
  }
  const mergedFired = [...new Set([...prevFired, ...newlyMet.map(c => c.id)])];
  await storageSet(AVATAR_UNLOCK_KEY, mergedFired, false);

  return { grants, profile: currentProfile };
}

// ---------------------------------------------------------------------------
// Issue #165 — Phase 5 avatar unlock: passing a level's proficiency exam for
// the FIRST time draws 2 avatars from the prize pool (grantRandomPrizeAvatar
// called twice), same mechanic as the Phase 1-4 criteria above (#162/#166)
// but tied to level completion instead of streak/mastery/Sunday Test
// milestones. LEVEL_COMPLETE_AVATAR_KEY tracks which levels have already
// granted their pair so a level never re-fires even across retakes (a
// student can pass the same level's exam again later — e.g. after a Reset
// Access — without drawing a second pair).
// ---------------------------------------------------------------------------
const LEVEL_COMPLETE_AVATAR_KEY = "level-complete-avatar-grants"; // personal: array of levels already granted (e.g. ["Pre-A1", "A1"])

async function runLevelCompleteAvatarEngine(level, profile) {
  const granted = await storageGet(LEVEL_COMPLETE_AVATAR_KEY, false) || [];
  if (!level || granted.includes(level)) return { grants: [], profile };

  let currentProfile = profile;
  const grants = [];
  for (let i = 0; i < 2; i++) {
    const result = await grantRandomPrizeAvatar(currentProfile);
    const criterion = { id: `level_complete_${level}_${i + 1}`, title: "Level Complete", desc: `Passed the ${level} proficiency exam` };
    if (result) {
      currentProfile = result.profile;
      grants.push({ criterion, avatar: result.avatar });
    } else {
      // Pool exhausted — acknowledge once (same UX as #179) and stop trying the 2nd draw.
      grants.push({ criterion, avatar: null, exhausted: true });
      break;
    }
  }
  await storageSet(LEVEL_COMPLETE_AVATAR_KEY, [...granted, level], false);
  return { grants, profile: currentProfile };
}

// ---------------------------------------------------------------------------
// Issue #181 — "Gatinho do Mês" monthly grant engine.
// Gate 1 (mandatory): highest streak reached this month >= 14.
// Gate 2 (sorteado): this month's single MONTHLY_CHALLENGE_POOL criterion.
// Grants at most once per month (MONTHLY_CAT_UNLOCK_KEY), and does nothing
// if no art/catalog entry exists yet for the current month, or if the
// student already owns that month's cat (e.g. via a teacher gift, #176) —
// in the gift case it just marks the month as settled so this never
// re-checks every load.
// ---------------------------------------------------------------------------
const MONTHLY_CAT_UNLOCK_KEY = "monthly-cat-unlocked"; // personal: array of monthKeys already granted/settled

async function runMonthlyCatEngine(profile) {
  const monthKey   = getMonthKey();
  const catAvatar  = getMonthlyCatAvatar(monthKey);
  if (!catAvatar) return { grant: null, profile }; // no monthly cat shipped yet for this month

  const settled = await storageGet(MONTHLY_CAT_UNLOCK_KEY, false) || [];
  if (settled.includes(monthKey)) return { grant: null, profile };

  const owned = new Set(profile.unlockedAvatars || []);
  if (owned.has(catAvatar.id)) {
    // Already has it (teacher gift beat the challenge to it) — settle silently.
    await storageSet(MONTHLY_CAT_UNLOCK_KEY, [...settled, monthKey], false);
    return { grant: null, profile };
  }

  const monthBest = await storageGet(MONTH_STREAK_BEST_KEY(monthKey), false) || 0;
  if (monthBest < getMonthStreakGate(monthKey)) return { grant: null, profile };

  const challenges = getMonthChallenges(monthKey); // #863 — up to 3
  const [weeklyStats, logStats] = await Promise.all([
    computeMonthWeeklyStats(monthKey),
    computeMonthlyLogStats(monthKey),
  ]);
  const monthStats = { ...weeklyStats, ...logStats };
  if (!challenges.every(c => c.check(monthStats))) return { grant: null, profile };
  const challenge = challenges[0]; // used for grant description below

  const updatedProfile = { ...profile, unlockedAvatars: [...(profile.unlockedAvatars || []), catAvatar.id] };
  await storageSet(KEYS.profile, updatedProfile, false);
  await storageSet(MONTHLY_CAT_UNLOCK_KEY, [...settled, monthKey], false);
  await mirrorUnlockedAvatarsToRoster(profile.username, updatedProfile.unlockedAvatars, profile); // Issue #176

  // Issue #233 — also grant a free Rare gacha ticket alongside the Cat of
  // the Month. Direct grant (bypasses the paid buyGachaTicket() flow).
  const ticketsBefore = await getGachaTickets();
  await storageSet(GACHA_TICKETS_KEY, { ...ticketsBefore, rare: (ticketsBefore.rare || 0) + 1 }, false);
  { const _u = getCurrentUsername(); if (_u) mirrorStudentWallet(_u).catch(() => {}); }

  return {
    grant: {
      criterion: { id: `monthly_cat_${monthKey}`, title: "Cat of the Month", desc: `${challenges.map(c => c.desc).join(" · ")} + ${getMonthStreakGate(monthKey)}-day streak this month` },
      avatar: catAvatar,
      bonusTicket: "rare",
    },
    profile: updatedProfile,
  };
}

// ---------------------------------------------------------------------------
// Issue #176 — Teacher gift (Store-exclusive or Monthly Cat avatar, no coins
// spent). Same client-side/no-RPC philosophy as Class Codes: the teacher
// only writes a shared record, the student self-claims it on their own next
// load/poll (see claimPendingAvatarGift, wired into the same polling effect
// that already re-checks enabledClassCodes).
// ---------------------------------------------------------------------------
const AVATAR_GIFT_PREFIX        = "avatar-gift:";        // shared: avatar-gift:<username> — the ONE pending/last gift = { avatarId, claimedAt }
const AVATAR_GIFT_BUDGET_PREFIX = "avatar-gift-budget:"; // shared: avatar-gift-budget:<username> = { lastGiftLevel } — tracks the "1 per level" budget, Store+Monthly only

// Avatars that consume the "1 gift per level" budget — the Gacha System pool
// is already freely obtainable via the random draw, so gifting one there is
// just a "luck shortcut" and doesn't spend the rarer Store/Monthly budget.
function giftConsumesBudget(avatar) {
  return !!(avatar.shopExclusive || avatar.monthlyExclusive);
}

// Teacher-side: writes the pending gift + (if budgeted) bumps the level lock.
// Caller (AvatarGiftModal) is responsible for only calling this when the
// button isn't disabled (student doesn't already own it / budget available).
async function sendAvatarGift(student, avatar) {
  if (giftConsumesBudget(avatar)) {
    await storageSet(`${AVATAR_GIFT_BUDGET_PREFIX}${student.username}`, { lastGiftLevel: student.level || "Pre-A1" }, true);
  }
  await storageSet(`${AVATAR_GIFT_PREFIX}${student.username}`, { avatarId: avatar.id, claimedAt: null }, true);
}

// Reads whether this student's "1 gift per level" budget is already spent
// for their CURRENT level (used by the modal to disable Store/Monthly
// buttons — Gacha System gifts are never budget-gated).
async function getAvatarGiftBudgetUsed(student) {
  const budget = await storageGet(`${AVATAR_GIFT_BUDGET_PREFIX}${student.username}`, true);
  return !!budget && budget.lastGiftLevel === (student.level || "Pre-A1");
}

// Student-side: checks for a pending gift and, if any, merges it into
// unlockedAvatars, mirrors the roster, and returns a grant shaped exactly
// like runAvatarUnlockEngine's/runMonthlyCatEngine's — reuses the same
// AvatarUnlockMoment reveal UI, gacha animation included.
async function claimPendingAvatarGift(profile) {
  const key = `${AVATAR_GIFT_PREFIX}${profile.username}`;
  const gift = await storageGet(key, true);
  if (!gift || gift.claimedAt) return { grant: null, profile };

  const owned = new Set(profile.unlockedAvatars || []);
  if (owned.has(gift.avatarId)) {
    // Already owns it some other way (e.g. won the monthly challenge before
    // claiming the gift) — settle the record so it stops looking pending.
    await storageSet(key, { ...gift, claimedAt: Date.now() }, true);
    return { grant: null, profile };
  }

  const avatar = getAvatarById(gift.avatarId);
  const updatedProfile = { ...profile, unlockedAvatars: [...(profile.unlockedAvatars || []), gift.avatarId] };
  await storageSet(KEYS.profile, updatedProfile, false);
  await storageSet(key, { ...gift, claimedAt: Date.now() }, true);
  await mirrorUnlockedAvatarsToRoster(profile.username, updatedProfile.unlockedAvatars, profile);

  return {
    grant: {
      criterion: { id: `avatar_gift_${gift.avatarId}_${Date.now()}`, title: "Gift from your teacher!", desc: `Your teacher gave you ${avatar.name} 🎁` },
      avatar,
    },
    profile: updatedProfile,
  };
}

// ---------------------------------------------------------------------------
// Issue #212 — Teacher gift of Meowtongs (coins), same architecture as the
// #176 avatar gift above: teacher can't write directly into the student's
// personal_kv (RLS), so it writes a shared pending record instead and the
// student self-claims it on their own next load/poll.
// ---------------------------------------------------------------------------
const COIN_GIFT_PREFIX   = "coin-gift:";   // shared: coin-gift:<username>   — { amount, grantedAt, claimedAt }
const TICKET_GIFT_PREFIX = "ticket-gift:"; // shared: ticket-gift:<username> — { kind, amount, grantedAt, claimedAt }

// Teacher-side: writes the pending coin gift. Caller (CoinGiftModal) picks
// the amount (quick-pick or custom input).
async function sendCoinGift(student, amount) {
  await storageSet(`${COIN_GIFT_PREFIX}${student.username}`, { amount, grantedAt: Date.now(), claimedAt: null }, true);
}

// Student-side: checks for a pending coin gift and, if any, credits it into
// COINS_KEY and marks it claimed. Returns a grant shaped for the existing
// coins celebration ({ events, total }), same shape used everywhere else
// coins are earned (practice/Sunday Test/streak).
async function claimPendingCoinGift(profile) {
  const key = `${COIN_GIFT_PREFIX}${profile.username}`;
  const gift = await storageGet(key, true);
  if (!gift || gift.claimedAt || !gift.amount) return null;

  await storageSet(key, { ...gift, claimedAt: Date.now() }, true);
  const newCoins = await creditCoins(gift.amount, "Teacher gift");

  return {
    grant: { events: [{ label: "Gift from your teacher! 🎁", amount: gift.amount }], total: gift.amount },
    newCoins,
  };
}

// Teacher-side: writes a pending ticket gift (kind = "rare" | "epic" | "banner").
async function sendTicketGift(student, kind, amount) {
  await storageSet(`${TICKET_GIFT_PREFIX}${student.username}`, { kind, amount, grantedAt: Date.now(), claimedAt: null }, true);
}

// Student-side: claims a pending ticket gift and credits it into GACHA_TICKETS_KEY.
// Called at app init alongside claimPendingCoinGift.
async function claimPendingTicketGift(profile) {
  const key = `${TICKET_GIFT_PREFIX}${profile.username}`;
  const gift = await storageGet(key, true);
  if (!gift || gift.claimedAt || !gift.amount || !gift.kind) return null;

  await storageSet(key, { ...gift, claimedAt: Date.now() }, true);

  // Dawn tickets live in a separate key (HEARTHBOUND_TICKETS_KEY, a plain
  // number) — not inside GACHA_TICKETS_KEY's { rare, epic, banner } object.
  if (gift.kind === "dawn") {
    const currentDawn = (await storageGet(HEARTHBOUND_TICKETS_KEY, false)) || 0;
    const newDawn = currentDawn + gift.amount;
    await storageSet(HEARTHBOUND_TICKETS_KEY, newDawn, false);
    return { kind: gift.kind, amount: gift.amount, newDawn };
  }

  const tickets = await getGachaTickets();
  const updated = { ...tickets, [gift.kind]: (tickets[gift.kind] || 0) + gift.amount };
  await storageSet(GACHA_TICKETS_KEY, updated, false);

  return { kind: gift.kind, amount: gift.amount, newTickets: updated };
}


function newId() {
  return `w_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
}

// ---------------------------------------------------------------------------
// Practice Mode — storage keys & progress helpers
// ---------------------------------------------------------------------------
const P_KEY    = (id)   => `p:${id}`;          // per-word user progress (personal)
const L_KEY    = (date) => `l:${date}`;         // daily lesson (personal)
const STREAK_KEY   = "streak";                     // streak (personal)
// Issue #322 — which Berserk Mode tiers this student has ever cleared with a
// perfect run, e.g. { easy: true, medium: true }. Personal scope, same
// pattern as STREAK_KEY.
const BERSERK_STARS_KEY = "berserk-stars";
// Issue #324 — total Berserk attempts ever started (any tier, any outcome),
// feeds the "Going Berserk" achievement (berserkAttempts >= 1). Personal.
const BERSERK_ATTEMPTS_KEY = "berserk-attempts";
const ST_KEY       = (date) => `st:${date}`;        // Sunday Test session (personal)
const EX_KEY       = (date) => `ex:${date}`;        // Issue #43 — Exam session, in-progress (personal)
const EXAM_HISTORY_KEY          = "exam-history";            // Issue #43 — [{ level, attemptNumber, passed, pct, date }] (personal)
const PENDING_STAGE_ADVANCE_KEY = "pending-stage-advance";   // #848 — { fromCode, nextCode } set when student completes last node of a stage

// ---------------------------------------------------------------------------
// Sunday Test — word selection logic
// ---------------------------------------------------------------------------
function isSunday(date = new Date()) {
  return date.getDay() === 0;
}

// Returns Mon–Sat date strings for the week ending on the given Sunday
function weekRangeDates(sunday = new Date()) {
  const dates = [];
  for (let i = 6; i >= 1; i--) {
    const d = new Date(sunday);
    d.setDate(d.getDate() - i);
    dates.push(`${d.getFullYear()}-${pad2(d.getMonth()+1)}-${pad2(d.getDate())}`);
  }
  return dates; // [Monday … Saturday]
}

function buildSundayLesson(words, progMap, level) {
  const weekDates = new Set(weekRangeDates());

  // Words the user interacted with (any result) during Mon–Sat this week
  const seenThisWeek = words.filter(w => {
    const p = progMap[w.id];
    return p && p.lastDate && weekDates.has(p.lastDate);
  });

  if (seenThisWeek.length === 0) return null;

  // Sort by priority quadrant (same logic as Practice Mode)
  const sorted = [...seenThisWeek].sort(
    (a, b) => prioScore(b, progMap[b.id] || mkProg()) - prioScore(a, progMap[a.id] || mkProg())
  );

  const final = sorted.slice(0, 50);
  const ids = final.map(w => w.id);
  // Issue #261 — filter the "R" (EN->TH recognition) slots down to words
  // the student has actually mastered (SRS Mastery +3); anything else in
  // the mix falls back to a random other type.
  const exercises = enforceRecognitionEligibility(ids, buildExerciseAssignments(final.length, detectSTT()), progMap);

  return {
    ids,
    exercises, // mix engine: stable per session (#101: include "D" when STT available; #261: "R" gated by mastery)
    results:   {},
    completed: false,
    date:      todayStr(),
    // Issue #300 — the student's level AT THE TIME of this Sunday Test.
    // Without this, "2 consecutive Sunday Tests" for the exam retry gate
    // could accidentally count a test taken at a previous level (before the
    // last level-up) as if it were done at the current one.
    level:     level || "Pre-A1",
  };
}

function mkProg() {
  // dontRecallCount (#333) — incremental lifetime counter of "ไม่รู้" (dont_recall)
  // answers, separate from lastResult/lastErrType which only ever hold the
  // MOST RECENT outcome. Only Practice Mode's recordResult() increments this
  // (see there for why Sunday Test/Exam wrong answers don't touch it).
  // masteredAt (#338) — set once, the first time srsInterval crosses the
  // mastery threshold (14, see isWordMastered). Distinct from lastDate,
  // which is overwritten on every touch (including reviews long after
  // mastery) and therefore useless for "words newly mastered this week".
  return { count: 0, srsInterval: 1, streak: 0, lastErrType: null, lastDate: null, lastResult: null, pronScores: [], dontRecallCount: 0, masteredAt: null };
}

// ---------------------------------------------------------------------------
// Issue #43 — Proficiency exam engine (Phase 11.3)
// Separate from daily Practice/Sunday Test: covers ALL vocabulary of the
// student's current level (not just words touched this week), weighted
// scoring by exercise difficulty, and per-level attempt history so #45 can
// tell a first attempt from a retake.
// ---------------------------------------------------------------------------

// Exam word pool = what the teacher has actually released to this student
// (getVisibleWords) intersected with the student's current level. Deliberately
// NOT buildSundayLesson's seenThisWeek filter — an exam has to be able to
// cover words the student never practiced, not just this week's activity.
const EXAM_MAX_WORDS = 40;

function buildExamLesson(words, profile, enabledClassCodes, progMap) {
  const level = profile?.level || "Pre-A1";
  // Issue #263 — the exam pool covers the WHOLE level's vocabulary (not just
  // this week's like Sunday Test), so a word can easily be exam-eligible
  // content-wise while never having been practiced enough to be mastered.
  // enforceRecognitionEligibility (same helper as Sunday Test, #261) still
  // gates "R" down to mastered words specifically — the exam pool itself is
  // unaffected, only which exercise TYPE a given word gets.
  const pool  = getVisibleWords(words, profile, enabledClassCodes).filter(w => (w.level || "Pre-A1") === level);
  if (pool.length === 0) return null;

  const final = shuffleArr(pool).slice(0, EXAM_MAX_WORDS);
  const ids = final.map(w => w.id);
  const exercises = enforceRecognitionEligibility(ids, buildExerciseAssignments(final.length, detectSTT()), progMap || {});

  return {
    ids,
    exercises,
    results:   {},
    completed: false,
    level,
    date:      todayStr(),
  };
}

// Weighted by how much recall (vs. recognition) each exercise type demands —
// a plain multiple-choice guess (C/A/E) shouldn't count the same as typing
// the word from memory (W). Numbers are relative weights, not percentages.
// R (recognition) is pure multiple-choice like C/A/E, and it's only ever
// assigned to already-mastered words (enforceRecognitionEligibility) — same
// weight tier as those, not the higher-effort recall types.
const EXAM_TYPE_WEIGHT = { C: 1, A: 1, E: 1, R: 1, T: 1.3, S: 1.3, D: 1.3, W: 1.6 };

function computeExamOutcome(finalLesson, examThreshold) {
  const idIndex = new Map(finalLesson.ids.map((id, i) => [id, i]));
  let weightedTotal = 0;
  let weightedCorrect = 0;

  finalLesson.ids.forEach((id) => {
    const idx    = idIndex.get(id);
    const exType = finalLesson.exercises[idx]?.type;
    const weight = EXAM_TYPE_WEIGHT[exType] ?? 1;
    weightedTotal += weight;
    const result = finalLesson.results[id];
    if (result?.correct) weightedCorrect += weight;
  });

  const pct    = weightedTotal ? Math.round((weightedCorrect / weightedTotal) * 100) : 0;
  const passed = pct >= (examThreshold ?? 75); // 75% fallback if the teacher never configured a threshold for this level

  return { pct, passed, weightedTotal, weightedCorrect };
}

// Persists one row per attempt (never overwrites) — #45 needs the full
// per-level history to tell a first pass from a retake ("Mr. Smartpants"
// vs. "ไม่เป็นไรลูก" achievements).
async function recordExamAttempt(level, passed, pct) {
  const history = (await storageGet(EXAM_HISTORY_KEY, false)) || [];
  const attemptNumber = history.filter(a => a.level === level).length + 1;
  const entry = { level, attemptNumber, passed, pct, date: todayStr() };
  await storageSet(EXAM_HISTORY_KEY, [...history, entry], false);
  return entry;
}

// ---------------------------------------------------------------------------
// Issue #300 (sub-issue 3/3 of #45) — exam retry gate.
// Deliberately has NO separate persisted "examFailedAt" flag: the gate state
// is fully DERIVED from examHistory + stHistory every time, which turns out
// to already give exactly the right lifecycle for free:
//   - Never attempted the level's exam, or the most recent attempt passed
//     -> not gated at all (normal mastery-threshold exam access applies).
//   - Most recent attempt for the CURRENT level failed -> gated. Unlocks
//     once the 2 most recent Sunday Tests completed AFTER that failure, at
//     that same level (via the `level` field on each stHistory entry, see
//     buildSundayLesson above), both scored > 75%.
//   - Once the student passes (first try or after unlocking a retake),
//     profile.level advances (#298) — examHistory/stHistory filtered by the
//     NEW current level have no failed attempt yet, so the gate is "clear"
//     with no explicit reset step needed.
// ---------------------------------------------------------------------------
function sundayTestPct(session) {
  const entries = Object.entries(session?.results || {});
  const total   = session?.ids?.length || 0;
  const correct = entries.filter(([, r]) => r.correct).length;
  return total ? Math.round((correct / total) * 100) : 0;
}

function getExamRetryGate(examHistory, stHistory, level) {
  const attempts = (examHistory || []).filter(e => e.level === level).sort((a, b) => a.attemptNumber - b.attemptNumber);
  const last = attempts[attempts.length - 1];
  if (!last || last.passed) return { gated: false, unlocked: true, doneSinceFailure: 0 };

  const since = (stHistory || [])
    .filter(s => s.level === level && s.date > last.date)
    .sort((a, b) => a.date.localeCompare(b.date));

  // "Unlocked" = at any point since the failure, 2 CONSECUTIVE Sunday Tests
  // (at this level) both scored > 75% — once that pair exists, stays true
  // even if a later, lower-scoring Sunday Test happens while still waiting
  // to actually retake the exam (a bad practice round afterward shouldn't
  // revoke an already-earned retake).
  let streak = 0, unlocked = false;
  for (const s of since) {
    if (sundayTestPct(s) > 75) { streak++; if (streak >= 2) unlocked = true; }
    else streak = 0;
  }
  return { gated: true, unlocked, doneSinceFailure: since.length, failedAt: last.date };
}

// ---------------------------------------------------------------------------
// Issue #44 — AI-generated personalized exam feedback (Phase 11.4)
// Reuses callAIWithFallback (Gemini -> Groq -> Cloudflare -> server proxy),
// the same entry point already used by enrichWords — never calls a single
// provider directly. Always generated regardless of pass/fail.
// ---------------------------------------------------------------------------
const EXAM_FEEDBACK_KEY = "exam-feedback"; // [{ level, attemptNumber, date, pct, passed, summary, strengths[], weaknesses[], tips[], provider }] (personal)

const EXAM_FEEDBACK_TYPE_LABELS = {
  C: "Multiple choice (Thai → English)", A: "Listening", T: "Build the word (tiles)",
  S: "Spelling", W: "Typing from memory", E: "Image match", D: "Pronunciation",
  R: "Recognition (English → Thai)",
};

// Pure aggregation, no AI/network — kept separate so it's trivially testable
// and reusable if the progress screen ever wants the same breakdown.
function buildExamFeedbackContext(finalLesson, wordMap, progMap, words) {
  const entries = Object.entries(finalLesson.results || {});

  const byType = {};
  const byCategory = {};
  const missedWords = [];

  entries.forEach(([id, r]) => {
    const t = r.exerciseType;
    if (!byType[t]) byType[t] = { correct: 0, total: 0 };
    byType[t].total++;
    if (r.correct) byType[t].correct++;

    const w = wordMap[id];
    if (!w) return;
    const cat = w.category || "uncategorized";
    if (!byCategory[cat]) byCategory[cat] = { correct: 0, total: 0 };
    byCategory[cat].total++;
    if (r.correct) byCategory[cat].correct++;
    if (!r.correct) missedWords.push({ thai: w.thai, english: w.english, category: cat, exerciseType: t });
  });

  // Phase 12 data (comment on issue #44, 2026-07-04) — global pronunciation
  // weak spots from daily practice, independent of this specific exam.
  const pronStats = computePronStats(progMap, words).slice(0, 5);

  return { byType, byCategory, missedWords, pronStats };
}

async function generateExamFeedback(finalLesson, outcome, level, wordMap, progMap, words, aiConfig) {
  const ctx = buildExamFeedbackContext(finalLesson, wordMap, progMap, words);

  const typeLines = Object.entries(ctx.byType)
    .map(([t, d]) => `- ${EXAM_FEEDBACK_TYPE_LABELS[t] || t}: ${d.correct}/${d.total} correct (${Math.round((d.correct / d.total) * 100)}%)`)
    .join("\n") || "(no data)";
  const catLines = Object.entries(ctx.byCategory)
    .map(([c, d]) => `- ${c}: ${d.correct}/${d.total} correct (${Math.round((d.correct / d.total) * 100)}%)`)
    .join("\n") || "(no data)";
  const missedLines = ctx.missedWords.slice(0, 15)
    .map(m => `- ${m.thai} (${m.english}) — category: ${m.category}, exercise: ${EXAM_FEEDBACK_TYPE_LABELS[m.exerciseType] || m.exerciseType}`)
    .join("\n") || "(none — perfect score!)";
  const pronLines = ctx.pronStats.length
    ? ctx.pronStats.map(p => `- ${p.word.thai} (${p.word.english}): ${p.avgScore}% avg over ${p.attempts} attempts`).join("\n")
    : "(no pronunciation practice data yet)";

  const system =
    `You are a supportive Thai-language teacher's assistant writing a short personalized feedback report for a ` +
    `student who just finished their ${level} proficiency exam. Score: ${outcome.pct}% (${outcome.passed ? "PASSED" : "did not pass"} — threshold-based).\n\n` +
    `Use ONLY the data below, which comes from this exact student's actual results — never give generic, made-up ` +
    `advice. Always write in plain, encouraging, simple English (the reader is a Thai student learning English), addressing them ` +
    `directly as "you".\n\n` +
    `Accuracy by exercise type:\n${typeLines}\n\n` +
    `Accuracy by vocabulary category:\n${catLines}\n\n` +
    `Words missed in this exam (up to 15):\n${missedLines}\n\n` +
    `Student's weakest words for pronunciation overall (separate from this exam, from daily practice history):\n${pronLines}\n\n` +
    `Respond ONLY with a valid JSON object, no markdown fences, no preamble, in this exact shape:\n` +
    `{"summary":"one encouraging sentence about the overall result","strengths":["short bullet","short bullet"],` +
    `"weaknesses":["short bullet","short bullet"],"tips":["specific actionable practice suggestion","..."]}\n\n` +
    `Rules:\n` +
    `1. 2-4 bullets per array, each one short (under ~110 characters).\n` +
    `2. Strengths/weaknesses must reference the ACTUAL exercise types, categories or specific words from the data ` +
    `above — never invent categories or words that weren't listed.\n` +
    `3. Tips must be concrete and actionable, naming the specific exercise type/category/word to practice (e.g. ` +
    `"Practice the 🎤 Pronunciation exercises for น้ำแข็ง and ตาราง" not "practice more").\n` +
    `4. Always fill every field, even on a perfect score — strengths can highlight what stayed strong, tips can ` +
    `suggest moving on to a new category or the next level.`;

  const { text, provider } = await callAIWithFallback(system, "Generate the feedback JSON now, based only on the data given above.", aiConfig, 700);
  const parsed = extractJsonObject(text);
  if (!parsed) throw new Error("AI response was not valid JSON");

  return {
    level, date: todayStr(), pct: outcome.pct, passed: outcome.passed,
    summary: typeof parsed.summary === "string" ? parsed.summary : "",
    strengths: Array.isArray(parsed.strengths) ? parsed.strengths.filter(s => typeof s === "string").slice(0, 6) : [],
    weaknesses: Array.isArray(parsed.weaknesses) ? parsed.weaknesses.filter(s => typeof s === "string").slice(0, 6) : [],
    tips: Array.isArray(parsed.tips) ? parsed.tips.filter(s => typeof s === "string").slice(0, 6) : [],
    provider,
  };
}

// Persists one row per attempt (never overwrites), mirroring recordExamAttempt.
async function recordExamFeedback(feedback) {
  const history = (await storageGet(EXAM_FEEDBACK_KEY, false)) || [];
  const attemptNumber = history.filter(f => f.level === feedback.level).length + 1;
  const entry = { ...feedback, attemptNumber };
  await storageSet(EXAM_FEEDBACK_KEY, [...history, entry], false);
  return entry;
}

// Date helpers
function pad2(n) { return String(n).padStart(2, "0"); }
function todayStr() {
  const d = new Date();
  return `${d.getFullYear()}-${pad2(d.getMonth()+1)}-${pad2(d.getDate())}`;
}
function yesterdayStr() {
  const d = new Date(); d.setDate(d.getDate()-1);
  return `${d.getFullYear()}-${pad2(d.getMonth()+1)}-${pad2(d.getDate())}`;
}
// #700 — ISO week key "YYYY-Www" for weekly_starlight_ticket
function isoWeekKey(now = new Date()) {
  const d = new Date(Date.UTC(now.getFullYear(), now.getMonth(), now.getDate()));
  d.setUTCDate(d.getUTCDate() + 4 - (d.getUTCDay() || 7));
  const year = d.getUTCFullYear();
  const week = Math.ceil(((d - new Date(Date.UTC(year, 0, 1))) / 86400000 + 1) / 7);
  return `${year}-W${String(week).padStart(2, "0")}`;
}

// ---------------------------------------------------------------------------
// Issue #53 — Word bank export (CSV/JSON) for teacher backup
// ---------------------------------------------------------------------------
function downloadBlob(filename, content, mime) {
  const blob = new Blob([content], { type: mime });
  const url  = URL.createObjectURL(blob);
  const a    = document.createElement("a");
  a.href = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

const WORD_EXPORT_COLUMNS = ["thai", "romanization", "english", "pos", "category", "classCode", "emoji", "verified", "addedAt"];

function wordsToCSV(words) {
  const escape = (v) => {
    const s = v === undefined || v === null ? "" : String(v);
    return /[",\n]/.test(s) ? '"' + s.replace(/"/g, '""') + '"' : s;
  };
  const header = WORD_EXPORT_COLUMNS.join(",");
  const rows = words.map((w) => WORD_EXPORT_COLUMNS.map((c) => escape(w[c])).join(","));
  return [header, ...rows].join("\n");
}

function exportWordsAsCSV(words) {
  downloadBlob(`chaachaa-angkrit-word-bank-${todayStr()}.csv`, wordsToCSV(words), "text/csv;charset=utf-8;");
}

function exportWordsAsJSON(words) {
  downloadBlob(`chaachaa-angkrit-word-bank-${todayStr()}.json`, JSON.stringify(words, null, 2), "application/json");
}
function daysAgo(dateStr) {
  if (!dateStr) return 9999;
  return Math.max(0, Math.round((Date.now() - new Date(dateStr)) / 86400000));
}
function tsToDate(ts) {
  const d = new Date(ts);
  return `${d.getFullYear()}-${pad2(d.getMonth()+1)}-${pad2(d.getDate())}`;
}

// SRS intervals: 1 → 3 → 7 → 14 → 30
const SRS_STEPS = [1, 3, 7, 14, 30];
function nextSRS(cur) {
  const i = SRS_STEPS.indexOf(cur);
  return i >= 0 && i < SRS_STEPS.length - 1 ? SRS_STEPS[i + 1] : 30;
}

// Issue #338 — shared by PracticeSession.recordResult and SundaySession.handleNext
// (the two places a "got_it"/correct answer bumps srsInterval). Returns the
// masteredAt value to persist: set to today only on the FIRST crossing of the
// 14-day mastery threshold, carried over unchanged otherwise. If a word later
// forgets (dont_recall resets srsInterval to 1) and gets re-mastered, this
// correctly updates again — a genuine re-mastery is a real event worth
// reporting, not a bug.
function withMasteredAt(prevSrsInterval, newSrsInterval, prevMasteredAt) {
  if (prevSrsInterval < 14 && newSrsInterval >= 14) return todayStr();
  return prevMasteredAt || null;
}

// Issue #261 (Phase 17) — "SRS Mastery +3" == srsInterval >= 14 days, the
// same threshold the achievements system already calls "wordsMastered"
// (SRS_STEPS.indexOf(14) === 3). Named helper so the EN->TH recognition
// exercise's eligibility filter reads the same everywhere it's checked,
// instead of re-deriving the comparison inline.
function isWordMastered(progMap, wordId) {
  const p = progMap[wordId];
  return !!p && p.srsInterval >= 14;
}

// Issue #412 (Phase 10) — words eligible for word-writing practice:
// must be SRS-mastered (≥14d) AND have at least one character with stroke data.
// Sorted by practisable-char count desc, then srsInterval desc.
function getWritableWords(visibleWords, progMap) {
  return visibleWords
    .filter(w => {
      if (!isWordMastered(progMap, w.id)) return false;
      return [...(w.english || "")].some(ch => ALL_THAI_STROKES[ch]);
    })
    .map(w => ({
      w,
      practisableCount: [...(w.english || "")].filter(ch => ALL_THAI_STROKES[ch]).length,
      srsInterval: progMap[w.id]?.srsInterval ?? 1,
    }))
    .sort((a, b) => b.practisableCount - a.practisableCount || b.srsInterval - a.srsInterval)
    .map(({ w }) => w);
}

// Priority score — higher = more urgent (appears first in lesson fill)
function prioScore(word, prog) {
  const lastDate = prog.lastDate || tsToDate(word.addedAt);
  const age      = daysAgo(lastDate);
  const errBonus = { both: 30, reading: 20, meaning: 10 }[prog.lastErrType] || 0;
  // SRS handles review priority via notDuePenalty (srsInterval-based).
  // The old streakPenalty (streak >= 6 ? -100) was removed — it was redundant
  // with notDuePenalty and created an arbitrary cutoff that hid mastered
  // words from the Sunday Test. See Issue #67.
  const notDuePenalty = prog.lastDate && age < prog.srsInterval
    ? (prog.srsInterval - age) * 5 : 0;
  return age * 10 + errBonus - notDuePenalty;
}

function shuffleArr(arr) {
  const a = [...arr];
  for (let i = a.length-1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i+1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

async function loadAllProgress(words) {
  const entries = await Promise.all(words.map(async w => {
    const p = await storageGet(P_KEY(w.id), false);
    return [w.id, p || mkProg()];
  }));
  return Object.fromEntries(entries);
}

// Issue #264 (Phase 17.3) — how often an already-mastered word gets a
// Recognition ("R") card instead of the normal flip card in Practice Mode.
// Sunday Test/Exam give every type (incl. R) an equal ~1/7 share via
// buildExerciseAssignments, but Practice Mode's core loop is the primary
// recall/SRS drill (flip is the default), so R is deliberately a lower-
// frequency "occasional check" here rather than an equal rotation slot.
// Only ever considered for words that pass isWordMastered() in the first
// place — this rate is on TOP of that gate, not instead of it.
const PRACTICE_RECOGNITION_RATE = 0.25;

// Issue #52 / #52.1 — Berserk Mode: bonus challenge for students with 100+
// currently unlocked words (getVisibleWords result — confirmed decision:
// "unlocked", not the total app-wide word bank). Three tiers, each a
// separate timed session, mutually exclusive word sets so Medium/Hard never
// repeat a word already drilled in a lower tier within the same attempt.
// 20 + 30 + 50 = 100 is exactly the unlock threshold on purpose.
const BERSERK_TIERS = [
  { id: "easy",   stars: 1, label: "Easy",   count: 20, timerSeconds: 12 },
  { id: "medium", stars: 2, label: "Medium", count: 30, timerSeconds: 8  },
  { id: "hard",   stars: 3, label: "Hard",   count: 50, timerSeconds: 5  },
];
const BERSERK_MIN_WORDS = BERSERK_TIERS.reduce((sum, t) => sum + t.count, 0); // 100

function berserkTierById(tierId) {
  return BERSERK_TIERS.find(t => t.id === tierId) || null;
}

// Issue #323 — 3h cooldown per tier after a FAILED (non-100%) attempt.
// Clearing a tier never triggers cooldown (confirmed in #52) — student can
// move to the next tier immediately on a perfect run.
const BERSERK_COOLDOWN_MS = 3 * 60 * 60 * 1000;
function berserkCooldownKey(tierId) {
  return `berserk:cooldown:${tierId}`;
}
// ms remaining on a tier's cooldown, 0 if none/elapsed. `startedAt` is the
// stored timestamp (number) or null/undefined if the tier was never failed.
function berserkCooldownRemaining(startedAt) {
  if (!startedAt) return 0;
  const remaining = BERSERK_COOLDOWN_MS - (Date.now() - startedAt);
  return remaining > 0 ? remaining : 0;
}
function formatBerserkCooldown(ms) {
  const totalMin = Math.ceil(ms / 60000);
  const h = Math.floor(totalMin / 60);
  const m = totalMin % 60;
  if (h > 0) return `${h}h ${m}m left`;
  return `${m}m left`;
}

// Reuses the same priority/SRS ranking as buildLesson (prioScore), pulling
// the `count` most due words that aren't in `excludeIds`. Ties are broken by
// random shuffle so a Berserk run doesn't feel identical every time.
function buildBerserkPool(words, progMap, excludeIds, count) {
  const excludeSet = new Set(excludeIds);
  const candidates = words.filter(w => !excludeSet.has(w.id));
  const sorted = [...candidates].sort(
    (a, b) => prioScore(b, progMap[b.id] || mkProg()) - prioScore(a, progMap[a.id] || mkProg())
  );
  return shuffleArr(sorted.slice(0, count));
}

// Builds a PracticeSession-shaped lesson for one Berserk tier. `excludeIds`
// = ids already drilled in lower tiers within this same attempt, per the
// "mutually exclusive" requirement in #52.
//
// Issue #265 (Phase 17.4) — same per-slot Recognition assignment buildLesson
// uses for regular Practice (#264): gated to isWordMastered() words, then
// thinned by PRACTICE_RECOGNITION_RATE. Reusing Practice's rate/approach
// rather than Sunday Test's ~1/7 equal rotation was a deliberate call —
// Berserk's session mechanic literally IS PracticeSession (flip-card timer
// engine, see BerserkSession below), not SundaySession, so it inherits
// Practice's "occasional check on top of the main drill" framing rather
// than Sunday Test's "equal share of every exercise type" framing. R cards
// still respect each tier's fixed timerSeconds like every other card in the
// pool — no special-casing needed, PracticeSession already treats it as
// just another lesson slot.
function buildBerserkLesson(tierId, words, progMap, excludeIds = []) {
  const tier = berserkTierById(tierId);
  if (!tier) return null;
  const pool = buildBerserkPool(words, progMap, excludeIds, tier.count);
  const exercises = pool.map(w =>
    isWordMastered(progMap, w.id) && Math.random() < PRACTICE_RECOGNITION_RATE
      ? { type: "R" }
      : { type: "flip" }
  );
  return {
    ids: pool.map(w => w.id),
    ymIds: [],
    nvIds: [],
    exercises, // "flip" (default) or "R" (recognition, #265)
    results: {},
    completed: false,
    date: todayStr(),
  };
}

// A tier "clears" only on a perfect run — confirmed decision in #52, no
// partial credit. Empty results (e.g. a 0-word pool) never counts as cleared.
function isBerserkTierCleared(lesson) {
  const results = Object.values(lesson?.results || {});
  if (results.length === 0) return false;
  return results.every(r => r.result === "got_it");
}

// Issue #322 — read-modify-write on BERSERK_STARS_KEY. Follows the standing
// rule from #251/#282: use storageGetSafe and bail out (write nothing) on a
// read failure, rather than risking overwriting real star progress with a
// partial object built from a masked-error fallback.
//
// Issue #56 — stores the clear TIMESTAMP (Date.now()) per tier instead of a
// plain `true`. Every existing truthy-check on this object (!!berserkStars.easy
// etc., all over PracticeModeScreen/ProgressScreen) keeps working unchanged
// since a timestamp number is truthy too — this just adds the ability to
// tell WHEN a tier was cleared, which the weekly report needs.
async function markBerserkTierCleared(tierId) {
  const { value: current, error } = await storageGetSafe(BERSERK_STARS_KEY, false);
  if (error) return null;
  const updated = { ...(current || {}), [tierId]: Date.now() };
  await storageSet(BERSERK_STARS_KEY, updated, false);
  return updated;
}

// Issue #56 — appends one {tier, ts, cleared} entry to this student's shared
// stats row (student-stats:<username>) so the weekly report can compute
// this week's Berserk attempts + success rate. Needs its own read-modify-
// write (same storageGetSafe rule) rather than going through
// updateSharedStats, since this must fire on BOTH the success AND the
// failure path — today only the success path ever touches shared stats.
// Capped to the most recent 50 entries so this row can't grow unbounded
// over months of play; a week's worth of attempts is nowhere near that.
const BERSERK_ATTEMPT_LOG_CAP = 50;
async function appendSharedBerserkAttempt(username, tier, cleared) {
  const key = `${STUDENT_STATS_PREFIX}${username}`;
  const { value: existing, error } = await storageGetSafe(key, true);
  if (error) return;
  const prevLog = Array.isArray(existing?.berserkAttemptLog) ? existing.berserkAttemptLog : [];
  const nextLog = [...prevLog, { tier, ts: Date.now(), cleared }].slice(-BERSERK_ATTEMPT_LOG_CAP);
  await storageSet(key, { ...(existing || { username }), berserkAttemptLog: nextLog }, true);
}

// Issue #56 — mirrors newly-unlocked BERSERK achievements (with their unlock
// timestamp) into the same shared stats row, so the weekly report can list
// which achievements were unlocked THIS WEEK, not just which are unlocked
// overall. Called from handleBerserkUpdate (App-level) right after
// runAchievementEngine returns its newOnes for a berserk-triggered re-check.
async function appendSharedBerserkAchievements(username, newBerserkAchievements) {
  if (!newBerserkAchievements || newBerserkAchievements.length === 0) return;
  const key = `${STUDENT_STATS_PREFIX}${username}`;
  const { value: existing, error } = await storageGetSafe(key, true);
  if (error) return;
  const prevMap = existing?.berserkAchievementUnlocks || {};
  const now = Date.now();
  const nextMap = { ...prevMap };
  newBerserkAchievements.forEach(a => { nextMap[a.id] = now; });
  await storageSet(key, { ...(existing || { username }), berserkAchievementUnlocks: nextMap }, true);
}

// Issue #324 — read-modify-write increment on BERSERK_ATTEMPTS_KEY, same
// storageGetSafe rule as markBerserkTierCleared above.
async function incrementBerserkAttempts() {
  const { value: current, error } = await storageGetSafe(BERSERK_ATTEMPTS_KEY, false);
  if (error) return null;
  const updated = (current || 0) + 1;
  await storageSet(BERSERK_ATTEMPTS_KEY, updated, false);
  return updated;
}

// Issue #52.1 — runs one Berserk tier using the REAL PracticeSession (same
// timer/countdown-to-incorrect mechanic already shipped for regular Practice
// in #18, just with a fixed timerSeconds per tier instead of level-scaled)
// so we don't duplicate the flip-card + timer logic a 2nd time. Berserk
// results never touch srsInterval (confirmed in #52) — same affectsProgress
// guarantee #318 already added to PracticeSession for the Preview Exercises
// tool is reused here as-is.
//
// NOTE: onUpdateLesson must actually update local state (not a no-op) — a
// Berserk lesson has 20-50 cards, so PracticeSession's own isLast/progress
// calculation (derived from the `lesson` PROP's `results`, not from any
// internal card-count state) needs to see the accumulated results after
// every single card, or it will never reach isLast and onComplete will never
// fire. This mirrors exactly what PracticeModeScreen already does in
// production for the real Daily Practice lesson.
function BerserkSession({ tier, words, progMap, profile, excludeIds, allCategories, onComplete }) {
  const tierDef = berserkTierById(tier);
  const [lesson, setLesson] = useState(() => buildBerserkLesson(tier, words, progMap, excludeIds));
  const thaiFont = thaiFontForLevel(profile?.level);

  if (!tierDef || !lesson || lesson.ids.length === 0) {
    return (
      <div className="screen-pad center-content">
        <EmptyState
          title="Not enough words"
          subtitle="You need more unlocked words to attempt this tier."
          image="/mascote-crying.png"
          compact
        />
      </div>
    );
  }

  return (
    <PracticeSession
      lesson={lesson}
      words={words}
      progMap={progMap}
      showRomanization={true}
      thaiFont={thaiFont}
      level={profile?.level}
      timerSeconds={tierDef.timerSeconds}
      sttAllowed={false}
      countdownEffect={{}}
      onUpdateLesson={async (upd) => setLesson(upd)}
      onComplete={async (finalLesson) => {
        const cleared = isBerserkTierCleared(finalLesson);
        await onComplete({ tier, cleared, lesson: finalLesson, usedIds: finalLesson.ids });
      }}
      allCategories={allCategories}
      affectsProgress={false}
    />
  );
}

function buildLesson(words, progMap) {
  const yStr = yesterdayStr();

  // 1. Yesterday's mistakes (mandatory)
  const ymWords = words.filter(w => {
    const p = progMap[w.id] || mkProg();
    return p.lastDate === yStr && p.lastResult === "dont_recall";
  });
  const ymIds = new Set(ymWords.map(w => w.id));

  // 2. New vocabulary (never practiced by this user), min 6
  const nvWords = words
    .filter(w => !ymIds.has(w.id) && (progMap[w.id] || mkProg()).count === 0)
    .sort((a, b) => a.addedAt - b.addedAt)
    .slice(0, 6);
  const nvIds = new Set(nvWords.map(w => w.id));

  // 3. Fill remaining to 30 from priority-sorted rest
  const rest = words
    .filter(w => !ymIds.has(w.id) && !nvIds.has(w.id))
    .sort((a, b) => prioScore(b, progMap[b.id] || mkProg()) - prioScore(a, progMap[a.id] || mkProg()));

  let lesson = [...ymWords, ...nvWords];
  for (const w of rest) {
    if (lesson.length >= 30) break;
    lesson.push(w);
  }

  // Emergency cap at 50 — cut lowest-priority first
  if (lesson.length > 50) {
    lesson = lesson
      .map(w => ({ w, s: prioScore(w, progMap[w.id] || mkProg()) }))
      .sort((a, b) => b.s - a.s)
      .slice(0, 50)
      .map(x => x.w);
  }

  // Shuffle only the "fill" portion; keep YM first, NV second
  const ymList   = lesson.filter(w =>  ymIds.has(w.id));
  const nvList   = lesson.filter(w =>  nvIds.has(w.id) && !ymIds.has(w.id));
  const restList = shuffleArr(lesson.filter(w => !ymIds.has(w.id) && !nvIds.has(w.id)));

  const final = [...ymList, ...nvList, ...restList];
  // Issue #264 — decide up-front (and persist) which slots are Recognition
  // cards, same "stable per session" principle buildSundayLesson/buildExamLesson
  // already use for their exercises array. Gated to mastered words only
  // (isWordMastered), then thinned by PRACTICE_RECOGNITION_RATE.
  const exercises = final.map(w =>
    isWordMastered(progMap, w.id) && Math.random() < PRACTICE_RECOGNITION_RATE
      ? { type: "R" }
      : { type: "flip" }
  );
  return {
    ids:     final.map(w => w.id),
    ymIds:   [...ymIds],
    nvIds:   nvList.map(w => w.id),
    exercises, // Issue #264: per-card type, "flip" (default) or "R" (recognition)
    results: {},          // wordId → { result, errType }
    completed: false,
    date:    todayStr(),
  };
}

// ---------------------------------------------------------------------------
// Sprint 15 — Multi-provider AI with automatic fallback.
// Primary:   Google Gemini 2.5 Flash (best Thai support, free tier)
// Fallback 1: Groq Llama 3.3 70B (OpenAI-compatible API, 30 req/min free)
// Fallback 2: Cloudflare Workers AI Llama 3.3 70B (10k neurons/day free)
// Each provider is only tried if its key is configured. If one fails
// (quota, network, etc.), the next is attempted automatically.
// ---------------------------------------------------------------------------
const GEMINI_KEY_STORAGE    = "ai-api-key";       // backward compat
const GROQ_KEY_STORAGE      = "groq-api-key";
const CF_TOKEN_STORAGE      = "cf-api-token";
const CF_ACCOUNT_STORAGE    = "cf-account-id";

const GEMINI_MODEL           = "gemini-2.5-flash";
const GROQ_MODEL             = "llama-3.3-70b-versatile";
const CF_MODEL               = "@cf/meta/llama-3.3-70b-instruct-fp8-fast";

// ── Provider 1: Google Gemini ──
async function callGeminiAPI(systemPrompt, userMessage, apiKey, maxTokens = 2000) {
  if (!apiKey) throw new Error("NO_KEY");
  const url = `https://generativelanguage.googleapis.com/v1beta/models/${GEMINI_MODEL}:generateContent?key=${apiKey}`;
  const res = await fetch(url, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      systemInstruction: { parts: [{ text: systemPrompt }] },
      contents: [{ role: "user", parts: [{ text: userMessage }] }],
      generationConfig: { temperature: 0.1, maxOutputTokens: maxTokens },
    }),
  });
  if (!res.ok) {
    const err = await res.json().catch(() => ({}));
    throw new Error(`Gemini ${res.status}: ${err?.error?.message || res.statusText}`);
  }
  const data = await res.json();
  return data.candidates?.[0]?.content?.parts?.[0]?.text || "";
}

// ── Provider 2: Groq (OpenAI-compatible) ──
async function callGroqAPI(systemPrompt, userMessage, apiKey, maxTokens = 2000) {
  if (!apiKey) throw new Error("NO_KEY");
  const res = await fetch("https://api.groq.com/openai/v1/chat/completions", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "Authorization": `Bearer ${apiKey}`,
    },
    body: JSON.stringify({
      model: GROQ_MODEL,
      temperature: 0.1,
      max_tokens: maxTokens,
      messages: [
        { role: "system", content: systemPrompt },
        { role: "user", content: userMessage },
      ],
    }),
  });
  if (!res.ok) {
    const err = await res.json().catch(() => ({}));
    throw new Error(`Groq ${res.status}: ${err?.error?.message || res.statusText}`);
  }
  const data = await res.json();
  return data.choices?.[0]?.message?.content || "";
}

// ── Provider 3: Cloudflare Workers AI (OpenAI-compatible) ──
async function callCloudflareAPI(systemPrompt, userMessage, apiToken, accountId, maxTokens = 2000) {
  if (!apiToken || !accountId) throw new Error("NO_KEY");
  const url = `https://api.cloudflare.com/client/v4/accounts/${accountId}/ai/v1/chat/completions`;
  const res = await fetch(url, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "Authorization": `Bearer ${apiToken}`,
    },
    body: JSON.stringify({
      model: CF_MODEL,
      temperature: 0.1,
      max_tokens: maxTokens,
      messages: [
        { role: "system", content: systemPrompt },
        { role: "user", content: userMessage },
      ],
    }),
  });
  if (!res.ok) {
    const err = await res.json().catch(() => ({}));
    const msg = err?.error?.message || err?.errors?.[0]?.message || res.statusText;
    throw new Error(`Cloudflare ${res.status}: ${msg}`);
  }
  const data = await res.json();
  return data.choices?.[0]?.message?.content || "";
}

// ── Server proxy: calls /api/ai-enrich with server-side keys ──
// Used when the teacher hasn't configured personal keys in Settings.
// The server holds GEMINI_API_KEY, GROQ_API_KEY, CLOUDFLARE_* as env vars.
async function callAIServerProxy(systemPrompt, userMessage, maxTokens) {
  const res = await fetch("/api/ai-enrich", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ systemPrompt, userMessage, maxTokens }),
  });
  if (!res.ok) {
    const err = await res.json().catch(() => ({}));
    if (err.error === "NO_SERVER_KEYS") throw new Error("NO_KEY");
    throw new Error(err.message || `Server proxy ${res.status}`);
  }
  const data = await res.json();
  return { text: data.text, provider: data.provider || "Server" };
}

// ── Fallback orchestrator: tries Gemini → Groq → Cloudflare, falls back to
// the server proxy (/api/ai-enrich) when no personal keys are configured ──
// aiConfig = { geminiKey, groqKey, cfToken, cfAccountId }
// Returns { text, provider } on success, throws if all fail.
async function callAIWithFallback(systemPrompt, userMessage, aiConfig, maxTokens) {
  // ── Phase 1: try personal keys (if any are configured) ──
  const hasPersonalKey = aiConfig && (
    aiConfig.geminiKey || aiConfig.groqKey ||
    (aiConfig.cfToken && aiConfig.cfAccountId)
  );

  if (hasPersonalKey) {
    const errors = [];
    const providers = [
      { name: "Gemini", fn: () => callGeminiAPI(systemPrompt, userMessage, aiConfig.geminiKey, maxTokens) },
      { name: "Groq",   fn: () => callGroqAPI(systemPrompt, userMessage, aiConfig.groqKey, maxTokens) },
      { name: "Cloudflare", fn: () => callCloudflareAPI(systemPrompt, userMessage, aiConfig.cfToken, aiConfig.cfAccountId, maxTokens) },
    ];
    for (const p of providers) {
      const hasKey = p.name === "Cloudflare"
        ? !!(aiConfig.cfToken && aiConfig.cfAccountId)
        : !!aiConfig[p.name === "Gemini" ? "geminiKey" : "groqKey"];
      if (!hasKey) continue;
      try {
        const text = await p.fn();
        return { text, provider: p.name };
      } catch (e) {
        errors.push(`${p.name}: ${e.message}`);
      }
    }
    // Personal keys all failed — fall through to server proxy
    if (errors.length > 0) {
      try {
        return await callAIServerProxy(systemPrompt, userMessage, maxTokens);
      } catch (serverErr) {
        if (serverErr.message !== "NO_KEY") errors.push(`Server: ${serverErr.message}`);
        throw new Error(`All AI providers failed — ${errors.join(" | ")}`);
      }
    }
  }

  // ── Phase 2: no personal keys — use server proxy ──
  return await callAIServerProxy(systemPrompt, userMessage, maxTokens);
}

// Gemini usually follows "respond with ONLY JSON" instructions well, but
// extractJsonArray() salvages a JSON array even when the model wraps it in
// explanation text or partial markdown, instead of requiring pure JSON from char 0.
function extractJsonArray(text) {
  const start = text.indexOf('[');
  const end = text.lastIndexOf(']');
  if (start === -1 || end === -1 || end < start) return null;
  try {
    return JSON.parse(text.slice(start, end + 1));
  } catch {
    return null;
  }
}

// Same salvage strategy as extractJsonArray, but for a top-level JSON object
// response (used by generateExamFeedback — issue #44).
function extractJsonObject(text) {
  const start = text.indexOf('{');
  const end = text.lastIndexOf('}');
  if (start === -1 || end === -1 || end < start) return null;
  try {
    return JSON.parse(text.slice(start, end + 1));
  } catch {
    return null;
  }
}

// Given a single Thai word, suggest Paiboon+ romanization, English translation, POS
async function suggestWordDetails(englishWord, aiConfig) {
  const system =
    "You are a English language expert. Given a single English word or short phrase, respond with ONLY a valid JSON object, no markdown fences, no preamble. " +
    'Keys: "romanization" (Paiboon+ system, with tone marks), "english" (short common translation), ' +
    '"pos" (one of: noun, verb, adjective, adverb, pronoun, preposition, conjunction, interjection, particle, classifier, numeral), ' +
    '"emoji" (a single emoji character that best represents the word meaning). ' +
    'Example: {"romanization":"sà-wàt-dii","english":"hello","pos":"noun","emoji":"👋"}';

  const { text } = await callAIWithFallback(system, englishWord, aiConfig);
  const clean = text.replace(/```json|```/g, "").trim();
  const parsed = JSON.parse(clean);
  if (!parsed.romanization || !parsed.english || !parsed.pos) throw new Error("Incomplete AI response");
  // emoji is optional — default to empty string if not returned
  return parsed;
}

// AI Helper (issue #105) — for an EXISTING word being edited, suggest the correct
// part-of-speech and category. Unlike suggestWordDetails() (used when adding a brand
// new word), this only touches pos/category and takes the current category list so
// the AI picks from categories that already exist in this teacher's word bank.
async function suggestPosCategory(word, categories, aiConfig) {
  const catNames = categories.map(c => c.name);
  const system =
    "You are a English language expert helping a teacher categorize vocabulary for a Thai learning app. " +
    "Given a Thai word plus its English translation and romanization, respond with ONLY a valid JSON object, " +
    "no markdown fences, no preamble. Keys: " +
    '"pos" (one of: noun, verb, adjective, adverb, pronoun, preposition, conjunction, interjection, particle, classifier, numeral), ' +
    `"category" (choose the single BEST fit from this exact list, copy the name verbatim: ${JSON.stringify(catNames)}). ` +
    'Example: {"pos":"noun","category":"Food & Drink"}';
  const userMessage = `Thai: ${word.thai}\nEnglish: ${word.english || "(unknown)"}\nRomanization: ${word.romanization || "(unknown)"}`;

  const { text } = await callAIWithFallback(system, userMessage, aiConfig);
  const clean = text.replace(/```json|```/g, "").trim();
  const parsed = JSON.parse(clean);
  if (!parsed.pos || !parsed.category) throw new Error("Incomplete AI response");
  const matchedCategory = categories.find(c => c.name.toLowerCase() === String(parsed.category).toLowerCase());
  return {
    pos: PARTS_OF_SPEECH.includes(parsed.pos) ? parsed.pos : null,
    categoryId: matchedCategory ? matchedCategory.id : null,
  };
}

// Issue #120 — Multi-sense AI Helper for word editing. Unlike suggestPosCategory()
// (single sense), this detects when a word's English field contains MULTIPLE distinct,
// unrelated meanings (e.g. "leaf · classifier") and returns one sense object per meaning,
// reusing the same split logic from enrichWords() (PPT import).
// Returns: { senses: [{ english, pos, categoryId, emoji }] } or { senses: [single] }
// if only one sense is detected.
async function suggestPosCategoryMulti(word, categories, aiConfig) {
  const catNames = categories.map(c => c.name);
  // Reuse the dictionary reference to help the AI distinguish distinct senses
  let dictRefs = [];
  try { dictRefs = await fetchDictionaryReference(word.thai); } catch {}
  const refText = dictRefs.length
    ? dictRefs.map(r => `${r.gloss} (${r.pos})`).join('; ')
    : 'none found';

  // Issue #137 — flag an already-broken romanization (e.g. an emoji ended up in this field
  // from a PPT import parsing bug) so the AI knows this specific one needs regenerating.
  const romLooksBad = looksLikeBadRomanization(word.romanization);

  const system =
    "You are a English language expert helping a teacher categorize vocabulary for a Thai learning app.\n" +
    "Given a Thai word, its English translation(s), romanization, and dictionary references, determine if the English field contains\n" +
    "ONE underlying sense (near-synonyms / closely related meanings) or MULTIPLE genuinely distinct, unrelated senses of the same Thai spelling\n" +
    "(e.g. \u0e43\u0e1a meaning both \"leaf\" AND, unrelated, \"classifier\" — these should be split into separate cards).\n\n" +
    "Rules:\n" +
    "0. The \"english\" value you output must ALWAYS be English.\n" +
    "1. If ONE sense: output exactly one entry with the single best English translation.\n" +
    "2. If MULTIPLE distinct senses: output one entry PER distinct sense, each with its own English translation,\n" +
    "   part of speech, and emoji (do not merge unrelated meanings into one string).\n" +
    "3. For each entry, set \"pos\" to one of: noun, verb, adjective, adverb, pronoun, preposition, conjunction, interjection, particle, classifier, numeral.\n" +
    `4. For each entry, set \"category\" to the single BEST fit from this exact list, copy the name verbatim: ${JSON.stringify(catNames)}.\n` +
    "5. For each entry, set \"emoji\" to a SINGLE emoji that best represents THAT specific sense.\n" +
    "6. For each entry, set \"romanization\" to the correct Paiboon+-style romanization of the Thai word. The romanization\n" +
    "   given to you may be wrong — a parsing bug can put an emoji there instead of real romanization, or it can simply have a\n" +
    "   typo. If it contains Thai script, an emoji, or otherwise isn't real romanization, replace it with the correct one\n" +
    "   derived from the Thai word yourself. If it already looks correct, copy it through unchanged.\n\n" +
    "Respond ONLY with a valid JSON array, no markdown fences, no preamble. Each element is an object with keys:\n" +
    '\"english\", \"romanization\", \"pos\", \"category\", \"emoji\".\n' +
    "Examples:\n" +
    '[{"english":"hello","romanization":"sà-wàt-dii","pos":"noun","category":"Greetings","emoji":"\u{1F44B}"}]\n' +
    '[{"english":"leaf","romanization":"bai","pos":"noun","category":"Nature","emoji":"\u{1F33F}"},{"english":"classifier for flat objects","romanization":"bai","pos":"classifier","category":"Numbers & Quantities","emoji":"\u{1F4D0}"}]';

  const romFlag = romLooksBad ? ' (⚠ looks corrupted — likely a parsing error, please regenerate from the Thai text)' : '';
  const userMessage = `Thai: ${word.thai}\nEnglish: ${word.english || "(unknown)"}\nRomanization: ${word.romanization || "(unknown)"}${romFlag}\nDictionary reference: ${refText}`;

  const { text } = await callAIWithFallback(system, userMessage, aiConfig);
  const clean = text.replace(/```json|```/g, '').trim();
  let parsed;
  try {
    parsed = JSON.parse(clean);
  } catch {
    // Try to extract a JSON array from the text
    const match = clean.match(/\[[\s\S]*\]/);
    if (match) {
      try { parsed = JSON.parse(match[0]); } catch { parsed = null; }
    }
  }
  if (!Array.isArray(parsed) || parsed.length === 0) throw new Error("AI could not parse a valid response");

  const senses = parsed.map(s => {
    const matchedCat = categories.find(c => c.name.toLowerCase() === String(s.category).toLowerCase());
    // Trust the AI's romanization unless it ALSO looks broken (echoed emoji/Thai script back);
    // in that case fall back to the original rather than saving new garbage, and if the
    // original was already bad too, leave it blank so the edit form's validation catches it.
    const aiRom = typeof s.romanization === 'string' ? s.romanization.trim() : '';
    const romanization = (aiRom && !looksLikeBadRomanization(aiRom))
      ? aiRom
      : (romLooksBad ? '' : word.romanization);
    return {
      english: (s.english || '').trim(),
      romanization,
      pos: PARTS_OF_SPEECH.includes(s.pos) ? s.pos : null,
      categoryId: matchedCat ? matchedCat.id : null,
      emoji: (typeof s.emoji === 'string' && s.emoji.trim()) ? s.emoji.trim() : '',
    };
  }).filter(s => s.english);

  if (senses.length === 0) throw new Error("AI returned no valid senses");
  return { senses };
}

// Generate Thai spelling breakdown (การสะกดคำ) for beginner-level students.
// Example: ตา → "ตอ - อา = ตา (Mid tone)"
//          ไก่ → "กอ - ไอ - ไม้เอก ( ่) = ไก่ (Low tone)"
// Cached in localStorage per word ID to avoid repeated AI calls.
// Sanitize known AI formatting slips regardless of how well the prompt is followed:
// - strip stray "สระ " (the word "vowel") prefix before vowel names
// - collapse duplicated consonant letter after its name, e.g. "กอ ก" -> "กอ", "มอ ม" -> "มอ"
function sanitizeSpelling(text) {
  let out = text.replace(/สระ /g, "");
  out = out.replace(/([ก-ฮ])อ \1(?=[\s,]|$)/gu, "$1อ");
  return out.trim();
}

async function generateSpelling(englishWord, wordId, aiConfig) {
  // v2: cache key bumped to invalidate old entries generated with the inconsistent/buggy format
  const lsKey = `spelling_v2_${wordId}`;
  // 1. Fastest: localStorage (same user, repeat visit)
  const lsCached = localStorage.getItem(lsKey);
  if (lsCached) return lsCached;

  const dbKey = `spelling_v2_${wordId}`;
  // 2. Supabase shared_kv — any student/teacher who already triggered this word
  try {
    const dbVal = await storageGet(dbKey, true);
    if (dbVal && typeof dbVal === "string") {
      localStorage.setItem(lsKey, dbVal);
      return dbVal;
    }
  } catch { /* shared_kv not available yet — continue to AI */ }

  // 3. Cache miss — generate via AI and persist to shared_kv for all future users
  const system =
    "You are a Thai language teacher expert in การสะกดคำ (traditional Thai spelling-out, used to teach reading). " +
    "Given a Thai word, break it down into its spelling components with STRICT, CONSISTENT formatting.\n\n" +
    "COMPONENT RULES (apply to every syllable):\n" +
    "- Initial consonant: write ONLY the consonant name (กอ, ขอ, คอ, ตอ, มอ, นอ, etc.). " +
    "NEVER repeat the bare consonant letter after its name — write \"กอ\", never \"กอ ก\".\n" +
    "- Vowel: write ONLY the vowel name itself (อา, ไอ, อุ, เอ, แอ, โอ, อำ, etc.). " +
    "NEVER prefix it with the word \"สระ\" — write \"เอ\", never \"สระ เอ\".\n" +
    "- Tone mark (if present): name it (ไม้เอก, ไม้โท, ไม้ตรี, ไม้จัตวา) followed by the mark symbol in parentheses.\n" +
    "- Final consonant (if present): write ONLY its name, same rule as initial consonant.\n" +
    "- Join all components of one syllable with ' - '.\n\n" +
    "TONE SUPERSCRIPT LETTERS — used instead of writing out the tone name in parentheses:\n" +
    "  Mid (สามัญ) -> ᵐ | Low (เอก) -> ˡ | Falling (โท) -> ᶠ | High (ตรี) -> ʰ | Rising (จัตวา) -> ʳ\n" +
    "Attach the matching superscript character directly after the syllable/word, no space.\n\n" +
    "OUTPUT FORMAT — MONOSYLLABIC words (1 syllable):\n" +
    "  {component breakdown} = {word}{ToneSuperscript}\n" +
    "  Example: ตอ - อา - มอ = ตามᵐ\n" +
    "  Example: กอ - เอ - มอ = เกมᵐ\n" +
    "  Example: กอ - ไอ - ไม้เอก ( ่) = ไก่ˡ\n\n" +
    "OUTPUT FORMAT — MULTI-SYLLABLE words (2+ syllables, e.g. compound words):\n" +
    "  Break down EACH syllable separately using the same component rules above, then join the " +
    "syllable breakdowns with ', ' (comma+space). After all syllable breakdowns, append " +
    "' อ่านว่า \"{syllable1}{tone1} - {syllable2}{tone2}...\" = {full word}'.\n" +
    "  Example (ปากกา = ปาก + กา):\n" +
    "  ปอ - อา - กอ - ปาก, กอ - อา - กา อ่านว่า \"ปากˡ - กาᵐ\" = ปากกา\n\n" +
    "Respond with ONLY the final breakdown string. No markdown, no explanation, no extra text.";

  try {
    const { text } = await callAIWithFallback(system, englishWord, aiConfig);
    const clean = sanitizeSpelling(text.replace(/```json|```/g, "").trim());
    // Persist to Supabase shared_kv so every other student benefits
    storageSet(dbKey, clean, true).catch(() => {});
    // Also cache locally for instant repeat access
    localStorage.setItem(lsKey, clean);
    return clean;
  } catch {
    return null;
  }
}

// Emoji used as generic fallback when no contextual emoji was generated.
const GENERIC_EMOJI = "\u{1F4DD}"; // 📝

// Deterministic small hash — used to seed the AI image generator so the same
// word always produces the same image (stable across students/sessions).
function simpleHash(str) {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    hash = (hash * 31 + str.charCodeAt(i)) >>> 0;
  }
  return hash % 1000000;
}

// Fetch with a timeout, since some free image sources can hang or be slow.
async function fetchWithTimeout(url, ms, init) {
  const controller = new AbortController();
  const id = setTimeout(() => controller.abort(), ms);
  try {
    return await fetch(url, { ...init, signal: controller.signal });
  } finally {
    clearTimeout(id);
  }
}

// Concrete, photographable classes: a real-world photo search makes sense.
// Everything else (actions, relations, abstract words) rarely has one universal photo and
// keyword search tends to return nonsensical matches (chemistry diagrams, unrelated screenshots) —
// an AI illustration depicting the concept works better for these.
const PHOTO_FIRST_POS = new Set(["noun", "adjective", "classifier", "numeral"]);

// Terms to exclude from Wikimedia Commons searches to steer away from clinical/technical
// diagrams that dominate Commons for many common words (e.g. "eye" -> anatomy diagrams).
const WIKI_EXCLUDE_TERMS = "-diagram -anatomy -chart -map -structure -schematic -chemical -molecule -formula";

function buildAIImagePrompt(englishWord, pos) {
  if (PHOTO_FIRST_POS.has(pos)) {
    return `a clear, simple real-world photo of ${englishWord}, minimal background, no text, no diagram`;
  }
  return `a simple flat illustration depicting the concept or action of "${englishWord}", showing it visually as a scene, minimal style, no text, no diagram`;
}

async function searchWikimedia(englishWord) {
  try {
    const query = encodeURIComponent(`${englishWord} ${WIKI_EXCLUDE_TERMS}`);
    const url = `https://commons.wikimedia.org/w/api.php?action=query&generator=search&gsrsearch=${query}&gsrnamespace=6&gsrlimit=1&prop=imageinfo&iiprop=url&iiurlwidth=300&format=json&origin=*`;
    const res = await fetchWithTimeout(url, 5000);
    const data = await res.json();
    const pages = data?.query?.pages;
    if (pages) {
      const firstPage = Object.values(pages)[0];
      return firstPage?.imageinfo?.[0]?.thumburl || null;
    }
  } catch { /* network error, timeout, or no match */ }
  return null;
}

async function searchOpenverse(englishWord) {
  try {
    const q = encodeURIComponent(englishWord);
    const res = await fetchWithTimeout(`https://api.openverse.org/v1/images/?q=${q}&page_size=1&mature=false`, 5000);
    const data = await res.json();
    return data?.results?.[0]?.thumbnail || data?.results?.[0]?.url || null;
  } catch { /* network error, timeout, or no match */ }
  return null;
}

// Pollinations.ai rate limiter — max 1 concurrent request + 2s spacing between
// requests to avoid 429 "Too Many Requests" errors. The free tier is aggressive
// about rate limiting; without throttling, loading a practice session with 4+
// image-type exercises floods the API and all images fail.
let _pollinationsQueue = Promise.resolve();
let _lastPollinationsTs = 0;
const POLLINATIONS_MIN_GAP = 2000; // ms between requests

function _pollinationsThrottle(fn) {
  _pollinationsQueue = _pollinationsQueue.then(async () => {
    const now = Date.now();
    const wait = Math.max(0, _lastPollinationsTs + POLLINATIONS_MIN_GAP - now);
    if (wait > 0) await new Promise(r => setTimeout(r, wait));
    _lastPollinationsTs = Date.now();
    return fn();
  }).catch(() => fn()); // if previous failed, still proceed
  return _pollinationsQueue;
}

async function generateAIImage(englishWord, pos) {
  const seed = simpleHash(englishWord);
  const prompt = encodeURIComponent(buildAIImagePrompt(englishWord, pos));
  const genUrl = `https://image.pollinations.ai/prompt/${prompt}?width=300&height=300&seed=${seed}&nologo=true`;

  // Try up to 2 times with backoff on 429
  for (let attempt = 0; attempt < 2; attempt++) {
    try {
      const res = await _pollinationsThrottle(() => fetchWithTimeout(genUrl, 12000));
      if (res.status === 429) {
        // Rate limited — wait longer before retry
        if (attempt < 1) {
          await new Promise(r => setTimeout(r, 3000));
          continue;
        }
        return null;
      }
      const ct = res.headers.get("content-type") || "";
      if (res.ok && ct.startsWith("image/")) return genUrl;
    } catch { /* generation failed/timed out */ }
    if (attempt < 1) await new Promise(r => setTimeout(r, 1000));
  }
  return null;
}

// Fetch a representative image for a word. Source ORDER depends on grammatical class:
//   Concrete words (noun/adjective/classifier/numeral): Openverse -> Wikimedia -> AI
//     (real photos make sense here; Openverse's curated photo relevance beats raw
//     Commons keyword search, which surfaces clinical/technical diagrams too often)
//   Action/abstract words (verb/adverb/preposition/conjunction/interjection/particle/pronoun):
//     AI -> Openverse -> Wikimedia
//     (there's no one universal photo for "to follow" or "according to" — an AI
//     illustration of the concept beats a random unrelated stock photo)
// Same 3-layer cache as generateSpelling: localStorage → Supabase shared_kv → live fetch.
// AI results are verified (status + content-type) before caching, since Pollinations.ai
// can be flaky — failures are NOT cached as permanent "NONE", so a later flip can retry.
async function fetchWordImage(englishWord, wordId, pos) {
  // v3: cache key bumped — new POS-aware source ordering + Wikimedia diagram filtering
  // means previously "NONE" or "wrong/technical image" words deserve a fresh attempt.
  const lsKey = `img_v3_${wordId}`;
  const dbKey = `img_v3_${wordId}`;

  // 1. localStorage — instant, same user repeat visit
  const lsCached = localStorage.getItem(lsKey);
  if (lsCached) return lsCached === "NONE" ? null : lsCached;

  // 2. Supabase shared_kv — any student/teacher who already triggered this word
  try {
    const dbVal = await storageGet(dbKey, true);
    if (dbVal && typeof dbVal === "string") {
      localStorage.setItem(lsKey, dbVal);
      return dbVal === "NONE" ? null : dbVal;
    }
  } catch { /* shared_kv not available yet — continue to fetch */ }

  let imgUrl = null;

  if (PHOTO_FIRST_POS.has(pos)) {
    imgUrl = await searchOpenverse(englishWord);
    if (!imgUrl) imgUrl = await searchWikimedia(englishWord);
    if (!imgUrl) imgUrl = await generateAIImage(englishWord, pos);
  } else {
    imgUrl = await generateAIImage(englishWord, pos);
    if (!imgUrl) imgUrl = await searchOpenverse(englishWord);
    if (!imgUrl) imgUrl = await searchWikimedia(englishWord);
  }

  // Only permanently cache "NONE" if every source missed this attempt — since the AI
  // tier can be flaky, a later flip is still allowed to retry rather than being stuck.
  if (imgUrl) {
    localStorage.setItem(lsKey, imgUrl);
    storageSet(dbKey, imgUrl, true).catch(() => {});
  }
  return imgUrl;
}

// ---------------------------------------------------------------------------
// Root app
// ---------------------------------------------------------------------------
// ---------------------------------------------------------------------------
// Breadcrumb ring buffer — records the last 10 user actions before a crash.
// Call pushBreadcrumb("action-name") at key transitions. The buffer lives on
// window.__breadcrumbs so ErrorBoundary (a class) can read it without props.
if (typeof window !== "undefined" && !window.__breadcrumbs) {
  window.__breadcrumbs = [];
}
function pushBreadcrumb(action) {
  if (typeof window === "undefined") return;
  if (!window.__breadcrumbs) window.__breadcrumbs = [];
  window.__breadcrumbs.push({ action, ts: new Date().toISOString() });
  if (window.__breadcrumbs.length > 10) window.__breadcrumbs.shift();
}

// ErrorBoundary — catches render errors in any child component so the user
// sees a friendly error screen (with the crying-cat mascot) instead of a
// blank white page.  Used both at the app root and around individual tabs.
// ---------------------------------------------------------------------------
function ErrorScreen({ message, onRetry, fullScreen = false }) {
  const [countdown, setCountdown] = useState(0);
  useEffect(() => {
    if (!onRetry) return;
    setCountdown(10);
    const id = setInterval(() => {
      setCountdown(c => {
        if (c <= 1) { clearInterval(id); onRetry(); return 0; }
        return c - 1;
      });
    }, 1000);
    return () => clearInterval(id);
  }, [onRetry]);

  return (
    <div className={"es-root" + (fullScreen ? " es-fullscreen" : " es-compact")}>
      <div className="es-mascot-wrap">
        <img src="/mascote-crying.png" alt="" className="es-mascot" />
      </div>
      <div className="es-title">Something went wrong</div>
      <div className="es-sub">
        {message || "An unexpected error occurred while loading this section."}
      </div>
      {onRetry && (
        <div className="es-sub" style={{ marginTop: 4, opacity: 0.4 }}>
          Retrying in {countdown}s…
        </div>
      )}
    </div>
  );
}

class ErrorBoundary extends React.Component {
  constructor(props) {
    super(props);
    this.state = { hasError: false, error: null };
  }
  static getDerivedStateFromError(error) {
    return { hasError: true, error };
  }
  componentDidCatch(error, errorInfo) {
    // Log to console for debugging
    console.error("[ErrorBoundary]", error?.message || error, errorInfo?.componentStack || "");
    // Fire-and-forget: report to GitHub Issues via serverless endpoint.
    // Deduped server-side (same error+tab = comment on existing issue, not a new one).
    // Wrapped in try/catch so reporting never causes a secondary crash.
    try {
      const w = typeof window !== "undefined" ? window : {};
      const payload = {
        message:        error?.message || String(error),
        stack:          error?.stack || null,
        componentStack: errorInfo?.componentStack || null,
        tab:            w.__currentTab || "unknown",
        userType:       w.__userType || "unknown",
        screen:         w.__screen || w.__currentTab || "unknown",
        breadcrumbs:    w.__breadcrumbs ? [...w.__breadcrumbs] : [],
        viewport:       typeof window !== "undefined" ? `${window.innerWidth}x${window.innerHeight}` : "unknown",
        userAgent:      typeof navigator !== "undefined" ? navigator.userAgent : "",
        url:            w.location?.href || "",
        timestamp:      new Date().toISOString(),
        appVersion:     null,
      };
      fetch("/api/report-error", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      }).catch(() => {}); // silently ignore — reporting is best-effort
    } catch {}
  }
  handleRetry = () => {
    this.setState({ hasError: false, error: null });
  };
  render() {
    if (this.state.hasError) {
      const { fallbackMessage, fullScreen, onRetry } = this.props;
      return (
        <ErrorScreen
          message={fallbackMessage || (this.state.error?.message || "An unexpected error occurred.")}
          onRetry={onRetry || this.handleRetry}
          fullScreen={fullScreen}
        />
      );
    }
    return this.props.children;
  }
}

// #573 — Register a Web Push subscription and upsert it to push_subscriptions
async function registerPushSubscription(username) {
  try {
    if (!VAPID_PUBLIC_KEY || !("serviceWorker" in navigator) || !("PushManager" in window)) return;
    const permission = await Notification.requestPermission();
    if (permission !== "granted") return;
    const reg = await navigator.serviceWorker.ready;
    const existing = await reg.pushManager.getSubscription();
    const sub = existing || await reg.pushManager.subscribe({
      userVisibleOnly: true,
      applicationServerKey: VAPID_PUBLIC_KEY,
    });
    const { endpoint, keys: { p256dh, auth } = {} } = sub.toJSON();
    if (!endpoint || !p256dh || !auth) return;
    const client = await getSupabaseClient();
    const timezone = Intl.DateTimeFormat().resolvedOptions().timeZone || "Asia/Bangkok";
    await client.from("push_subscriptions").upsert(
      { username, endpoint, p256dh, auth, timezone },
      { onConflict: "endpoint" }
    );
  } catch (e) {
    console.warn("[push] subscription failed:", e?.message || e);
  }
}

// #577 — Notify teacher via push when a student records an exam result (fire-and-forget)
async function triggerPushExamResult(username, level, passed, pct) {
  try {
    const client = await getSupabaseClient();
    await client.functions.invoke("push-exam-result", {
      body: { username, level, passed, pct },
    });
  } catch (e) {
    console.warn("[push-exam-result] failed:", e?.message || e);
  }
}

// #574 — Trigger push-gift Edge Function after teacher sends a gift (fire-and-forget)
async function triggerPushGift(username, gift_type, gift_label) {
  try {
    const client = await getSupabaseClient();
    await client.functions.invoke("push-gift", {
      body: { username, gift_type, gift_label },
    });
  } catch (e) {
    console.warn("[push-gift] failed:", e?.message || e);
  }
}

