  // Issue #201 — unified celebration sequencer. Achievements, coins, and
  // avatar/gacha reveals used to all fire independently (achievement +
  // avatar full-screen moments could mount at the same time, with coin
  // toasts stuck rendering underneath). Now everything funnels through one
  // ordered queue and only ONE full-screen moment is ever on screen,
  // advancing to the next on dismiss — in the required priority order:
  // Achievements -> Coins -> Avatar/gacha reveal.
  useEffect(() => {
    if (activeCelebration || celebrationQueue.length === 0) return;
    const [next, ...rest] = celebrationQueue;
    setActiveCelebration(next);
    setCelebrationQueue(rest);
  }, [celebrationQueue, activeCelebration]);

  // Appends items to the celebration queue, preserving whatever order they're passed in.
  function pushCelebrations(items) {
    const list = (items || []).filter(Boolean);
    if (list.length === 0) return;
    setCelebrationQueue(q => [...q, ...list]);
  }
  useEffect(() => {
    async function init() {
      // Sprint 11 — restore last-used username *and* its Supabase session
      // (PIN was already verified when this session was created; we don't
      // ask again until the student explicitly logs out).
      try {
        if (USE_SUPABASE) {
          const lastUser = localStorage.getItem("sb-last-user");
          if (lastUser) {
            const user = await restoreSession(lastUser);
            if (user) {
              setStorageAuthState(user, lastUser);
            } else {
              localStorage.removeItem("sb-last-user"); // stale/expired — back to login screen
            }
          }
        }
        const p = await storageGet(KEYS.profile, false);
        setProfile(withAvatarDefaults(p));
        setLoaded(true);
      } catch {
        // #511 — network/Supabase failure: exit splash and show error screen with retry
        setLoadError(true);
        setLoaded(true);
      }
    }
    init();
  }, [loadKey]); // loadKey bump triggers retry

