    storageGet(ONBOARDING_KEY, false).then(stored => {
      if (!stored) { setTourStep(0); return; }
      // stored may be `true` (legacy, pre-achievements) or `{ done, skipped, skippedAt, resumeDone }`
      const meta = stored === true ? { done: true, skipped: null } : stored;
      setOnboardingMeta(meta);
      // #728 — resume tour from where student skipped, until they complete it
      if (meta.skipped && !meta.resumeDone && typeof meta.skippedAt === "number") {
        setTourStep(meta.skippedAt);
        setTourResumed(true);
      }
    });
