  // #559 — show event popup once per day when there's an active event with a vertical banner
  useEffect(() => {
    if (!loaded || !profile?.username || teacher) return;
    (async () => {
      try {
        const today = todayStr();
        const lastSeen = await storageGet(EVENT_POPUP_DATE_KEY, false);
        if (lastSeen === today) return;
        const now = new Date();
        const registry = getEventsRegistry(now);
        const activeEvents = registry.filter(ev => ev.window && now >= ev.window.start && now <= ev.window.end)
          .sort((a, b) => a.window.end - b.window.end);
        for (const ev of activeEvents) {
          let vUrl = null;
          if (ev.useLegacyBannerArt && ev.bannerKey) {
            const art = await getBannerArtOriented(ev.bannerKey);
            vUrl = art.vertical || null;
          } else {
            vUrl = (await storageGet(EVENT_BANNER_V_KEY(ev.id), true)) || null;
          }
          if (vUrl) {
            setEventPopupBannerUrl(vUrl);
            await storageSet(EVENT_POPUP_DATE_KEY, today, false);
            break;
          }
        }
      } catch (_) {}
    })();
  }, [loaded, profile?.username]); // eslint-disable-line

  // #508 — navigate to correct tab and measure spotlight target when step changes
  useEffect(() => {
    if (tourStep === null) return;
    const s = TOUR_STEPS[tourStep];
    s.sideEffect?.();  // #695 — optional side-effect (e.g. switch wcTab)
    setTab(s.tab);
    const timer = setTimeout(() => {
      if (!s.selector) { setTourTargetRect(null); return; }
      const el = document.querySelector(s.selector);
      setTourTargetRect(el ? el.getBoundingClientRect() : null);
    }, 380);
    return () => clearTimeout(timer);
  }, [tourStep]); // eslint-disable-line

  // #556/#557 — record first manual visit to Events/Progress tabs and trigger achievements.
  // "Manual" = tourStep is null (not driven by the tour) + student (not teacher).
  useEffect(() => {
    if (teacher || tourStep !== null || !profile?.username) return;
    if (tab === "events" && !visitedEventsTab) {
      setVisitedEventsTab(true);
      storageSet(VISITED_EVENTS_KEY, true, false).catch(() => {});
      (async () => {
        try {
          const stats = computeAchievementStats(progMap, streak, stHistory, sessionsCompleted, profile, {
            examHistory, gachaTickets, words, berserkStars, berserkAttempts, calligraphyProg, wordCalligraphyProg, pathStats, onboardingMeta, visitedEventsTab: true, visitedProgressTab,
          });
          const { newOnes, coinsEarned, rareTicketsEarned, epicTicketsEarned, avatarPrizes } = await runAchievementEngine(stats, achievementRewardOverrides, {
            onRareTicket:  (n) => { setGachaTickets(t => ({ ...t, rare: (t.rare || 0) + n })); pushCelebrations(Array.from({ length: n }, () => ({ type: "ticket", data: { rarity: "rare" } }))); },
            onEpicTicket:  (n) => { setGachaTickets(t => ({ ...t, epic: (t.epic || 0) + n })); pushCelebrations(Array.from({ length: n }, () => ({ type: "ticket", data: { rarity: "epic" } }))); },
            onAvatarPrize: async (avatarId) => {
              const av = getAvatarById(avatarId);
              if (!av || (profile.unlockedAvatars || []).includes(avatarId)) return;
              const updated = { ...profile, unlockedAvatars: [...(profile.unlockedAvatars || []), avatarId] };
              setProfile(updated);
              await storageSet(KEYS.profile, updated, false);
              await mirrorUnlockedAvatarsToRoster(profile.username, updated.unlockedAvatars, profile);
              pushCelebrations([{ type: "avatar", data: { criterion: { id: `achievement_avatar_${avatarId}`, title: "Achievement Reward!", desc: `You received ${av.name} 🎁` }, avatar: av } }]);
            },
          });
          setUnlockedTotal(t => t + newOnes.length);
          setUnlockedAchIds(prev => [...new Set([...prev, ...newOnes.map(a => a.id)])]);
          const items = [];
          if (newOnes.length > 0) {
            items.push(...newOnes.map(a => ({ type: "achievement", data: a })));
            if (profile?.username) appendAchievementTimelineEvents(profile.username, newOnes, unlockedAchIds).catch(() => {});
          }
          if (coinsEarned > 0) { handleCoinsEarned([{ amount: coinsEarned, label: "Achievement" }]); }
          if (items.length > 0) pushCelebrations(items);
        } catch (_) {}
      })();
    }
    if (tab === "progress" && !visitedProgressTab) {
      setVisitedProgressTab(true);
      storageSet(VISITED_PROGRESS_KEY, true, false).catch(() => {});
      (async () => {
        try {
          const stats = computeAchievementStats(progMap, streak, stHistory, sessionsCompleted, profile, {
            examHistory, gachaTickets, words, berserkStars, berserkAttempts, calligraphyProg, wordCalligraphyProg, pathStats, onboardingMeta, visitedEventsTab, visitedProgressTab: true,
          });
          const { newOnes, coinsEarned, epicTicketsEarned } = await runAchievementEngine(stats, achievementRewardOverrides, {
            onEpicTicket: (n) => { setGachaTickets(t => ({ ...t, epic: (t.epic || 0) + n })); pushCelebrations(Array.from({ length: n }, () => ({ type: "ticket", data: { rarity: "epic" } }))); },
          });
          setUnlockedTotal(t => t + newOnes.length);
          setUnlockedAchIds(prev => [...new Set([...prev, ...newOnes.map(a => a.id)])]);
          const items = [];
          if (newOnes.length > 0) {
            items.push(...newOnes.map(a => ({ type: "achievement", data: a })));
            if (profile?.username) appendAchievementTimelineEvents(profile.username, newOnes, unlockedAchIds).catch(() => {});
          }
          if (coinsEarned > 0) { handleCoinsEarned([{ amount: coinsEarned, label: "Achievement" }]); }
          if (items.length > 0) pushCelebrations(items);
        } catch (_) {}
      })();
    }
    // #718 — Hearthbound: first manual visit to Cat Sanctuary grants +1 Dawn Ticket
    if (tab === "store" && !teacher && !visitedSanctuaryTab && profile?.username) {
      setVisitedSanctuaryTab(true);
      (async () => {
        try {
          const flags = (await storageGet(HEARTHBOUND_FLAGS_KEY, false)) || {};
          if (!flags.visitedSanctuary && isHearthboundEarningActive(pathStats)) {
            await storageSet(HEARTHBOUND_FLAGS_KEY, { ...flags, visitedSanctuary: true }, false);
            const [cfg, boosts] = await Promise.all([getAvatarPowersConfig(), getActiveBoosts()]);
            const next = await grantDawnTickets(1, { profile, powersConfig: cfg, activeBoosts: boosts, doubleEffect: true });
            setDawnTickets(next);
            pushCelebrations([{ type: "ticket", data: { rarity: "dawn", label: "Dawn Ticket — Cat Sanctuary discovered! 🏡" } }]);
          } else if (!flags.visitedSanctuary) {
            await storageSet(HEARTHBOUND_FLAGS_KEY, { ...flags, visitedSanctuary: true }, false);
          }
        } catch (_) {}
      })();
    }
  }, [tab]); // eslint-disable-line

  // #508 — tour handlers live in App so they're in scope where OnboardingTour is rendered
  async function finishTour(skipped) {
    const currentStep = tourStep; // capture before clearing
    // #728 — on resume: keep skipped:true so secret_tour_full is never awarded;
    // mark resumeDone:true only when they complete (not skip again).
    const meta = tourResumed
      ? { ...onboardingMeta, resumeDone: !skipped, ...(skipped && { skippedAt: currentStep }) }
      : { done: true, skipped, ...(skipped && { skippedAt: currentStep }) };
    setTourStep(null);
    setTourTargetRect(null);
    setTourResumed(false);
    setTab("home");
    setOnboardingMeta(meta);
    storageSet(ONBOARDING_KEY, meta, false).catch(() => {});
    try {
      const stats = computeAchievementStats(progMap, streak, stHistory, sessionsCompleted, profile, {
        examHistory, gachaTickets, words, berserkStars, berserkAttempts, calligraphyProg, wordCalligraphyProg, pathStats, onboardingMeta: meta,
      });
      const { newOnes, coinsEarned } = await runAchievementEngine(stats, achievementRewardOverrides);
      setUnlockedTotal(t => t + newOnes.length);
      if (newOnes.length > 0) pushCelebrations(newOnes.map(a => ({ type: "achievement", data: a })));
      if (coinsEarned > 0) handleCoinsEarned([{ amount: coinsEarned, label: "Achievement" }]);
    } catch (_) {}
    // #718 — Hearthbound: tutorial completed without skip → +1 Dawn Ticket
    if (!skipped && isHearthboundEarningActive(pathStats)) {
      try {
        const flags = (await storageGet(HEARTHBOUND_FLAGS_KEY, false)) || {};
        if (!flags.tutorialDone) {
          await storageSet(HEARTHBOUND_FLAGS_KEY, { ...flags, tutorialDone: true }, false);
          const [cfg, boosts] = await Promise.all([getAvatarPowersConfig(), getActiveBoosts()]);
          const next = await grantDawnTickets(1, { profile, powersConfig: cfg, activeBoosts: boosts, doubleEffect: true });
          setDawnTickets(next);
          pushCelebrations([{ type: "ticket", data: { rarity: "dawn", label: "Dawn Ticket — Tutorial complete! 🌅" } }]);
        }
      } catch (_) {}
    }
  }
  function handleTourNext() {
    if (tourStep === null) return;
    if (tourResumed) setTourResumed(false); // #728 — dismiss "I hope you don't skip me" after first step
    if (tourStep >= TOUR_STEPS.length - 1) { finishTour(false); return; }
    setTourStep(s => s + 1);
  }
  function handleTourSkip() { finishTour(true); }

  // Load coins balance (Issue #167)
  // Issue #282 — switched to storageGetSafe: a plain storageGet(COINS_KEY)
  // returning null is ambiguous between "read failed" and "balance is 0".
  // Issue #382 — #282 only stopped this effect from DISPLAYING a wrong (0)
  // balance on a failed read; it never gave it a way to retry once the
  // race actually closes. With dep `[]` this ran exactly once, at the same
  // moment `restoreSession()` (in the `init()` effect above) could still be
  // in flight on a cold mobile reload — if that race was lost, `coins`
  // stayed frozen at its initial `useState(0)` for the rest of the session,
  // since nothing else (Shop/Gacha/Transactions tabs) re-fetches COINS_KEY
  // on its own. That's what made a student's balance show 0 in the header
  // while the ledger/DB balance was correct the whole time. Fix: key the
  // effect off `loaded` (only flips true after `init()` has awaited
  // restoreSession()) so the read is guaranteed to happen after the race
  // window has closed, instead of racing it.
  // Issue #609 — self-heal: if coins-balance is missing/null in personal_kv,
  // reconstruct from the last ledger entry and repair the key so future reads work.
  useEffect(() => {
    if (!loaded) return;
    storageGetSafe(COINS_KEY, false).then(async ({ value, error }) => {
      if (error) console.error("[coins] load failed:", error);
      if (value > 0) { setCoins(value); return; }
      const { value: ledger } = await storageGetSafe(COINS_LEDGER_KEY, false);
      if (Array.isArray(ledger) && ledger.length > 0) {
        const last = ledger[ledger.length - 1];
        if (last?.balanceAfter > 0) {
          setCoins(last.balanceAfter);
          storageSet(COINS_KEY, last.balanceAfter, false);
        }
      }
    });
  }, [loaded]);

  // Load Gacha ticket inventory (Issue #198)
  // Issue #382 — getGachaTickets() defaults to { rare: 0, epic: 0 } whenever
  // storageGet can't tell "no session yet" apart from "genuinely empty"
  // (same underlying race as the coins balance above). Deferring to `loaded`
  // avoids showing a false "0 tickets" on a cold reload for the same reason.
  useEffect(() => {
    if (!loaded) return;
    getGachaTickets().then(setGachaTickets);
  }, [loaded]);

  // Load pending daily reward + auto-expire check on app open
  useEffect(() => {
    if (!loaded) return;
    (async () => {
      const [pending, drTickets, doubled] = await Promise.all([
        storageGet(DAILY_REWARD_PENDING_KEY, false),
        storageGet("daily-reward-tickets", false),
        storageGet("daily-reward-doubled-used", false),
      ]);
      if (drTickets) setDailyRewardTickets(drTickets);
      if (doubled)   setUsedDailyDouble(true);
      if (!pending) return;
      const today = todayStr();
      if (!pending.collected && pending.todayKey !== today) {
        const coinValue = pending.type === "coins"
          ? pending.value
          : Math.floor((GACHA_TICKET_CATALOG[pending.type]?.price || 0) / 2);
        if (coinValue > 0) await creditCoins(coinValue, `Daily reward auto-converted (${pending.type})`);
        const expired = { ...pending, collected: true, autoConverted: true };
        await storageSet(DAILY_REWARD_PENDING_KEY, expired, false);
        setPendingReward(expired);
      } else {
        setPendingReward(pending);
      }
    })();
  }, [loaded]);

  // #727 — refresh personal_kv data when switching tabs so stale state from
  // a previous session / another device never persists across tab changes.
  const tabSwitchRef = useRef(false);
  useEffect(() => {
    if (!loaded) return;
    if (!tabSwitchRef.current) { tabSwitchRef.current = true; return; } // skip initial mount
    if (tab === "home") {
      (async () => {
        const [pending, sk, pStats, prof, log, sessionLog, energyLog, accuracyLog, wDone] = await Promise.all([
          storageGet(DAILY_REWARD_PENDING_KEY, false),
          storageGet(STREAK_KEY, false),
          storageGet(PATH_STATS_KEY, false),
          storageGet(KEYS.profile, false),
          storageGet(ACTIVITY_LOG_KEY, false),
          storageGet(SESSION_TIME_KEY, false),
          storageGet(ENERGY_SPEND_LOG_KEY, false),
          storageGet(PATH_ACCURACY_LOG_KEY, false),
          storageGet(WEEKLY_DONE_KEY(getCurrentWeekKey()), false),
        ]);
        if (sk) setStreak(sk);
        if (pStats) setPathStats(pStats);
        if (prof)   setProfile(withAvatarDefaults(prof));
        if (Array.isArray(log))         setActivityLog(log);
        if (Array.isArray(sessionLog))  setSessionTimeLog(sessionLog);
        if (Array.isArray(energyLog))   setEnergySpendLog(energyLog);
        if (Array.isArray(accuracyLog)) setPathAccuracyLog(accuracyLog);
        if (Array.isArray(wDone))       setWeeklyDone(wDone);
        if (!pending) return;
        const today = todayStr();
        if (!pending.collected && pending.todayKey !== today) {
          const coinValue = pending.type === "coins"
            ? pending.value
            : Math.floor((GACHA_TICKET_CATALOG[pending.type]?.price || 0) / 2);
          if (coinValue > 0) await creditCoins(coinValue, `Daily reward auto-converted (${pending.type})`);
          const expired = { ...pending, collected: true, autoConverted: true };
          await storageSet(DAILY_REWARD_PENDING_KEY, expired, false);
          setPendingReward(expired);
        } else {
          setPendingReward(pending);
        }
      })();
    } else if (tab === "progress") {
      (async () => {
        const [sk, log, sessionLog, energyLog, accuracyLog, pStats, wDone, prof] = await Promise.all([
          storageGet(STREAK_KEY, false),
          storageGet(ACTIVITY_LOG_KEY, false),
          storageGet(SESSION_TIME_KEY, false),
          storageGet(ENERGY_SPEND_LOG_KEY, false),
          storageGet(PATH_ACCURACY_LOG_KEY, false),
          storageGet(PATH_STATS_KEY, false),
          storageGet(WEEKLY_DONE_KEY(getCurrentWeekKey()), false),
          storageGet(KEYS.profile, false),
        ]);
        if (sk) setStreak(sk);
        if (Array.isArray(log))        setActivityLog(log);
        if (Array.isArray(sessionLog)) setSessionTimeLog(sessionLog);
        if (Array.isArray(energyLog))  setEnergySpendLog(energyLog);
        if (Array.isArray(accuracyLog)) setPathAccuracyLog(accuracyLog);
        if (pStats) setPathStats(pStats);
        if (Array.isArray(wDone))      setWeeklyDone(wDone);
        if (prof)                      setProfile(withAvatarDefaults(prof));
      })();
    }
  }, [tab, loaded]); // eslint-disable-line react-hooks/exhaustive-deps

