// ---------------------------------------------------------------------------
// Sprint 5.1 — JSZip dynamic loader
// ---------------------------------------------------------------------------
function useJSZip() {
  const [ready, setReady] = useState(!!(typeof window !== 'undefined' && window.JSZip));
  useEffect(() => {
    if (window.JSZip) { setReady(true); return; }
    const existing = document.querySelector('script[data-jszip]');
    if (existing) { existing.addEventListener('load', () => setReady(true)); return; }
    const s = document.createElement('script');
    s.src = 'https://cdnjs.cloudflare.com/ajax/libs/jszip/3.10.1/jszip.min.js';
    s.setAttribute('data-jszip', '1');
    s.onload = () => setReady(true);
    document.head.appendChild(s);
  }, []);
  return ready;
}

// Issue #62 — ADR-018 restricts the calligraphy feature to touch devices
// (tracing with a mouse doesn't validate stroke shape meaningfully — see
// ADR-018 in docs/decisions.md). Deliberately checks input CAPABILITY via
// `(pointer: coarse)`, not viewport width or user-agent sniffing — a
// touchscreen laptop should still get it, a wide-screen tablet in landscape
// still should too.
function useIsTouchCapable() {
  const [touch, setTouch] = useState(
    () => typeof window !== "undefined" && !!window.matchMedia && window.matchMedia("(pointer: coarse)").matches
  );
  useEffect(() => {
    if (typeof window === "undefined" || !window.matchMedia) return undefined;
    const mq = window.matchMedia("(pointer: coarse)");
    const onChange = () => setTouch(mq.matches);
    mq.addEventListener ? mq.addEventListener("change", onChange) : mq.addListener(onChange);
    return () => {
      mq.removeEventListener ? mq.removeEventListener("change", onChange) : mq.removeListener(onChange);
    };
  }, []);
  return touch;
}

// ---------------------------------------------------------------------------
// Sprint 5.1 — PPTX parsing utilities
// ---------------------------------------------------------------------------
const THAI_RE   = /[\u0E00-\u0E7F]/;
const IPA_RE    = /^\/[^/]+\/$/;
const IPA_MATCH = (t) => IPA_RE.test(t) || /^IPA\s+\/[^/]+\/$/.test(t);
const SKIP_TEXT = (t) => {
  const s = t.trim();
  return !s ||
    /^\d+\s*[/\/]\s*\d+$/.test(s) ||          // slide numbers like "14 / 15"
    LEVELS.includes(s) ||
    s.includes('VOCABULARY REVIEW') ||
    s === 'VOCABULARY' ||                       // individual slide header
    /^Review\s+\d/.test(s) ||
    s.startsWith('SHORT VOWEL') ||
    s.startsWith('LONG VOWEL') ||
    s === 'traditional' ||                      // script variant labels
    s === 'modern';
};

function startsWithEmoji(str) {
  const cp = str.codePointAt(0);
  return (cp >= 0x1F000 && cp <= 0x1FFFF) || (cp >= 0x2600 && cp <= 0x27BF);
}

// Issue #137 — defensive guard against a specific PPTX import bug: a slide's row-grouping
// can misalign by one row (e.g. an unrecognized caption line above a word block), which
// spills the EMOJI row's content into what should be the ROMANIZATION column. Any string
// containing Thai script or an emoji character is never valid romanization (romanization is
// always plain Latin text), so this catches that failure mode regardless of where in the
// pipeline it happened — used both to flag suspect input for the AI enrichment pass and to
// reject a bad value the AI itself might echo back.
const EMOJI_ANYWHERE_RE = /[\u{1F000}-\u{1FFFF}\u{2600}-\u{27BF}]/u;
function looksLikeBadRomanization(t) {
  const s = (t || '').trim();
  return !s || THAI_RE.test(s) || EMOJI_ANYWHERE_RE.test(s);
}

// Extract text from one slide XML, position-sorted by shape offset
// Returns the raw {x, y, texts} shape list, position-sorted, WITHOUT flattening —
// used by parseReviewSlideWords() below, which needs the row/column grid intact.
function extractSlidePositionedItems(xmlStr) {
  const doc = new DOMParser().parseFromString(xmlStr, 'application/xml');
  const items = [];

  // Regular shapes (p:sp)
  for (const sp of doc.getElementsByTagNameNS('*', 'sp')) {
    const off = sp.getElementsByTagNameNS('*', 'off')[0];
    const x = off ? +off.getAttribute('x') : 0;
    const y = off ? +off.getAttribute('y') : 0;
    const texts = Array.from(sp.getElementsByTagNameNS('*', 'p'))
      .map(p => Array.from(p.getElementsByTagNameNS('*', 't')).map(t => t.textContent).join(''))
      .filter(t => t.trim());
    if (texts.length) items.push({ x, y, texts });
  }

  // Table cells inside graphicFrame (p:graphicFrame → a:tbl → a:tr → a:tc)
  for (const gf of doc.getElementsByTagNameNS('*', 'graphicFrame')) {
    const off = gf.getElementsByTagNameNS('*', 'off')[0];
    const x = off ? +off.getAttribute('x') : 0;
    let rowY = off ? +off.getAttribute('y') : 0;
    for (const tr of gf.getElementsByTagNameNS('*', 'tr')) {
      let colX = x;
      for (const tc of tr.getElementsByTagNameNS('*', 'tc')) {
        const texts = Array.from(tc.getElementsByTagNameNS('*', 'p'))
          .map(p => Array.from(p.getElementsByTagNameNS('*', 't')).map(t => t.textContent).join(''))
          .filter(t => t.trim());
        if (texts.length) items.push({ x: colX, y: rowY, texts });
        colX += 100000; // approximate column offset
      }
      rowY += 100000;
    }
  }

  items.sort((a, b) => a.y !== b.y ? a.y - b.y : a.x - b.x);
  return items;
}

// Flat text version (order-only, no position data) — used by the stage-machine
// parser for individual VOCABULARY slides.
function extractSlideTexts(xmlStr) {
  return extractSlidePositionedItems(xmlStr).flatMap(i => i.texts);
}

// ---------------------------------------------------------------------------
// "VOCABULARY REVIEW" slides lay every word taught in the lesson out as a
// position-based grid of text boxes (NOT a real pptx table): a row of Thai
// words, then a row of emoji, then romanization, then IPA, then English —
// repeating in blocks of N words per row (N = however many fit side by side;
// the last block on a slide is often a partial row of fewer than N).
// This is the authoritative, clean word list for the lesson — unlike the
// individual "VOCABULARY"/"EXPRESSION" slides, whose layout varies release to
// release (e.g. some use a "-ี"/"เ-อ" vowel-mark shorthand in the spot where
// others use the full words "LONG VOWEL", which trips up the linear
// thai→romanization→ipa→english stage machine because the shorthand itself
// contains a Thai character).
// ---------------------------------------------------------------------------
const Y_ROW_TOLERANCE = 15000; // EMU — merges near-identical y offsets into one row band

function groupIntoRows(positionedItems) {
  const sorted = [...positionedItems].sort((a, b) => a.y - b.y || a.x - b.x);
  const rows = [];
  for (const item of sorted) {
    const last = rows[rows.length - 1];
    if (last && Math.abs(item.y - last.y) <= Y_ROW_TOLERANCE) {
      last.items.push(item);
    } else {
      rows.push({ y: item.y, items: [item] });
    }
  }
  for (const r of rows) r.items.sort((a, b) => a.x - b.x);
  return rows;
}

function parseReviewSlideWords(positionedItems) {
  // Drop header/caption noise (level pill, slide number, the "VOCABULARY
  // REVIEW" label itself, and the "Words 1–6 — mid tone only..." caption).
  const CAPTION_RE = /^(all\s+\d+\s+words|words\s+\d+)/i;
  const content = positionedItems.filter(i => {
    const t = i.texts.join(' ').trim();
    return !SKIP_TEXT(t) && !CAPTION_RE.test(t);
  });

  const rows = groupIntoRows(content);
  const words = [];
  // Rows cycle in fixed bands of 5: thai, emoji, romanization, ipa, english.
  for (let i = 0; i + 4 < rows.length; i += 5) {
    const [thaiRow, emojiRow, romRow, ipaRow, engRow] = rows.slice(i, i + 5);
    const n = thaiRow.items.length;
    for (let col = 0; col < n; col++) {
      const thai = (thaiRow.items[col]?.texts.join('') || '').trim();
      if (!thai || !THAI_RE.test(thai)) continue; // row misalignment guard
      words.push({
        emoji:        (emojiRow?.items[col]?.texts.join('') || '').trim(),
        thai,
        romanization: (romRow?.items[col]?.texts.join('') || '').trim(),
        ipa:          cleanIPA(ipaRow?.items[col]?.texts.join('') || ''),
        english:      (engRow?.items[col]?.texts.join('') || '').trim(),
        englishGlosses: [(engRow?.items[col]?.texts.join('') || '').trim()],
      });
    }
  }
  return words;
}

// Strip the "IPA" label / colon that sometimes precedes the slash notation,
// so the stored value is always just the clean phonemic transcription (e.g. "/taː/").
function cleanIPA(t) {
  return t.replace(/^IPA\s*:?\s*/i, '').trim();
}

// Stage-machine vocabulary parser
function parseVocabItems(texts) {
  const filtered = texts.filter(t => !SKIP_TEXT(t));
  const items = [];
  let cur = null;
  let stage = 0; // 1=thai 2=ro 3=ipa 4=en

  for (const raw of filtered) {
    const t = raw.trim();
    if (!t) continue;

    if (startsWithEmoji(t)) {
      if (cur?.thai) items.push(cur);
      cur = { emoji: t, thai: '', romanization: '', ipa: '', english: '', englishGlosses: [] };
      stage = 1;
      continue;
    }
    if (!cur) continue;

    if (stage === 1 && THAI_RE.test(t))              { cur.thai = t; stage = 2; }
    else if (stage === 2 && !THAI_RE.test(t) && !IPA_MATCH(t))   { cur.romanization = t; stage = 3; }
    else if (stage === 2 && IPA_MATCH(t))             { cur.ipa = cleanIPA(t); stage = 4; }
    else if (stage === 3 && IPA_MATCH(t))             { cur.ipa = cleanIPA(t); stage = 4; }
    else if (stage === 4) {
      // A slide can list more than one English gloss for the same Thai word
      // (e.g. "eye" and "maternal uncle" for ตา). Keep both the combined
      // display string AND the individual raw glosses — enrichWords() uses
      // the latter to decide whether these are one sense or several.
      cur.english = cur.english ? cur.english + ' · ' + t : t;
      cur.englishGlosses.push(t);
    }
  }
  if (cur?.thai) items.push(cur);

  // Deduplicate by Thai word
  const seen = new Set();
  return items.filter(w => !seen.has(w.thai) && seen.add(w.thai));
}

// Best-effort guess at why a "VOCABULARY" slide produced zero words, so the
// teacher gets an actionable hint instead of a word silently vanishing.
function guessSkipReason(texts) {
  const filtered = texts.filter(t => !SKIP_TEXT(t)).map(t => t.trim());
  if (!filtered.some(startsWithEmoji))          return 'no emoji icon found to mark the start of the word';
  if (!filtered.some(t => THAI_RE.test(t)))     return 'no Thai text found on this slide';
  return 'slide layout did not match the expected order (Thai → romanization → IPA → English)';
}

// Flags a parsed word that is missing a field a teacher would expect to see
// (e.g. the English gloss never arrived because the slide layout was off).
function collectMissingFields(word) {
  const missing = [];
  if (!word.english)      missing.push('English translation');
  if (!word.romanization) missing.push('romanization');
  if (!word.ipa)          missing.push('IPA');
  return missing;
}

async function parsePPTXFile(file) {
  const zip = new window.JSZip();
  await zip.loadAsync(await file.arrayBuffer());

  const slideNames = Object.keys(zip.files)
    .filter(n => /^ppt\/slides\/slide\d+\.xml$/.test(n))
    .sort((a, b) => +a.match(/\d+/)[0] - +b.match(/\d+/)[0]);

  let reviewWords = [];      // words found on "VOCABULARY REVIEW" slides — the authoritative source
  let individualWords = [];  // words found on individual "VOCABULARY" slides — legacy fallback only
  let reviewSlideCount = 0;
  let level = 'Pre-A1';
  let skippedSlides = []; // { slide: number, reason: string } — VOCABULARY slides that yielded no word
  let wordWarnings  = []; // { slide: number, thai: string, missing: string[] } — words missing a field

  for (const name of slideNames) {
    const xmlStr = await zip.files[name].async('string');
    const positioned = extractSlidePositionedItems(xmlStr);
    const texts  = positioned.flatMap(i => i.texts);

    const lvl = texts.find(t => LEVELS.includes(t.trim()));
    if (lvl) level = lvl.trim();

    // "VOCABULARY REVIEW" slides recap every word taught that lesson (including
    // ones whose individual slide was tagged EXPRESSION, not VOCABULARY) in a
    // clean, consistent grid — this is what we actually import words from.
    if (texts.some(t => t.includes('VOCABULARY REVIEW'))) {
      reviewSlideCount++;
      const slideNum = +(name.match(/\d+/)[0]);
      reviewWords = reviewWords.concat(
        parseReviewSlideWords(positioned).map(w => ({ ...w, _slide: slideNum }))
      );
      continue;
    }

    // Individual word slides — kept only as a fallback for older files that
    // don't have a REVIEW slide at all. Their layout varies release to release
    // (e.g. a vowel-mark shorthand like "-ี" in place of "LONG VOWEL" trips up
    // this linear parser), so never treat these as primary once review data exists.
    if (texts.some(t => t.trim() === 'VOCABULARY')) {
      const slideNum = +(name.match(/\d+/)[0]);
      const slideWords = parseVocabItems(texts);
      if (slideWords.length === 0) {
        skippedSlides.push({ slide: slideNum, reason: guessSkipReason(texts) });
      } else {
        individualWords = individualWords.concat(slideWords);
      }
      reviewSlideCount++;
    }
  }

  // Prefer the REVIEW-slide word list; only fall back to individual-slide
  // parsing when a file has no REVIEW slide at all (e.g. older decks).
  const usingReview = reviewWords.length > 0;
  const allWords = usingReview ? reviewWords : individualWords;

  for (const w of allWords) {
    const missing = collectMissingFields(w);
    if (missing.length) wordWarnings.push({ slide: w._slide ?? null, thai: w.thai, missing });
  }

  // Deduplicate by Thai
  const seen = new Set();
  const words = allWords
    .filter(w => !seen.has(w.thai) && seen.add(w.thai))
    .map(({ _slide, ...w }) => w); // strip internal tracking field before it reaches enrichment/save

  return { level, words, totalSlideCount: slideNames.length, reviewSlideCount, skippedSlides, wordWarnings, usingReview };
}

