// #518 — Forgot PIN modal: 3-step self-service recovery
function ForgotPinModal({ onClose }) {
  const [step, setStep]         = useState(1); // 1=username 2=answer 3=new pin
  const [username, setUsername] = useState("");
  const [question, setQuestion] = useState("");
  const [answer, setAnswer]     = useState("");
  const [newPin, setNewPin]     = useState("");
  const [newPin2, setNewPin2]   = useState("");
  const [loading, setLoading]   = useState(false);
  const [error, setError]       = useState("");
  const [done, setDone]         = useState(false);

  async function handleLookup() {
    if (!username.trim()) return;
    setLoading(true); setError("");
    try {
      const res = await loadSecurityQuestion(username);
      if (!res) {
        setError("ไม่พบคำถามสำรองสำหรับชื่อนี้ — ตั้งค่าได้ใน Settings หลังเข้าสู่ระบบ หรือติดต่อครู");
      } else {
        setQuestion(res.question);
        setStep(2);
      }
    } catch { setError("เชื่อมต่อเซิร์ฟเวอร์ไม่ได้ — ลองตรวจสอบอินเทอร์เน็ตแล้วลองใหม่"); }
    setLoading(false);
  }

  async function handleVerify() {
    if (!answer.trim()) return;
    setLoading(true); setError("");
    try {
      const answerHash = await hashAnswer(answer);
      // Verify by attempting to load and compare locally (shared_kv read)
      const slug = username.trim().toLowerCase();
      const stored = await storageGet(SECURITY_QUESTION_KEY(slug), true);
      if (!stored?.answerHash || stored.answerHash !== answerHash) {
        setError("คำตอบไม่ถูกต้อง — ลองใหม่อีกครั้ง");
      } else {
        setStep(3);
      }
    } catch { setError("เกิดข้อผิดพลาด — ลองใหม่อีกครั้ง"); }
    setLoading(false);
  }

  async function handleReset() {
    if (newPin.length !== 4 || newPin !== newPin2) return;
    setLoading(true); setError("");
    try {
      const answerHash = await hashAnswer(answer);
      const res = await fetch("/api/reset-pin", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ username: username.trim(), answerHash, newPin }),
      });
      const body = await res.json();
      if (body.ok) {
        setDone(true);
      } else if (body.reason === "wrong-answer") {
        setError("คำตอบไม่ตรงกัน — กรุณาเริ่มใหม่");
        setStep(1);
      } else {
        setError("รีเซ็ต PIN ไม่สำเร็จ — ลองใหม่หรือติดต่อครู");
      }
    } catch { setError("เชื่อมต่อเซิร์ฟเวอร์ไม่ได้ — ลองตรวจสอบอินเทอร์เน็ต"); }
    setLoading(false);
  }

  return (
    <ModalOverlay onClose={onClose}>
      <div className="modal-card" style={{ maxWidth: 340 }} onClick={e => e.stopPropagation()}>
        <div className="modal-head">
          <h2 style={{ fontSize: 16 }}>🔐 รีเซ็ต PIN</h2>
          <button className="icon-btn" onClick={onClose}><X size={16} /></button>
        </div>
        <div className="modal-body" style={{ padding: "16px 20px 20px" }}>
          {done ? (
            <>
              <p style={{ textAlign: "center", marginBottom: 16 }}>✅ รีเซ็ต PIN สำเร็จแล้ว! เข้าสู่ระบบด้วย PIN ใหม่ได้เลย</p>
              <button className="login-btn" style={{ width: "100%" }} onClick={onClose}>กลับไปเข้าสู่ระบบ</button>
            </>
          ) : (
            <>
              <div className="forgot-pin-steps">
                {[1,2,3].map(s => (
                  <div key={s} className={"forgot-pin-step-dot" + (s === step ? " active" : s < step ? " done" : "")} />
                ))}
              </div>

              {step === 1 && (
                <>
                  <p className="page-sub" style={{ marginBottom: 12 }}>พิมพ์ชื่อของคุณเพื่อค้นหาคำถามสำรอง</p>
                  <input className="login-input" placeholder="ชื่อของคุณ" value={username}
                    onChange={e => { setUsername(e.target.value); setError(""); }} autoFocus />
                  {error && <p className="login-error">{error}</p>}
                  <button className="login-btn" style={{ width: "100%", marginTop: 10 }}
                    disabled={!username.trim() || loading} onClick={handleLookup}>
                    {loading ? "กำลังค้นหา…" : "ถัดไป →"}
                  </button>
                </>
              )}

              {step === 2 && (
                <>
                  <p className="page-sub" style={{ marginBottom: 4 }}>ตอบคำถามความปลอดภัยของคุณ:</p>
                  <p style={{ fontWeight: 600, marginBottom: 12, fontSize: 14 }}>{question}</p>
                  <input className="login-input" placeholder="คำตอบของคุณ" value={answer}
                    onChange={e => { setAnswer(e.target.value); setError(""); }} autoFocus />
                  {error && <p className="login-error">{error}</p>}
                  <button className="login-btn" style={{ width: "100%", marginTop: 10 }}
                    disabled={!answer.trim() || loading} onClick={handleVerify}>
                    {loading ? "กำลังตรวจสอบ…" : "ยืนยัน →"}
                  </button>
                </>
              )}

              {step === 3 && (
                <>
                  <p className="page-sub" style={{ marginBottom: 12 }}>เลือก PIN ใหม่ 4 หลัก</p>
                  <input className="login-input" placeholder="PIN ใหม่" type="password" inputMode="numeric"
                    maxLength={4} value={newPin}
                    onChange={e => { setNewPin(e.target.value.replace(/\D/g,"").slice(0,4)); setError(""); }} autoFocus />
                  <input className="login-input" placeholder="ยืนยัน PIN ใหม่" type="password" inputMode="numeric"
                    maxLength={4} value={newPin2} style={{ marginTop: 8 }}
                    onChange={e => { setNewPin2(e.target.value.replace(/\D/g,"").slice(0,4)); setError(""); }} />
                  {newPin.length === 4 && newPin2.length === 4 && newPin !== newPin2 && (
                    <p className="login-error">PIN ไม่ตรงกัน</p>
                  )}
                  {error && <p className="login-error">{error}</p>}
                  <button className="login-btn" style={{ width: "100%", marginTop: 10 }}
                    disabled={newPin.length !== 4 || newPin !== newPin2 || loading} onClick={handleReset}>
                    {loading ? "กำลังรีเซ็ต…" : "รีเซ็ต PIN"}
                  </button>
                </>
              )}
            </>
          )}
        </div>
      </div>
    </ModalOverlay>
  );
}

function buildLoginGreeting(snap) {
  if (!snap) return {
    title: "สวัสดี! 👋",
    sub:   "พิมพ์ชื่อและสร้าง PIN เพื่อเริ่มต้นเลย",
  };
  const { username, streak, streakLastDate, energy, lastSeen } = snap;
  const firstName = username?.split(" ")[0] || username;
  const hoursAgo  = (Date.now() - lastSeen) / 3_600_000;
  const daysSince = hoursAgo / 24;

  if (streak >= 1 && streakLastDate) {
    const today     = todayStr();
    const yesterday = (() => { const d = new Date(); d.setDate(d.getDate() - 1); return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}-${String(d.getDate()).padStart(2,"0")}`; })();
    const streakAlive = streakLastDate === today || streakLastDate === yesterday;
    if (!streakAlive && daysSince >= 2) {
      return {
        title: `ไม่เป็นไรนะ ${firstName} 😊`,
        sub:   `streak ${streak} วันหายไปแล้ว แต่ความรู้ยังอยู่ — มาเริ่มใหม่กันเลย! 💪`,
      };
    }
    if (streakAlive && streak >= 3) {
      return {
        title: `${firstName} เก่งมาก! 🔥`,
        sub:   `${streak} วันติดต่อกันแล้ว — อย่าหยุดนะ, keep going!`,
      };
    }
  }
  if (typeof energy === "number" && energy <= 3 && hoursAgo < 48) {
    return {
      title: `ยินดีต้อนรับกลับมา ${firstName}!`,
      sub:   `ครั้งที่แล้วเหลือพลังงาน ${energy} — มาชาร์จใหม่กันเลย ⚡`,
    };
  }
  // General — rotates by day-of-week so it varies across the week
  // but stays the same all day (no jarring mid-session change).
  const hour = new Date().getHours();
  const timeHello = hour < 12 ? "อรุณสวัสดิ์" : hour < 17 ? "สวัสดีตอนบ่าย" : "สวัสดีตอนเย็น";
  const generals = [
    { title: `${timeHello}, ${firstName}! ☀️`,        sub: "มาฝึก English กันต่อเลย 🇬🇧" },
    { title: `ยินดีต้อนรับกลับมา ${firstName}!`,      sub: "ทีละนิดๆ ก็พูด English ได้นะ 🌱" },
    { title: `${firstName} มาแล้ว! 😄`,               sub: "วันนี้จะได้เรียนอะไรใหม่บ้างนะ? ✨" },
    { title: `สวัสดี ${firstName}! 👋`,               sub: "English ไม่ได้น่ากลัวอย่างที่คิดหรอก 😊" },
    { title: `ยินดีต้อนรับกลับมา ${firstName}!`,      sub: "Ready? Let's go! — เราทำได้! 🚀" },
    { title: `${firstName}! รอคุณอยู่เลย 🐾`,         sub: "มาต่อกันเลยนะ — one sip at a time 🌟" },
    { title: `${timeHello}, ${firstName}! 🌸`,        sub: "ภาษาอังกฤษรอคุณอยู่ — ไปกันเลย!" },
  ];
  return generals[new Date().getDay() % generals.length];
}

function LoginScreen({ onLogin }) {
  const [name,           setName]           = useState("");
  const [pin,            setPin]            = useState("");
  const [showTeacher,    setShowTeacher]    = useState(false);
  const [teacherCode,    setTeacherCode]    = useState("");
  const [loading,        setLoading]        = useState(false);
  const [error,          setError]          = useState("");
  const [showForgotPin,  setShowForgotPin]  = useState(false); // #518
  const [lastSnap,       setLastSnap]       = useState(null);

  // #583 — ler snapshot local para saudação contextual e pré-preenchimento
  useEffect(() => {
    try {
      const raw = localStorage.getItem("chaa-last-session");
      if (!raw) return;
      const snap = JSON.parse(raw);
      setLastSnap(snap);
      if (snap.username) setName(snap.username);
    } catch (e) { /* corrompido — ignora */ }
  }, []);

  const greeting = buildLoginGreeting(name.trim() ? lastSnap : null);

  const canSubmit = name.trim() && pin.length === 4 && !loading;

  async function submit() {
    if (!canSubmit) return;
    setError("");
    setLoading(true);
    try {
      await onLogin(name.trim(), pin, showTeacher ? teacherCode : "");
    } catch (e) {
      setError(e?.message || "Something went wrong. Please try again.");
    }
    setLoading(false);
  }

  const [showPin, setShowPin] = useState(false);

  return (
    <div className="login-screen">
      <img src="/login-brand.png" alt="Chá Chá Angkrit — Learn Thai One Sip at a Time" className="login-brand-img login-brand-mobile" />
      <div className="login-card">
        <img src="/login-brand.png" alt="" className="login-brand-img login-brand-desktop" aria-hidden="true" />

        <div className="login-welcome">
          <p className="login-welcome-title">{greeting.title}</p>
          <p className="login-welcome-sub">{greeting.sub}</p>
        </div>

        {/* Issue #35 — these fields must live inside a real <form>. Chrome
            treats bare `type="password"` inputs outside a <form> as
            password-manager autofill targets and can silently overwrite
            them with an unrelated saved credential, which is exactly what
            corrupted the teacher access code in the field. Wrapping in a
            <form> (+ explicit autoComplete) stops that. */}
        <form
          className="login-form"
          onSubmit={e => { e.preventDefault(); submit(); }}
        >
          <div className="login-input-wrap">
            <svg className="login-input-icon" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><circle cx="12" cy="8" r="4"/><path d="M4 20c0-4 3.6-7 8-7s8 3 8 7"/></svg>
            <input
              className="login-input"
              placeholder="ชื่อของคุณ"
              value={name}
              onChange={e => { setName(e.target.value); setError(""); }}
              autoComplete="off"
              name="chaa-student-name"
              autoFocus
            />
          </div>

          <div className="login-input-wrap">
            <svg className="login-input-icon" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><rect x="5" y="11" width="14" height="10" rx="2"/><path d="M8 11V7a4 4 0 0 1 8 0v4"/></svg>
            <input
              className="login-input"
              placeholder="PIN 4 หลัก"
              type={showPin ? "text" : "password"}
              inputMode="numeric"
              pattern="[0-9]*"
              maxLength={4}
              value={pin}
              onChange={e => { setPin(e.target.value.replace(/\D/g, "").slice(0, 4)); setError(""); }}
              autoComplete="off"
              name="chaa-student-pin"
            />
            <button type="button" className="login-pin-eye" onClick={() => setShowPin(v => !v)} tabIndex={-1} aria-label={showPin ? "Hide PIN" : "Show PIN"}>
              {showPin
                ? <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M17.94 17.94A10.07 10.07 0 0 1 12 20c-7 0-11-8-11-8a18.45 18.45 0 0 1 5.06-5.94"/><path d="M9.9 4.24A9.12 9.12 0 0 1 12 4c7 0 11 8 11 8a18.5 18.5 0 0 1-2.16 3.19"/><line x1="1" y1="1" x2="23" y2="23"/></svg>
                : <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/><circle cx="12" cy="12" r="3"/></svg>
              }
            </button>
          </div>

          <p className="login-pin-hint">
            มาครั้งแรกใช่ไหม? PIN นี้จะปกป้องชื่อของคุณตั้งแต่นี้เป็นต้นไป
          </p>

          {showTeacher && (
            <div className="login-input-wrap">
              <svg className="login-input-icon" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M22 10v6M2 10l10-5 10 5-10 5z"/><path d="M6 12v5c0 1.657 2.686 3 6 3s6-1.343 6-3v-5"/></svg>
              <input
                className="login-input teacher-code-input"
                placeholder="Teacher access code"
                type="password"
                value={teacherCode}
                onChange={e => setTeacherCode(e.target.value)}
                autoComplete="off"
                name="chaa-teacher-code"
              />
            </div>
          )}

          {error && <p className="login-error">{error}</p>}

          <button
            type="submit"
            className="login-btn"
            disabled={!canSubmit}
          >
            {loading ? "กำลังเข้าสู่ระบบ…" : <><span className="login-btn-star">✦</span> Continue <span className="login-btn-star">✦</span></>}
          </button>

          {!showTeacher && (
            <>
              <div className="login-or-row"><span className="login-or-line"/><span className="login-or-text">or</span><span className="login-or-line"/></div>
              <button
                type="button"
                className="login-teacher-btn"
                onClick={() => { setShowTeacher(true); setTeacherCode(""); }}
              >
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" width="16" height="16"><path d="M22 10v6M2 10l10-5 10 5-10 5z"/><path d="M6 12v5c0 1.657 2.686 3 6 3s6-1.343 6-3v-5"/></svg>
                I am a teacher
              </button>
            </>
          )}
          {showTeacher && (
            <button type="button" className="teacher-toggle" onClick={() => { setShowTeacher(false); setTeacherCode(""); }}>
              ← กลับไปหน้านักเรียน
            </button>
          )}

          {/* #518 — forgot PIN link */}
          {!showTeacher && (
            <button type="button" className="forgot-pin-link"
              onClick={() => setShowForgotPin(true)}>
              ลืม PIN ใช่ไหม?
            </button>
          )}
        </form>

      </div>
      {showForgotPin && <ForgotPinModal onClose={() => setShowForgotPin(false)} />}
    </div>
  );
}

// ---------------------------------------------------------------------------
// Tab button
// ---------------------------------------------------------------------------
// ---------------------------------------------------------------------------
// #508 — Onboarding Tour
// ---------------------------------------------------------------------------
// #695 — redesigned tour: 21 steps in narrative order
const TOUR_STEPS = [
  { tab: "home",     selector: null,                              title: "Welcome to Chá Chá Angkrit! 👋",  desc: "Let me give you a quick tour of the app. It'll only take a few seconds!" },
  { tab: "home",     selector: "[data-tour='hero-banner']",       title: "Your Dashboard 🌟",          desc: "This banner greets you every day with an encouraging message. Tap the button here to go straight to your Lesson Path — the fastest way to start learning." },
  { tab: "home",     selector: ".stat-grid",                      title: "Your Vocabulary 📚",         desc: "Words practiced, new ones available, and words you've mastered. These numbers grow every time you study." },
  { tab: "home",     selector: ".level-progress-card",            title: "Level Progress 📊",          desc: "Your mastery of the current level. Study consistently and this bar will fill up!" },
  { tab: "home",     selector: null,                              title: "Proficiency Exam 🎓",        desc: "Once your mastery reaches 100%, a proficiency exam unlocks. Pass it and you advance to the next level — with a new set of vocabulary and harder challenges." },
  { tab: "home",     selector: ".hqc-mission",                    title: "Daily Mission 🎁",           desc: "Practice once today to complete your daily mission. Once done, a reward appears here — tap it to collect! Rewards include Meowtongs or Gacha tickets. Miss it and it auto-converts at midnight." },
  { tab: "practice", selector: "[data-tour='nav-practice']",      title: "Practice Tab 🎯",            desc: "Smart flashcards with spaced repetition (SRS) — the app automatically picks the right words for you to review today." },
  { tab: "path",     selector: "[data-tour='nav-path']",          title: "Lesson Path Tab 🗺️",        desc: "Structured lessons created by your teacher. Follow the trail to learn English step by step." },
  { tab: "path",     selector: ".lp-energy-bar",                  title: "Energy ⚡",                  desc: "Each lesson costs 2 energy. You start with 20 and it refills automatically — 1 point every 15 minutes. Run out? Just come back later and it'll be ready." },
  { tab: "progress", selector: "[data-tour='nav-progress']",      title: "Progress Tab 📈",            desc: "Track your unlocked achievements, weekly activity, and overall progress over time." },
  { tab: "progress", selector: "[data-tour='weekly-card']",       title: "This Week 📅",               desc: "Your practice activity for the current week — days you studied, vocabulary reviewed, and lessons completed. Keep the habit going!",
    sideEffect: () => document.dispatchEvent(new CustomEvent("tour-wc-tab", { detail: "activities" })) },
  { tab: "progress", selector: "[data-tour='streak-pill']",       title: "Your Streak 🔥",             desc: "Every consecutive day you practice adds to your streak. The longer it runs, the bigger the bonuses — and some monthly cats require a streak milestone to unlock!" },
  { tab: "progress", selector: "[data-tour='weekly-card']",       title: "Weekly Challenges 🏆",       desc: "Three challenges set by your teacher each week. Complete all three and earn a bonus reward!",
    sideEffect: () => document.dispatchEvent(new CustomEvent("tour-wc-tab", { detail: "challenges" })) },
  { tab: "store",    selector: ".sch-cotm-card",                  title: "Cat of the Month 🗓️",       desc: "Every month a Legendary cat is up for grabs. Hit the streak goal and complete the weekly challenge to unlock it. The clock resets on the 1st!" },
  { tab: "store",    selector: ".sanctuary-col-left",             title: "Your Collection 🐱",         desc: "All the cats you've unlocked so far. Tap any cat to see its skills and set it as your avatar — each one has a unique power!" },
  { tab: "store",    selector: ".sanctuary-feed-group",           title: "Activity Feed 💰",            desc: "Every Meowtong earned or spent appears here — practice sessions, missions, achievements. Your personal transaction log." },
  { tab: "store",    selector: ".topbar-pill-coins",              title: "Meowtongs 🪙",               desc: "Your currency balance — แมวทอง. Earn them by studying and completing missions. Tap here anytime to see your full transaction history." },
  { tab: "store",    selector: ".wish-carousel",                  title: "Make a Wish 🎴",              desc: "Use tickets to pull for new cats! Choose Moonrise for Rare, Starlight for Epic, or a Solstice Ticket when a special banner is active." },
  { tab: "store",    selector: ".sch-col-pills",                  title: "Your Tickets 🎫",             desc: "See how many tickets of each type you have. Buy more with Meowtongs below — or earn them through missions and events!" },
  { tab: "events",   selector: "[data-tour='nav-events']",        title: "Events Tab 🎪",              desc: "Special events bring extra challenges and unique rewards. Some are the only way to unlock Legendary cats — check back often!" },
  { tab: "home",     selector: null,                              title: "You're all set! 🎉",         desc: "Start with the Lesson Path or jump into Practice — every session brings you closer to fluency. Good luck! 🐱" },
];

function OnboardingTour({ step, onNext, onSkip, targetRect, resumed = false }) {
  const s = TOUR_STEPS[step];
  const isLast = step === TOUR_STEPS.length - 1;
  const desc = resumed ? `หวังว่าคราวนี้จะไม่ skip นะ! ${s.desc}` : s.desc;
  const hasSpot = !!(targetRect && s.selector);
  const pad = 10;

  // #567 — position balloon above the spotlight when the element is in the bottom half
  // of the viewport, so the balloon never covers what's being explained
  const spotCenter = hasSpot ? targetRect.top + targetRect.height / 2 : 0;
  const balloonAtTop = hasSpot && spotCenter > window.innerHeight / 2;
  const balloonPos = balloonAtTop ? { top: 12 } : { bottom: 76 };

  return createPortal(
    <>
      {hasSpot ? (
        <div style={{
          position: "fixed",
          top: targetRect.top - pad, left: targetRect.left - pad,
          width: targetRect.width + pad * 2, height: targetRect.height + pad * 2,
          borderRadius: 12,
          boxShadow: "0 0 0 9999px rgba(6,4,18,0.82)",
          zIndex: 99998, pointerEvents: "none",
          transition: "top 0.32s ease, left 0.32s ease, width 0.32s ease, height 0.32s ease",
          outline: "2px solid rgba(255,200,80,0.55)",
        }} />
      ) : (
        <div style={{ position: "fixed", inset: 0, zIndex: 99998, background: "rgba(6,4,18,0.82)", pointerEvents: "none" }} />
      )}
      <div style={{
        position: "fixed", ...balloonPos, left: 12, right: 12, zIndex: 99999,
        background: "linear-gradient(145deg, #1a1040 0%, #0d1b3e 100%)",
        border: "1px solid rgba(255,200,80,0.28)", borderRadius: 18,
        padding: "20px 18px 16px",
        boxShadow: "0 12px 40px rgba(0,0,0,0.55)",
      }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 8 }}>
          <span style={{ fontSize: 17, fontWeight: 700, color: "#ffd080", lineHeight: 1.25 }}>{s.title}</span>
          <button onClick={onSkip} style={{ background: "none", border: "none", color: "rgba(255,255,255,0.38)", fontSize: 13, cursor: "pointer", paddingLeft: 10, flexShrink: 0 }}>
            Skip
          </button>
        </div>
        <p style={{ margin: "0 0 12px", fontSize: 14, lineHeight: 1.6, color: "rgba(255,255,255,0.78)" }}>{desc}</p>
        {s.cats && (
          <div style={{ display: "flex", gap: 10, marginBottom: 16 }}>
            {s.cats.map(cat => {
              const rarityColor = cat.rarity === "legendary" ? "#e8557a" : cat.rarity === "epic" ? "#b060e8" : "#4a90d9";
              const rarityLabel = cat.rarity === "legendary" ? "Legendary" : cat.rarity === "epic" ? "Epic" : "Rare";
              return (
                <div key={cat.id} style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", gap: 5 }}>
                  <div style={{
                    width: 64, height: 64, borderRadius: 12,
                    border: `2px solid ${rarityColor}`,
                    boxShadow: `0 0 10px ${rarityColor}55`,
                    overflow: "hidden", background: "rgba(255,255,255,0.05)",
                  }}>
                    <img src={cat.image} alt={cat.name} style={{ width: "100%", height: "100%", objectFit: "cover" }} />
                  </div>
                  <span style={{ fontSize: 11, fontWeight: 700, color: rarityColor, letterSpacing: "0.04em", textTransform: "uppercase" }}>{rarityLabel}</span>
                  <span style={{ fontSize: 11, color: "rgba(255,255,255,0.55)", textAlign: "center", lineHeight: 1.2 }}>{cat.name}</span>
                </div>
              );
            })}
          </div>
        )}
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
          <span style={{ fontSize: 12, color: "rgba(255,255,255,0.28)", letterSpacing: "0.03em" }}>{step + 1} / {TOUR_STEPS.length}</span>
          <button onClick={onNext} style={{
            background: "linear-gradient(135deg,#f5a623,#e08800)", border: "none",
            borderRadius: 999, padding: "9px 26px", fontSize: 14, fontWeight: 700,
            color: "#1a1040", cursor: "pointer", letterSpacing: "0.01em",
          }}>
            {isLast ? "Let's go! 🐱" : "Next →"}
          </button>
        </div>
      </div>
    </>,
    document.body
  );
}

// #532 — custom image icon wrapper compatible with TabButton's icon={X} pattern
function ImgTabIcon({ src, size }) {
  const [broken, setBroken] = React.useState(false);
  if (broken) return <BookOpen size={size} />;  // fallback icon while image loads
  return (
    <img
      src={src}
      width={size}
      height={size}
      style={{ objectFit: "contain" }}
      alt=""
      onError={() => setBroken(true)}
    />
  );
}
const PathTabIcon = ({ size }) => <ImgTabIcon src="/icons/icon-path.png" size={size} />;

function TabButton({ icon: Icon, label, active, onClick, disabled, badge, ...rest }) {
  return (
    <button className={"tab-btn" + (active ? " active" : "") + (disabled ? " disabled" : "")} onClick={disabled ? undefined : onClick} {...rest}>
      <div style={{ position: "relative", display: "inline-flex" }}>
        <Icon size={18} />
        {badge > 0 && <span className="tab-badge">{badge}</span>}
      </div>
      <span>{label}</span>
      {disabled && <span className="soon-dot" />}
    </button>
  );
}

