// ---------------------------------------------------------------------------
// Issue #403 (foundation for #400) — shared modal-overlay wrapper.
//
// Renders into document.body via createPortal instead of wherever the
// calling component happens to sit in the tree. This is the fix for #400:
// modals nested inside a scrolling/overflow-clipped ancestor (e.g. a card
// inside a scrollable list) get visually clipped or mispositioned today
// because `.modal-overlay`'s `position: fixed` is relative to the nearest
// transformed/positioned ancestor, not necessarily the viewport, depending
// on where in the tree a given modal call site lives. A portal always
// escapes to <body>, so every modal behaves the same regardless of caller.
//
// `closeOnBackdrop` intentionally accepts a boolean (not just always wiring
// onClick to onClose) to cover ImportPPTModal's special case (~line 12767):
// `onClick={phase === 'saved' ? onClose : undefined}` — the backdrop only
// closes the modal once the import has actually finished saving. Callers
// that don't care just pass the default `true`.
//
// This issue ONLY introduces the component + one manual smoke test
// (DifficultyModal, the simplest existing modal) to confirm it renders
// identically through the portal. No other modal is migrated yet — that's
// #400.1 through #400.6.
function ModalOverlay({ onClose, closeOnBackdrop = true, children }) {
  return createPortal(
    <div className="modal-overlay" onClick={closeOnBackdrop ? onClose : undefined}>
      {children}
    </div>,
    document.body
  );
}

// Issue #50 — fast path to release a class code to every student missing it
function ReleaseClassesModal({ codes, roster, onClose, onReleased }) {
  const [releasing, setReleasing] = useState(null);

  async function releaseCode(code) {
    if (releasing) return;
    setReleasing(code);
    const missing = roster.filter((s) => Array.isArray(s.enabledClassCodes) && !s.enabledClassCodes.includes(code));
    await Promise.all(missing.map((s) => {
      const updated = { ...s, enabledClassCodes: [...s.enabledClassCodes, code] };
      return storageSet(`${ROSTER_PREFIX}${s.username}`, updated, true);
    }));
    await onReleased();
    setReleasing(null);
    onClose();
  }

  return (
    <ModalOverlay onClose={onClose}>
      <div className="modal-card release-modal" onClick={(e) => e.stopPropagation()}>
        <div className="modal-head">
          <h2>Release classes</h2>
          <button className="icon-btn" onClick={onClose}>
            <X size={16} />
          </button>
        </div>
        <div className="modal-body">
          <p className="release-modal-hint">Tap a class code to unlock it for every student who doesn't have it yet.</p>
          {codes.length === 0 && <div className="release-empty">Nothing left to release — every code is already unlocked for everyone.</div>}
          <div className="release-code-list">
            {codes.map((c) => (
              <button key={c.code} className="release-code-row" onClick={() => releaseCode(c.code)} disabled={!!releasing}>
                <span className="release-code-name">{c.code}</span>
                <span className="release-code-count">{c.wordCount || 0} words</span>
                {releasing === c.code && <span className="release-code-status">Releasing…</span>}
              </button>
            ))}
          </div>
        </div>
      </div>
    </ModalOverlay>
  );
}

// Issue #93 — Level Settings modal (teacher-only)
function LevelSettingsModal({ config, onClose, onSave }) {
  const [draft, setDraft] = useState(() => {
    // Initialize all levels with existing config or defaults
    const d = {};
    for (const lvl of LEVELS) {
      const existing = config[lvl] || {};
      d[lvl] = {
        totalClassCodes: existing.totalClassCodes ?? "",
        examThreshold: existing.examThreshold ?? "",
      };
    }
    return d;
  });

  function update(lvl, field, value) {
    setDraft(prev => ({
      ...prev,
      [lvl]: { ...prev[lvl], [field]: value === "" ? "" : Number(value) },
    }));
  }

  function handleSave() {
    const clean = {};
    for (const [lvl, v] of Object.entries(draft)) {
      clean[lvl] = {
        totalClassCodes: v.totalClassCodes === "" ? null : Math.max(0, v.totalClassCodes),
        examThreshold: v.examThreshold === "" ? null : Math.min(100, Math.max(0, v.examThreshold)),
      };
    }
    onSave(clean);
  }

  return (
    <ModalOverlay onClose={onClose}>
      <div className="modal-card level-settings-modal" onClick={(e) => e.stopPropagation()}>
        <div className="modal-head">
          <h2>Level Settings</h2>
          <button className="icon-btn" onClick={onClose}>
            <X size={16} />
          </button>
        </div>
        <div className="modal-body">
          <p className="release-modal-hint">
            Set the expected total ClassCodes and exam readiness threshold (% mastered) for each level.
            Leave blank to skip — students won't see that metric for that level.
          </p>
          <div className="level-settings-list">
            {LEVELS.map(lvl => (
              <div key={lvl} className="level-settings-row">
                <span className="level-settings-level">{lvl}</span>
                <label className="level-settings-field">
                  <span className="level-settings-field-label">ClassCodes</span>
                  <input
                    type="number" min="0" placeholder="—"
                    value={draft[lvl].totalClassCodes}
                    onChange={(e) => update(lvl, "totalClassCodes", e.target.value)}
                  />
                </label>
                <label className="level-settings-field">
                  <span className="level-settings-field-label">Threshold %</span>
                  <input
                    type="number" min="0" max="100" placeholder="—"
                    value={draft[lvl].examThreshold}
                    onChange={(e) => update(lvl, "examThreshold", e.target.value)}
                  />
                </label>
              </div>
            ))}
          </div>
          <button className="btn-primary level-settings-save" onClick={handleSave}>
            Save Settings
          </button>
        </div>
      </div>
    </ModalOverlay>
  );
}

// ---------------------------------------------------------------------------
// Issue #184 / #216 — teacher screen: assign a power to each avatar +
// (owner-added scope for this same phase) edit shop avatar prices.
// Reads/writes AVATAR_POWERS_CONFIG_KEY and AVATAR_PRICE_OVERRIDES_KEY
// (both shared KV, defined in #214/#216) via the onSave callback, mirroring
// LevelSettingsModal's draft-then-save pattern above.
//
// The default avatar (shadow-cat, free to every student from day one) is
// deliberately excluded from the list — giving the one avatar every student
// already has a power would erase the entire point of tying powers to
// rarity/scarcity.
// Issue #227 — function, not a frozen module constant, so it reflects
// whatever's in the custom-avatar cache at the moment the modal opens
// (the cache may not be populated yet at module-eval time on first load).
function getAvatarPowersAssignable() {
  return getFullAvatarCatalog().filter((a) => !a.isDefault);
}

function AvatarPowersModal({ powersConfig, priceOverrides, onClose, onSave }) {
  const [draft, setDraft] = useState(() => {
    const d = {};
    for (const a of getAvatarPowersAssignable()) {
      const existing = powersConfig[a.id] || {};
      d[a.id] = {
        // Legacy single-choice field — still drives the Common/Uncommon
        // dropdown (mutually exclusive, unchanged). Rare+ rows use the two
        // independent flags below instead (Issue #224).
        mechanic: existing.passive ? "passive" : (existing.simple || existing.special) ? "consumable" : "none",
        // Issue #224 — Rare+ avatars can have consumable(s) AND a passive at
        // once, so these are independent rather than one exclusive choice.
        useConsumable: !!(existing.simple || existing.special),
        usePassive: !!existing.passive,
        simple: existing.simple || "",
        special: existing.special || "",
        passive: existing.passive || "",
        // Issue #295 — optional 2nd passive slot, e.g. pairing a positive
        // bonus with a negative drawback for balance on the same avatar.
        passive2: existing.passive2 || "",
        price: priceOverrides[a.id] ?? a.price ?? "",
      };
    }
    return d;
  });

  function update(avatarId, field, value) {
    setDraft((prev) => ({ ...prev, [avatarId]: { ...prev[avatarId], [field]: value } }));
  }

  function handleSave() {
    const newPowersConfig = {};
    const newPriceOverrides = {};
    for (const a of getAvatarPowersAssignable()) {
      const d = draft[a.id];
      // Issue #287 — window no longer a separate field; it's baked into
      // whichever passive power id was picked (coins_50_morning etc.).
      newPowersConfig[a.id] = {
        simple:  d.useConsumable ? (d.simple || null)  : null,
        special: d.useConsumable ? (d.special || null) : null,
        passive: d.usePassive    ? (d.passive || null) : null,
        // Issue #295 — 2nd passive, only meaningful while the passive toggle is on.
        passive2: d.usePassive   ? (d.passive2 || null) : null,
      };
      if (a.shopExclusive && d.price !== "") {
        newPriceOverrides[a.id] = Math.max(0, Number(d.price));
      }
    }
    onSave(newPowersConfig, newPriceOverrides);
  }

  function renderGroup(title, avatars) {
    if (avatars.length === 0) return null;
    return (
      <div className="avatar-powers-group" key={title}>
        <div className="avatar-powers-group-title">{title}</div>
        {avatars.map((a) => {
          const d = draft[a.id];
          const hasSpecial = !!RARITY_POWER_COOLDOWN[a.rarity]?.special;
          const simpleOpts  = getAssignablePowers("simple", a.rarity);
          const specialOpts = getAssignablePowers("special", a.rarity);
          const passiveOpts = getAssignablePowers("passive", a.rarity);
          return (
            <div key={a.id} className="avatar-powers-row">
              <div className="avatar-powers-avatar">
                <img src={a.image} alt={a.name} className="avatar-powers-thumb" />
                <div>
                  <div className="avatar-powers-name">{a.name}</div>
                  <div className="avatar-powers-rarity">{RARITY_LABEL[a.rarity] || a.rarity}</div>
                </div>
              </div>

              {/* Issue #224 — Rare+ avatars get two independent toggles
                  (consumable(s) AND passive can both be on); Common/Uncommon
                  keep the original mutually-exclusive dropdown unchanged. */}
              {!hasSpecial && (
                <label className="level-settings-field">
                  <span className="level-settings-field-label">Power</span>
                  <select
                    value={d.mechanic}
                    onChange={(e) => {
                      const v = e.target.value;
                      setDraft((prev) => ({
                        ...prev,
                        [a.id]: { ...prev[a.id], mechanic: v, useConsumable: v === "consumable", usePassive: v === "passive" },
                      }));
                    }}
                  >
                    <option value="none">None</option>
                    <option value="consumable">Consumable</option>
                    <option value="passive">Passive</option>
                  </select>
                </label>
              )}

              {hasSpecial && (
                <div className="avatar-powers-toggles">
                  <label className="avatar-powers-toggle">
                    <input
                      type="checkbox"
                      checked={d.useConsumable}
                      onChange={(e) => update(a.id, "useConsumable", e.target.checked)}
                    />
                    <span>Consumable(s)</span>
                  </label>
                  <label className="avatar-powers-toggle">
                    <input
                      type="checkbox"
                      checked={d.usePassive}
                      onChange={(e) => update(a.id, "usePassive", e.target.checked)}
                    />
                    <span>Passive</span>
                  </label>
                </div>
              )}

              {d.useConsumable && (
                <>
                  <label className="level-settings-field">
                    <span className="level-settings-field-label">Simple</span>
                    <select value={d.simple} onChange={(e) => update(a.id, "simple", e.target.value)}>
                      <option value="">—</option>
                      {simpleOpts.map((p) => <option key={p.id} value={p.id}>{p.name}</option>)}
                    </select>
                  </label>
                  {hasSpecial && (
                    <label className="level-settings-field">
                      <span className="level-settings-field-label">Special</span>
                      <select value={d.special} onChange={(e) => update(a.id, "special", e.target.value)}>
                        <option value="">—</option>
                        {specialOpts.map((p) => <option key={p.id} value={p.id}>{p.name}</option>)}
                      </select>
                    </label>
                  )}
                </>
              )}

              {d.usePassive && (
                <>
                  <label className="level-settings-field">
                    <span className="level-settings-field-label">Ability</span>
                    <select value={d.passive} onChange={(e) => update(a.id, "passive", e.target.value)}>
                      <option value="">—</option>
                      {passiveOpts.map((p) => <option key={p.id} value={p.id}>{p.name}</option>)}
                    </select>
                  </label>
                  {/* Issue #295 — optional 2nd ability, e.g. pairing a
                      positive passive with a negative drawback. */}
                  <label className="level-settings-field">
                    <span className="level-settings-field-label">Ability 2 (optional)</span>
                    <select value={d.passive2} onChange={(e) => update(a.id, "passive2", e.target.value)}>
                      <option value="">—</option>
                      {/* Issue #295 — hide whatever's already picked as Ability 1
                          so the same passive can't be double-stacked by accident. */}
                      {passiveOpts.filter((p) => p.id !== d.passive).map((p) => <option key={p.id} value={p.id}>{p.name}</option>)}
                    </select>
                  </label>
                </>
              )}

              {a.shopExclusive && (
                <label className="level-settings-field">
                  <span className="level-settings-field-label">Price (Meowtongs)</span>
                  <input
                    type="number" min="0" placeholder={String(SHOP_AVATAR_PRICE)}
                    value={d.price}
                    onChange={(e) => update(a.id, "price", e.target.value)}
                  />
                </label>
              )}
            </div>
          );
        })}
      </div>
    );
  }

  const assignable = getAvatarPowersAssignable();
  const prizePool = assignable.filter((a) => !a.shopExclusive && !a.monthlyExclusive);
  const shop      = assignable.filter((a) => a.shopExclusive);
  const monthly   = assignable.filter((a) => a.monthlyExclusive);

  return (
    <ModalOverlay onClose={onClose}>
      <div className="modal-card avatar-powers-modal" onClick={(e) => e.stopPropagation()}>
        <div className="modal-head">
          <h2>Avatar Powers &amp; Pricing</h2>
          <button className="icon-btn" onClick={onClose}>
            <X size={16} />
          </button>
        </div>
        <div className="modal-body">
          <p className="release-modal-hint">
            Assign a power to each cat (no automatic rarity gating — it's your call) and adjust
            the shop cats' prices without needing a deploy.
          </p>
          {renderGroup("Prize Pool", prizePool)}
          {renderGroup("Shop", shop)}
          {renderGroup("Cat of the Month", monthly)}
          <button className="btn-primary level-settings-save" onClick={handleSave}>
            Save
          </button>
        </div>
      </div>
    </ModalOverlay>
  );
}

// Issue #228 (sub-issue 2/2 of #223) — Teacher-facing screen to create,
// edit and remove custom cats without a code deploy. Sits on top of #227's
// data layer (getCustomAvatars/addCustomAvatar/updateCustomAvatar/
// removeCustomAvatar/validateCustomAvatarData). Hardcoded catalog avatars
// are NOT editable here — only ones the teacher created show up in the list.
const EMPTY_CAT_FORM = { name: "", image: "", rarity: "common", category: "prize", price: "", monthKey: "", lockedUntilMonthKey: "" };

// Issue #386 — the admin config screen #351 always meant to ship ("escolha
// manual do professor no painel admin, com fallback pra 2 Rare aleatórios")
// but #377 only ever shipped the data layer (setBannerFeaturedRares/
// setBannerFeaturedLegendary) — nothing in the UI ever called them, so every
// banner has been running on the deterministic random fallback this whole
// time. Deliberately shows ALL Rares/Legendaries (including locked #386
// banner-exclusive debuts like Don Thong/Kila Meowter/Meowlin) — this is
// exactly the one screen where assigning a locked avatar to ITS OWN debut
// banner is the whole point, so it reads straight from getFullAvatarCatalog()
// rather than the lock-filtered getAvatarsByRarity().
function ManageBannerModal({ onClose, initialBannerKey }) {
  const [bannerKey, setBannerKey] = useState(() => {
    if (initialBannerKey && isBannerLaunched(initialBannerKey)) return initialBannerKey;
    const active = getActiveBanner(new Date());
    return (active && isBannerLaunched(active.bannerKey)) ? active.bannerKey : BANNER_LAUNCH_KEY;
  });
  const [selectedRares, setSelectedRares] = useState([]);
  const [legendaryOverride, setLegendaryOverride] = useState("");
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [savedMsg, setSavedMsg] = useState("");
  const [bannerArtH, setBannerArtH] = useState("");
  const [bannerArtV, setBannerArtV] = useState("");
  const [bannerArtUploading, setBannerArtUploading] = useState("");
  const [bannerArtError, setBannerArtError] = useState("");

  const catalog = getFullAvatarCatalog();
  const allRares = catalog.filter((a) => a.rarity === "rare");
  const allLegendaries = catalog.filter((a) => a.rarity === "legendary");

  useEffect(() => {
    let cancelled = false;
    setLoading(true);
    setSavedMsg("");
    Promise.all([
      getBannerFeaturedRares(bannerKey),
      getBannerFeaturedLegendaryOverride(bannerKey),
      getBannerArtOriented(bannerKey),
    ]).then(([rares, legendary, art]) => {
      if (cancelled) return;
      setSelectedRares(rares || []);
      setLegendaryOverride(legendary || "");
      setBannerArtH(art.horizontal || art.legacy || "");
      setBannerArtV(art.vertical || "");
      setLoading(false);
    });
    return () => { cancelled = true; };
  }, [bannerKey]);

  // Same M-2 math as getActiveBanner, just re-derived from the raw
  // bannerKey the teacher typed/picked (no live Date to read a window from).
  const validKey = /^\d{4}-\d{2}$/.test(bannerKey);
  const autoFeaturedMonthKey = validKey ? (() => {
    const [y, m] = bannerKey.split("-").map(Number);
    return getMonthKey(new Date(y, m - 3, 1));
  })() : null;
  const autoLegendary = autoFeaturedMonthKey ? getMonthlyCatAvatar(autoFeaturedMonthKey, catalog) : null;

  function toggleRare(id) {
    setSelectedRares((prev) => {
      if (prev.includes(id)) return prev.filter((x) => x !== id);
      if (prev.length >= 2) return prev;
      return [...prev, id];
    });
  }

  async function handleBannerArtUpload(orientation, e) {
    const file = e.target.files?.[0];
    e.target.value = "";
    if (!file) return;
    if (!file.type.startsWith("image/")) { setBannerArtError("Please choose an image file."); return; }
    setBannerArtUploading(orientation);
    setBannerArtError("");
    try {
      const publicUrl = await storageUpload(file, "cat-avatars", `banner-art-${orientation}-${bannerKey}-`);
      if (orientation === "h") setBannerArtH(publicUrl);
      else setBannerArtV(publicUrl);
    } catch (err) {
      setBannerArtError(err.message || "Upload failed.");
    } finally {
      setBannerArtUploading("");
    }
  }

  async function handleSave() {
    setSaving(true);
    setSavedMsg("");
    try {
      await setBannerFeaturedRares(bannerKey, selectedRares);
      if (legendaryOverride) await setBannerFeaturedLegendary(bannerKey, legendaryOverride);
      await setBannerArtOriented(bannerKey, { horizontal: bannerArtH.trim() || null, vertical: bannerArtV.trim() || null });
      setSavedMsg("✓ Saved.");
    } catch (e) {
      setSavedMsg(e.message || "Couldn't save.");
    }
    setSaving(false);
  }

  return (
    <ModalOverlay onClose={onClose}>
      <div className="modal-card" onClick={(e) => e.stopPropagation()}>
        <div className="modal-head">
          <h2>Manage Solstice Banner</h2>
          <button className="icon-btn" onClick={onClose}>
            <X size={16} />
          </button>
        </div>
        <div className="modal-body">
          <div className="avatar-powers-row">
            <div className="level-settings-field">
              <span className="level-settings-field-label">Banner month</span>
              <input type="month" value={bannerKey} onChange={(e) => setBannerKey(e.target.value)} />
              {validKey && !isBannerLaunched(bannerKey) && (
                <div className="mancat-banner-preview">Solstice Banners start with {BANNER_LAUNCH_KEY} — this month won't run one.</div>
              )}
            </div>
          </div>

          {loading ? (
            <div className="gift-loading">Loading…</div>
          ) : (
            <>
              <div className="avatar-powers-row" style={{ marginTop: 12 }}>
                <div className="level-settings-field">
                  <span className="level-settings-field-label">Featured Legendary</span>
                  <select value={legendaryOverride} onChange={(e) => setLegendaryOverride(e.target.value)}>
                    <option value="">
                      {autoLegendary ? `Auto — ${autoLegendary.name} (${autoFeaturedMonthKey})` : "Auto — nothing shipped for that month yet"}
                    </option>
                    {allLegendaries.map((a) => (
                      <option key={a.id} value={a.id}>{a.name}</option>
                    ))}
                  </select>
                </div>
              </div>

              <div style={{ marginTop: 12 }}>
                <span className="level-settings-field-label">Featured Rares — pick up to 2 (empty = random fallback)</span>
                <div className="gift-grid" style={{ marginTop: 6 }}>
                  {allRares.map((a) => {
                    const checked = selectedRares.includes(a.id);
                    return (
                      <button
                        key={a.id}
                        type="button"
                        className={"gift-item-btn" + (checked ? " gift-item-btn-done" : "")}
                        onClick={() => toggleRare(a.id)}
                        disabled={!checked && selectedRares.length >= 2}
                      >
                        {a.name}{checked ? " ✓" : ""}
                      </button>
                    );
                  })}
                </div>
              </div>

              <div style={{ marginTop: 12 }}>
                <span className="level-settings-field-label">Banner art — horizontal 16:9 (desktop / tablet)</span>
                {bannerArtH && (
                  <img src={bannerArtH} alt="Horizontal preview" style={{ display: "block", width: "100%", maxHeight: 120, objectFit: "cover", borderRadius: 8, marginTop: 6, border: "1px solid var(--border)" }} />
                )}
                <div style={{ display: "flex", gap: 8, alignItems: "center", marginTop: 6, flexWrap: "wrap" }}>
                  <label style={{ cursor: "pointer" }}>
                    <input type="file" accept="image/*" onChange={(e) => handleBannerArtUpload("h", e)} disabled={!!bannerArtUploading} style={{ display: "none" }} />
                    <span className="btn-secondary" style={{ pointerEvents: "none" }}>
                      {bannerArtUploading === "h" ? "Uploading…" : "Upload horizontal"}
                    </span>
                  </label>
                </div>
                <input type="url" placeholder="…or paste horizontal image URL" value={bannerArtH}
                  onChange={(e) => { setBannerArtH(e.target.value); setBannerArtError(""); }}
                  style={{ marginTop: 6, width: "100%", boxSizing: "border-box" }} />
                {bannerArtH && (
                  <button type="button" className="delete-btn" style={{ marginTop: 4, fontSize: "0.75rem", padding: "2px 8px" }} onClick={() => setBannerArtH("")}>
                    Remove horizontal
                  </button>
                )}
              </div>

              <div style={{ marginTop: 12 }}>
                <span className="level-settings-field-label">Banner art — vertical 9:16 (smartphone)</span>
                {bannerArtV && (
                  <img src={bannerArtV} alt="Vertical preview" style={{ display: "block", maxWidth: 120, maxHeight: 200, objectFit: "cover", borderRadius: 8, marginTop: 6, border: "1px solid var(--border)" }} />
                )}
                <div style={{ display: "flex", gap: 8, alignItems: "center", marginTop: 6, flexWrap: "wrap" }}>
                  <label style={{ cursor: "pointer" }}>
                    <input type="file" accept="image/*" onChange={(e) => handleBannerArtUpload("v", e)} disabled={!!bannerArtUploading} style={{ display: "none" }} />
                    <span className="btn-secondary" style={{ pointerEvents: "none" }}>
                      {bannerArtUploading === "v" ? "Uploading…" : "Upload vertical"}
                    </span>
                  </label>
                </div>
                <input type="url" placeholder="…or paste vertical image URL" value={bannerArtV}
                  onChange={(e) => { setBannerArtV(e.target.value); setBannerArtError(""); }}
                  style={{ marginTop: 6, width: "100%", boxSizing: "border-box" }} />
                {bannerArtV && (
                  <button type="button" className="delete-btn" style={{ marginTop: 4, fontSize: "0.75rem", padding: "2px 8px" }} onClick={() => setBannerArtV("")}>
                    Remove vertical
                  </button>
                )}
                {bannerArtError && <div className="stg-msg stg-msg-error" style={{ marginTop: 4 }}>{bannerArtError}</div>}
              </div>

              {savedMsg && <StgToast key={savedMsg} msg={savedMsg} />}
              <button className="btn-primary level-settings-save" style={{ marginTop: 14 }} onClick={handleSave} disabled={saving || bannerArtUploading}>
                {saving ? "Saving…" : "Save"}
              </button>
            </>
          )}
        </div>
      </div>
    </ModalOverlay>
  );
}

// ---------------------------------------------------------------------------
// #718 — Manage Hearthbound Modal (teacher config for Hearthbound featured cats)
// ---------------------------------------------------------------------------
function ManageHearthboundModal({ onClose }) {
  const catalog = getFullAvatarCatalog();
  const allLegendaries = catalog.filter(a => a.rarity === "legendary");
  const allEpics       = catalog.filter(a => a.rarity === "epic");
  const allRares       = catalog.filter(a => a.rarity === "rare");

  const [legendaryId,      setLegendaryId]      = useState("");
  const [epic1Id,          setEpic1Id]          = useState("");
  const [epic2Id,          setEpic2Id]          = useState("");
  const [rareId,           setRareId]           = useState("");
  const [artDesktop,       setArtDesktop]       = useState("");
  const [artMobile,        setArtMobile]        = useState("");
  const [artPortrait,      setArtPortrait]      = useState("");
  const [artUploading,     setArtUploading]     = useState("");
  const [artError,         setArtError]         = useState("");
  const [loading,          setLoading]          = useState(true);
  const [saving,           setSaving]           = useState(false);
  const [savedMsg,         setSavedMsg]         = useState("");

  useEffect(() => {
    Promise.all([
      storageGet(HEARTHBOUND_FEATURED_LEGENDARY_KEY, true),
      storageGet(HEARTHBOUND_FEATURED_EPIC1_KEY,     true),
      storageGet(HEARTHBOUND_FEATURED_EPIC2_KEY,     true),
      storageGet(HEARTHBOUND_FEATURED_RARE_KEY,      true),
      storageGet(HEARTHBOUND_ART_DESKTOP_KEY,        true),
      storageGet(HEARTHBOUND_ART_MOBILE_KEY,         true),
      storageGet(HEARTHBOUND_ART_PORTRAIT_KEY,       true),
    ]).then(([l, e1, e2, r, d, m, p]) => {
      setLegendaryId(l || "");
      setEpic1Id(e1 || "");
      setEpic2Id(e2 || "");
      setRareId(r || "");
      setArtDesktop(d || "");
      setArtMobile(m || "");
      setArtPortrait(p || "");
      setLoading(false);
    });
  }, []);

  async function handleArtUpload(variant, e) {
    const file = e.target.files?.[0];
    e.target.value = "";
    if (!file) return;
    if (!file.type.startsWith("image/")) { setArtError("Please choose an image file."); return; }
    setArtUploading(variant);
    setArtError("");
    try {
      const url = await storageUpload(file, "cat-avatars", `hearthbound-art-${variant}-`);
      if (variant === "desktop")  setArtDesktop(url);
      if (variant === "mobile")   setArtMobile(url);
      if (variant === "portrait") setArtPortrait(url);
    } catch (err) {
      setArtError(err.message || "Upload failed.");
    } finally {
      setArtUploading("");
    }
  }

  async function handleSave() {
    setSaving(true); setSavedMsg("");
    try {
      await Promise.all([
        storageSet(HEARTHBOUND_FEATURED_LEGENDARY_KEY, legendaryId  || null, true),
        storageSet(HEARTHBOUND_FEATURED_EPIC1_KEY,     epic1Id      || null, true),
        storageSet(HEARTHBOUND_FEATURED_EPIC2_KEY,     epic2Id      || null, true),
        storageSet(HEARTHBOUND_FEATURED_RARE_KEY,      rareId       || null, true),
        storageSet(HEARTHBOUND_ART_DESKTOP_KEY,        artDesktop.trim()  || null, true),
        storageSet(HEARTHBOUND_ART_MOBILE_KEY,         artMobile.trim()   || null, true),
        storageSet(HEARTHBOUND_ART_PORTRAIT_KEY,       artPortrait.trim() || null, true),
      ]);
      setSavedMsg("✓ Saved.");
    } catch (e) { setSavedMsg(e.message || "Couldn't save."); }
    setSaving(false);
  }

  return (
    <ModalOverlay onClose={onClose}>
      <div className="modal-card" onClick={e => e.stopPropagation()}>
        <div className="modal-head">
          <h2>Manage Hearthbound</h2>
          <button className="icon-btn" onClick={onClose}><X size={16} /></button>
        </div>
        <div className="modal-body">
          {loading ? <div className="gift-loading">Loading…</div> : (<>
            <p style={{ color: "var(--text-sub)", fontSize: "0.85rem", marginBottom: 10 }}>
              Configure the four featured avatars for the Hearthbound (Dawn Ticket) event.
            </p>
            <div className="avatar-powers-row">
              <label className="level-settings-field">
                <span className="level-settings-field-label">Featured Legendary</span>
                <select value={legendaryId} onChange={e => setLegendaryId(e.target.value)}>
                  <option value="">— None —</option>
                  {allLegendaries.map(a => <option key={a.id} value={a.id}>{a.name}</option>)}
                </select>
              </label>
            </div>
            <div className="avatar-powers-row" style={{ marginTop: 10 }}>
              <label className="level-settings-field">
                <span className="level-settings-field-label">Featured Epic 1</span>
                <select value={epic1Id} onChange={e => setEpic1Id(e.target.value)}>
                  <option value="">— None —</option>
                  {allEpics.map(a => <option key={a.id} value={a.id}>{a.name}</option>)}
                </select>
              </label>
            </div>
            <div className="avatar-powers-row" style={{ marginTop: 10 }}>
              <label className="level-settings-field">
                <span className="level-settings-field-label">Featured Epic 2</span>
                <select value={epic2Id} onChange={e => setEpic2Id(e.target.value)}>
                  <option value="">— None —</option>
                  {allEpics.filter(a => a.id !== epic1Id).map(a => <option key={a.id} value={a.id}>{a.name}</option>)}
                </select>
              </label>
            </div>
            <div className="avatar-powers-row" style={{ marginTop: 10 }}>
              <label className="level-settings-field">
                <span className="level-settings-field-label">Featured Rare</span>
                <select value={rareId} onChange={e => setRareId(e.target.value)}>
                  <option value="">— None —</option>
                  {allRares.map(a => <option key={a.id} value={a.id}>{a.name}</option>)}
                </select>
              </label>
            </div>

            <div style={{ marginTop: 14, borderTop: "1px solid var(--border)", paddingTop: 12 }}>
              <span className="level-settings-field-label" style={{ display: "block", marginBottom: 8 }}>Banner art</span>

              {/* Desktop 16:9 */}
              <div style={{ marginBottom: 12 }}>
                <span className="level-settings-field-label">Desktop — 16:9 (fallback: /banners/hearthbound-desktop.png)</span>
                {artDesktop && (
                  <img src={artDesktop} alt="Desktop preview" style={{ display: "block", width: "100%", maxHeight: 120, objectFit: "cover", borderRadius: 8, marginTop: 6, border: "1px solid var(--border)" }} />
                )}
                <div style={{ display: "flex", gap: 8, alignItems: "center", marginTop: 6, flexWrap: "wrap" }}>
                  <label style={{ cursor: "pointer" }}>
                    <input type="file" accept="image/*" onChange={e => handleArtUpload("desktop", e)} disabled={!!artUploading} style={{ display: "none" }} />
                    <span className="btn-secondary" style={{ pointerEvents: "none" }}>
                      {artUploading === "desktop" ? "Uploading…" : "Upload Desktop"}
                    </span>
                  </label>
                </div>
                <input type="url" placeholder="…or paste URL" value={artDesktop}
                  onChange={e => { setArtDesktop(e.target.value); setArtError(""); }}
                  style={{ marginTop: 6, width: "100%", boxSizing: "border-box" }} />
                {artDesktop && (
                  <button type="button" className="delete-btn" style={{ marginTop: 4, fontSize: "0.75rem", padding: "2px 8px" }} onClick={() => setArtDesktop("")}>
                    Remove
                  </button>
                )}
              </div>

              {/* Mobile landscape */}
              <div style={{ marginBottom: 12 }}>
                <span className="level-settings-field-label">Mobile landscape (fallback: /banners/hearthbound-mobile.png)</span>
                {artMobile && (
                  <img src={artMobile} alt="Mobile preview" style={{ display: "block", width: "100%", maxHeight: 120, objectFit: "cover", borderRadius: 8, marginTop: 6, border: "1px solid var(--border)" }} />
                )}
                <div style={{ display: "flex", gap: 8, alignItems: "center", marginTop: 6, flexWrap: "wrap" }}>
                  <label style={{ cursor: "pointer" }}>
                    <input type="file" accept="image/*" onChange={e => handleArtUpload("mobile", e)} disabled={!!artUploading} style={{ display: "none" }} />
                    <span className="btn-secondary" style={{ pointerEvents: "none" }}>
                      {artUploading === "mobile" ? "Uploading…" : "Upload Mobile landscape"}
                    </span>
                  </label>
                </div>
                <input type="url" placeholder="…or paste URL" value={artMobile}
                  onChange={e => { setArtMobile(e.target.value); setArtError(""); }}
                  style={{ marginTop: 6, width: "100%", boxSizing: "border-box" }} />
                {artMobile && (
                  <button type="button" className="delete-btn" style={{ marginTop: 4, fontSize: "0.75rem", padding: "2px 8px" }} onClick={() => setArtMobile("")}>
                    Remove
                  </button>
                )}
              </div>

              {/* Portrait 9:16 */}
              <div style={{ marginBottom: 4 }}>
                <span className="level-settings-field-label">Portrait 9:16 (fallback: /banners/hearthbound-portrait.png)</span>
                {artPortrait && (
                  <img src={artPortrait} alt="Portrait preview" style={{ display: "block", maxWidth: 120, maxHeight: 200, objectFit: "cover", borderRadius: 8, marginTop: 6, border: "1px solid var(--border)" }} />
                )}
                <div style={{ display: "flex", gap: 8, alignItems: "center", marginTop: 6, flexWrap: "wrap" }}>
                  <label style={{ cursor: "pointer" }}>
                    <input type="file" accept="image/*" onChange={e => handleArtUpload("portrait", e)} disabled={!!artUploading} style={{ display: "none" }} />
                    <span className="btn-secondary" style={{ pointerEvents: "none" }}>
                      {artUploading === "portrait" ? "Uploading…" : "Upload Portrait"}
                    </span>
                  </label>
                </div>
                <input type="url" placeholder="…or paste URL" value={artPortrait}
                  onChange={e => { setArtPortrait(e.target.value); setArtError(""); }}
                  style={{ marginTop: 6, width: "100%", boxSizing: "border-box" }} />
                {artPortrait && (
                  <button type="button" className="delete-btn" style={{ marginTop: 4, fontSize: "0.75rem", padding: "2px 8px" }} onClick={() => setArtPortrait("")}>
                    Remove
                  </button>
                )}
              </div>
              {artError && <div className="stg-msg stg-msg-error" style={{ marginTop: 4 }}>{artError}</div>}
            </div>

            {savedMsg && <StgToast key={savedMsg} msg={savedMsg} />}
            <button className="btn-primary level-settings-save" style={{ marginTop: 14 }} onClick={handleSave} disabled={saving || !!artUploading}>
              {saving ? "Saving…" : "Save"}
            </button>
          </>)}
        </div>
      </div>
    </ModalOverlay>
  );
}

