function EventCountdown({ target, prefix }) {
  const [label, setLabel] = useState("");
  useEffect(() => {
    function tick() {
      const diff = target - Date.now();
      if (diff <= 0) { setLabel("now"); return; }
      const d = Math.floor(diff / 86400000);
      const h = Math.floor((diff % 86400000) / 3600000);
      const m = Math.floor((diff % 3600000) / 60000);
      if (d > 0) setLabel(`${d}d ${h}h`);
      else if (h > 0) setLabel(`${h}h ${m}m`);
      else setLabel(`${m}m`);
    }
    tick();
    const id = setInterval(tick, 60000);
    return () => clearInterval(id);
  }, [target]);
  return <span className="ev-countdown">{prefix} {label}</span>;
}

function EventCalendar({ events, now }) {
  const year  = now.getFullYear();
  const month = now.getMonth();
  const monthStart = new Date(year, month, 1);
  const monthEnd   = new Date(year, month + 1, 0);
  const totalDays  = monthEnd.getDate();
  const monthLabel = now.toLocaleDateString("en-US", { month: "long", year: "numeric" }).toUpperCase();

  const calEvents = events.filter(ev => {
    if (!ev.window) return false;
    return ev.window.end >= monthStart && ev.window.start <= monthEnd;
  });

  // Day 1 + every Sunday + last day of month
  const sundays = [];
  for (let d = 1; d <= totalDays; d++) {
    if (new Date(year, month, d).getDay() === 0) sundays.push(d);
  }
  const ticks = [...new Set([1, ...sundays, totalDays])].sort((a, b) => a - b);

  function barPos(ev) {
    const startClamp = new Date(Math.max(ev.window.start, monthStart));
    const endClamp   = new Date(Math.min(ev.window.end,   monthEnd));
    const startDay = startClamp.getDate() - 1;
    const endDay   = endClamp.getDate();
    const left  = (startDay / totalDays) * 100;
    const width = ((endDay - startDay) / totalDays) * 100;
    return { left: `${left}%`, width: `${Math.max(width, 4)}%` };
  }

  function imgSide(ev) {
    if (ev.calendarImgSide) return ev.calendarImgSide;
    const effectiveStartDay = ev.window.start < monthStart ? 1 : ev.window.start.getDate();
    return effectiveStartDay > 10 ? "left" : "right";
  }

  return (
    <div className="ev-cal">
      {/* Header row */}
      <div className="ev-cal-header">
        <div className="ev-cal-title"><span className="ev-cal-title-icon">📅</span>CALENDAR</div>
        <div className="ev-cal-month">{monthLabel}</div>
      </div>

      {/* Ruler */}
      <div className="ev-cal-ruler">
        {ticks.map(d => (
          <div key={d} className="ev-cal-tick" style={{ left: `${((d - 1) / totalDays) * 100}%` }}>
            <div className="ev-cal-tick-line" />
            <div className="ev-cal-tick-label">{d}</div>
          </div>
        ))}
      </div>

      {/* Body: today marker + bars */}
      <div className="ev-cal-body">
        <div className="ev-cal-today-marker" style={{ left: `${((now.getDate() - 1) / totalDays) * 100}%` }} />
        <div className="ev-cal-bars">
          {calEvents.length === 0 && (
            <div className="ev-cal-empty">No events this month</div>
          )}
          {calEvents.map(ev => {
            const side = imgSide(ev);
            const pos  = barPos(ev);
            const bg   = ev.calendarGradient || ev.color;
            const border = ev.calendarBorder ? `1px solid ${ev.calendarBorder}` : undefined;
            const nameLeft  = side === "left" ? "20px" : "8px";
            const nameRight = side === "right" ? "2px"  : "8px";
            return (
              <div key={ev.id} className="ev-cal-bar-track">
                <div className="ev-cal-bar" style={{ ...pos, background: bg, border }}>
                  {ev.calendarImg && (
                    <img src={ev.calendarImg} alt="" className={`ev-cal-bar-img ev-cal-bar-img--${side}`} />
                  )}
                  {!ev.calendarImg && (
                    <span className={`ev-cal-bar-icon ev-cal-bar-icon--${side}`}>{ev.icon}</span>
                  )}
                  <span className="ev-cal-bar-name" style={{ left: nameLeft, right: nameRight }}>{ev.name}</span>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}

const EV_CATEGORY_COLORS = {
  ECONOMY: "#D4AF37", GACHA: "#E8557A", LEARNING: "#4CAF8A", COMMUNITY: "#5B8DD9",
};

function EventCard({ ev, teacher, uploading, uploadError, onToggleForce, onBannerUpload }) {
  const now = Date.now();
  const isActive = ev.window && now >= ev.window.start && now <= ev.window.end;
  const art = ev.bannerArt;
  const [showManageBanner, setShowManageBanner] = useState(false);
  const [showPopup, setShowPopup] = useState(false);
  const bannerSrc = art?.h || art?.v || null;
  const popupSrc = art?.v || art?.h || null;
  const catColor = ev.category ? (EV_CATEGORY_COLORS[ev.category] || ev.color) : ev.color;

  return (
    <div className="ev-card" style={{ "--ev-color": ev.color, "--ev-cat-color": catColor }}
      onClick={() => { if (popupSrc) setShowPopup(true); }}>
      <div className="ev-card-art">
        {bannerSrc
          ? <img src={bannerSrc} alt={ev.name} className="ev-banner-img" />
          : <div className="ev-card-art-placeholder"><span>{ev.icon}</span></div>
        }
        {ev.category && (
          <div className="ev-cat-badge" style={{ background: catColor }}>{ev.category}</div>
        )}
      </div>
      <div className="ev-card-body">
        <div className="ev-card-name">{ev.name}</div>
        <div className="ev-card-subtitle">{ev.subtitle}</div>
        {ev.window && (
          <div className="ev-card-countdown">
            <span className="ev-countdown-icon">📅</span>
            {isActive
              ? <EventCountdown target={ev.window.end.getTime()} prefix="Ends in" />
              : <EventCountdown target={ev.window.start.getTime()} prefix="Starts in" />
            }
          </div>
        )}
        {teacher && (
          <div className="ev-teacher-controls" onClick={e => e.stopPropagation()}>
            <label className="ev-force-row">
              <input type="checkbox" checked={!!ev.forceVisible} onChange={() => onToggleForce(ev)} />
              <span>Force visible before 30-day window</span>
            </label>
            <div className="ev-art-row">
              <div className="ev-art-field">
                <span className="level-settings-field-label">Banner H (16:9)</span>
                {art?.h && <img src={art.h} alt="" className="ev-art-preview ev-art-preview-h" />}
                <label className="lp-upload-btn">
                  <input type="file" accept="image/*" style={{ display: "none" }}
                    onChange={e => { onBannerUpload(ev, "h", e.target.files?.[0]); e.target.value = ""; }}
                    disabled={!!uploading[`${ev.id}-h`]} />
                  {uploading[`${ev.id}-h`] ? "Uploading…" : (art?.h ? "Replace H" : "Upload H")}
                </label>
              </div>
              <div className="ev-art-field">
                <span className="level-settings-field-label">Banner V (9:16)</span>
                {art?.v && <img src={art.v} alt="" className="ev-art-preview ev-art-preview-v" />}
                <label className="lp-upload-btn">
                  <input type="file" accept="image/*" style={{ display: "none" }}
                    onChange={e => { onBannerUpload(ev, "v", e.target.files?.[0]); e.target.value = ""; }}
                    disabled={!!uploading[`${ev.id}-v`]} />
                  {uploading[`${ev.id}-v`] ? "Uploading…" : (art?.v ? "Replace V" : "Upload V")}
                </label>
              </div>
            </div>
            {uploadError[ev.id] && <div className="stg-msg stg-msg-error">{uploadError[ev.id]}</div>}
            {ev.useLegacyBannerArt && ev.bannerKey && (
              <button className="lp-upload-btn" style={{ marginTop: 8 }} onClick={() => setShowManageBanner(true)}>
                Manage Featured Cats →
              </button>
            )}
          </div>
        )}
      </div>
      {showManageBanner && (
        <ManageBannerModal initialBannerKey={ev.bannerKey} onClose={() => setShowManageBanner(false)} />
      )}
      {showPopup && popupSrc && (
        <div className="ev-banner-popup-overlay" onClick={e => { e.stopPropagation(); setShowPopup(false); }}>
          <button className="ev-banner-popup-close" onClick={() => setShowPopup(false)}>✕</button>
          <img src={popupSrc} alt={ev.name} className="ev-banner-popup-img" onClick={e => e.stopPropagation()} />
        </div>
      )}
    </div>
  );
}

function EventsScreen({ profile, pathStats = {}, dawnTickets = 0, onGoToStore }) {
  const teacher = isTeacher(profile);
  const [events, setEvents] = useState([]);
  const [loading, setLoading] = useState(true);
  const [uploading, setUploading] = useState({});
  const [uploadError, setUploadError] = useState({});

  useEffect(() => { loadEvents(); }, []);

  async function loadEvents() {
    const now = new Date();
    const registry = getEventsRegistry(now);
    const enriched = await Promise.all(registry.map(async (ev) => {
      const forceVisible = teacher
        ? ((await storageGet(EVENT_FORCE_KEY(ev.id), true)) || false)
        : false;
      let bannerArt = { h: null, v: null };
      if (ev.useLegacyBannerArt && ev.bannerKey) {
        const art = await getBannerArtOriented(ev.bannerKey);
        bannerArt = { h: art.horizontal || art.legacy || null, v: art.vertical || null };
      } else {
        const stableKey = ev.recurringBannerKey;
        const [h, v, hFallback, vFallback] = await Promise.all([
          stableKey ? storageGet(EVENT_BANNER_H_KEY(stableKey), true) : Promise.resolve(null),
          stableKey ? storageGet(EVENT_BANNER_V_KEY(stableKey), true) : Promise.resolve(null),
          storageGet(EVENT_BANNER_H_KEY(ev.id), true),
          storageGet(EVENT_BANNER_V_KEY(ev.id), true),
        ]);
        bannerArt = { h: h || hFallback || null, v: v || vFallback || null };
      }
      return { ...ev, forceVisible, bannerArt };
    }));
    setEvents(enriched);
    setLoading(false);
  }

  async function handleToggleForce(ev) {
    const next = !ev.forceVisible;
    await storageSet(EVENT_FORCE_KEY(ev.id), next, true);
    setEvents(evs => evs.map(e => e.id === ev.id ? { ...e, forceVisible: next } : e));
  }

  async function handleBannerUpload(ev, orientation, file) {
    if (!file) return;
    const key = `${ev.id}-${orientation}`;
    setUploading(u => ({ ...u, [key]: true }));
    setUploadError(u => ({ ...u, [ev.id]: "" }));
    try {
      const url = await storageUpload(file, "cat-avatars", `event-${ev.id}-${orientation}-`);
      if (ev.useLegacyBannerArt && ev.bannerKey) {
        const cur = await getBannerArtOriented(ev.bannerKey);
        await setBannerArtOriented(ev.bannerKey, {
          horizontal: orientation === "h" ? url : (cur.horizontal || cur.legacy || null),
          vertical:   orientation === "v" ? url : (cur.vertical || null),
        });
      } else {
        const saveKey = ev.recurringBannerKey
          ? (orientation === "h" ? EVENT_BANNER_H_KEY(ev.recurringBannerKey) : EVENT_BANNER_V_KEY(ev.recurringBannerKey))
          : (orientation === "h" ? EVENT_BANNER_H_KEY(ev.id) : EVENT_BANNER_V_KEY(ev.id));
        await storageSet(saveKey, url, true);
      }
      setEvents(evs => evs.map(e => e.id === ev.id
        ? { ...e, bannerArt: { ...e.bannerArt, [orientation]: url } }
        : e
      ));
    } catch (err) {
      setUploadError(u => ({ ...u, [ev.id]: err.message || "Upload failed." }));
    } finally {
      setUploading(u => ({ ...u, [key]: false }));
    }
  }

  const [carouselIdx, setCarouselIdx] = useState(0);
  const [carouselPopupSrc, setCarouselPopupSrc] = useState(null);
  const evTouchStartX = useRef(null);
  // ev-carousel auto-play — useEffect aqui (fora de qualquer condicional) para cumprir Rules of Hooks
  const [carouselLen, setCarouselLen] = useState(0);
  useEffect(() => {
    if (carouselLen <= 1) return;
    const t = setTimeout(() => setCarouselIdx(v => (v + 1) % carouselLen), 10000);
    return () => clearTimeout(t);
  }, [carouselIdx, carouselLen]);

  if (loading) return <div className="ev-loading">Loading events…</div>;

  const now = new Date();
  const active = events
    .filter(ev => ev.window && now >= ev.window.start && now <= ev.window.end)
    .sort((a, b) => a.window.end - b.window.end);

  const upcoming = events
    .filter(ev => {
      if (!ev.window || now >= ev.window.start) return false;
      if (teacher) return true;
      const daysUntil = (ev.window.start - now) / 86400000;
      if (daysUntil > 30) return ev.forceVisible;
      return ev.forceVisible || !ev.useLegacyBannerArt || (ev.bannerArt?.h || ev.bannerArt?.v);
    })
    .sort((a, b) => a.window.start - b.window.start);

  const RECURRING_EVENTS = [
    { icon: "📝", name: "Sunday Test", freq: "Every Sunday" },
    { icon: "✨", name: "Golden Abundance", freq: "Monthly" },
    { icon: "📖", name: "Cat of the Month", freq: "Monthly" },
    { icon: "🎫", name: "Solstice Ticket", freq: "Special Event" },
  ];

  const tabEvents = [...active, ...upcoming];
  const sharedCardProps = { teacher, uploading, uploadError, onToggleForce: handleToggleForce, onBannerUpload: handleBannerUpload };

  // #718 — Hearthbound virtual event for carousel + calendar
  const hearthboundActive = isHearthboundBannerActive(pathStats, dawnTickets);
  const HB_EVENT = hearthboundActive ? {
    id: "__hearthbound__",
    name: "Hearthbound",
    subtitle: "Welcome event for new students",
    icon: "🌅",
    window: { start: new Date(now.getFullYear(), now.getMonth(), 1), end: new Date(now.getFullYear(), now.getMonth() + 1, 0) },
    bannerArt: { h: "/banners/hearthbound-desktop.png", v: "/banners/hearthbound-portrait.png" },
    calendarGradient: "linear-gradient(90deg, #301637, #4F963C)",
    calendarBorder: "#2C5421",
    calendarImgSide: "right",
    calendarImg: GACHA_TICKET_CATALOG.dawn.image,
  } : null;

  // Carrossel mobile: eventos ativos com banner; fallback = upcoming mais próximo
  const carouselItems = active.filter(ev => ev.bannerArt?.h || ev.bannerArt?.v);
  const carouselFallback = carouselItems.length === 0 && upcoming.length > 0 ? [upcoming[0]] : [];
  const baseCarouselSlides = carouselItems.length > 0 ? carouselItems : carouselFallback;
  const carouselSlides = HB_EVENT ? [HB_EVENT, ...baseCarouselSlides] : baseCarouselSlides;
  const isFallback = carouselItems.length === 0 && carouselFallback.length > 0;
  const safeIdx = Math.min(carouselIdx, Math.max(carouselSlides.length - 1, 0));
  // sync length para o useEffect de auto-play (sem chamar hook condicionalmente)
  if (carouselLen !== carouselSlides.length) setCarouselLen(carouselSlides.length);

  return (
    <div className="ev-screen">
      {/* ── Page header ── */}
      <div className="ev-page-header">
        <div className="ev-page-title-row">
          <h1 className="ev-page-title">✦ <span className="sch-title-big">E</span>VENTS ✦</h1>
        </div>
        <p className="ev-page-sub">Exciting events, amazing rewards.</p>
      </div>

      {/* ── Calendar ── */}
      <EventCalendar events={HB_EVENT ? [HB_EVENT, ...events] : events} now={now} />

      {/* ── Carrossel mobile ── */}
      {carouselSlides.length > 0 && (
        <div className="ev-carousel"
          onTouchStart={e => { evTouchStartX.current = e.touches[0].clientX; }}
          onTouchEnd={e => {
            const dx = e.changedTouches[0].clientX - evTouchStartX.current;
            if (Math.abs(dx) < 40 || carouselLen <= 1) return;
            if (dx < 0) setCarouselIdx(v => (v + 1) % carouselLen);
            else setCarouselIdx(v => (v - 1 + carouselLen) % carouselLen);
          }}
        >
          {carouselSlides.map((ev, i) => {
            const art = ev.bannerArt;
            const src = art?.h || art?.v || null;
            const popupSrc = art?.v || art?.h || null;
            const isActive = now >= ev.window?.start && now <= ev.window?.end;
            const isWishEvent = ev.id === "__hearthbound__" || !!ev.useLegacyBannerArt;
            const isHearthbound = ev.id === "__hearthbound__";
            const handleClick = () => {
              if (isWishEvent) { onGoToStore?.(); return; }
              if (popupSrc) setCarouselPopupSrc(popupSrc);
            };
            return (
              <div key={ev.id} className={"ev-carousel-slide"+(i === safeIdx ? " ev-carousel-slide--active" : "")}
                onClick={handleClick} style={{ cursor: (isWishEvent || popupSrc) ? "pointer" : "default" }}>
                {src
                  ? <img src={src} alt={ev.name} className="ev-carousel-img" />
                  : <div className="ev-carousel-placeholder"><span>{ev.icon}</span></div>
                }
                <div className="ev-carousel-overlay">
                  {isFallback && !isActive && (
                    <div className="ev-carousel-coming-pill">
                      Coming Next: <EventCountdown target={ev.window.start.getTime()} prefix="" />
                    </div>
                  )}
                  <div className="ev-carousel-name">{ev.name}</div>
                  <div className="ev-carousel-sub">{ev.subtitle}</div>
                  {ev.window && (
                    <div className="ev-carousel-meta">
                      <span className="ev-carousel-dates">
                        {isHearthbound
                          ? "Limited for Beginner's account"
                          : `${ev.window.start.toLocaleDateString("en-US",{month:"short",day:"numeric"})} – ${ev.window.end.toLocaleDateString("en-US",{month:"short",day:"numeric",year:"numeric"})}`}
                      </span>
                      {!isFallback && !isHearthbound && (
                        <span className="ev-carousel-countdown">
                          <EventCountdown target={isActive ? ev.window.end.getTime() : ev.window.start.getTime()} prefix={isActive ? "Ends in" : "Starts in"} />
                        </span>
                      )}
                    </div>
                  )}
                </div>
              </div>
            );
          })}
          {carouselSlides.length > 1 && (
            <div className="ev-carousel-dots">
              {carouselSlides.map((_, i) => (
                <button key={i} className={"ev-carousel-dot"+(i === safeIdx ? " ev-carousel-dot--active" : "")} onClick={e => { e.stopPropagation(); setCarouselIdx(i); }} />
              ))}
            </div>
          )}
        </div>
      )}
      {carouselPopupSrc && (
        <div className="ev-banner-popup" onClick={() => setCarouselPopupSrc(null)}>
          <img src={carouselPopupSrc} alt="" className="ev-banner-popup-img" onClick={e => e.stopPropagation()} />
        </div>
      )}

      {/* ── Main layout: content + sidebar ── */}
      <div className="ev-layout">
        <div className="ev-main">
          {/* Cards grid */}
          {tabEvents.length > 0 ? (
            <div className="ev-grid">
              {tabEvents.map(ev => (
                <EventCard key={ev.id} ev={ev} {...sharedCardProps} />
              ))}
            </div>
          ) : (
            <div className="ev-empty">
              <span className="ev-empty-icon">🌙</span>
              <p>No events right now.</p>
              <p className="ev-empty-sub">Check back soon!</p>
              {teacher && (
                <p className="ev-teacher-hint">Upload a banner and/or enable "Force visible" to show an event here.</p>
              )}
            </div>
          )}
        </div>

        {/* ── Sidebar ── */}
        <aside className="ev-sidebar">
          {teacher && <HearthboundTeacherWidget />}
        </aside>
      </div>
    </div>
  );
}

function HearthboundTeacherWidget() {
  const [showModal, setShowModal] = useState(false);
  return (
    <div className="hb-teacher-widget">
      <div className="hb-teacher-widget-title">🌅 Hearthbound</div>
      <p className="hb-teacher-widget-sub">Dawn Ticket event for new students (Section 0).</p>
      <button className="lp-upload-btn" onClick={() => setShowModal(true)}>Manage Featured Cats →</button>
      {showModal && <ManageHearthboundModal onClose={() => setShowModal(false)} />}
    </div>
  );
}

function ManageCatsModal({ onClose }) {
  const [cats, setCats]         = useState([]);
  const [loading, setLoading]   = useState(true);
  const [editingId, setEditingId] = useState(null); // null = "creating new"
  const [form, setForm]         = useState(EMPTY_CAT_FORM);
  const [error, setError]       = useState("");
  const [busy, setBusy]         = useState(false);
  // Issue #366 — upload a cat image straight from the teacher's computer
  // instead of requiring an already-hosted URL. Goes to a public Supabase
  // Storage bucket ("cat-avatars") via the same client/session already used
  // for everything else in this app — no new secret needed. The bucket +
  // its RLS policies must exist first (one-time manual setup, see #366).
  const [uploading, setUploading] = useState(false);

  async function handleFileUpload(e) {
    const file = e.target.files?.[0];
    e.target.value = ""; // allow re-selecting the same file later
    if (!file) return;
    if (!file.type.startsWith("image/")) {
      setError("Please choose an image file.");
      return;
    }
    setUploading(true);
    setError("");
    try {
      const publicUrl = await storageUpload(file, "cat-avatars");
      setForm((f) => ({ ...f, image: publicUrl }));
    } catch (err) {
      setError(err.message || "Upload failed.");
    } finally {
      setUploading(false);
    }
  }

  async function reload() {
    setCats(await getCustomAvatars());
  }
  useEffect(() => { reload().finally(() => setLoading(false)); }, []);

  function startCreate() {
    setEditingId(null);
    setForm(EMPTY_CAT_FORM);
    setError("");
  }
  function startEdit(cat) {
    setEditingId(cat.id);
    setForm({
      name: cat.name,
      image: cat.image,
      rarity: cat.rarity,
      category: cat.shopExclusive ? "shop" : cat.monthlyExclusive ? "monthly" : "prize",
      price: cat.price ?? "",
      monthKey: cat.monthKey ?? "",
      lockedUntilMonthKey: cat.lockedUntilMonthKey ?? "", // Issue #391
    });
    setError("");
  }

  async function handleSave() {
    setError("");
    const payload = {
      name: form.name,
      image: form.image,
      rarity: form.rarity,
      shopExclusive: form.category === "shop",
      monthlyExclusive: form.category === "monthly",
      price: form.category === "shop" ? form.price : undefined,
      monthKey: form.category === "monthly" ? form.monthKey : undefined,
      lockedUntilMonthKey: form.lockedUntilMonthKey || undefined, // Issue #391
    };
    setBusy(true);
    try {
      if (editingId) {
        await updateCustomAvatar(editingId, payload);
      } else {
        await addCustomAvatar(payload);
      }
      await reload();
      startCreate(); // reset form back to "create new" after a successful save
    } catch (e) {
      setError(e.message || "Something went wrong.");
    } finally {
      setBusy(false);
    }
  }

  async function handleRemove(id) {
    if (!window.confirm("Remove this cat? Students who already own it keep it in their collection, but it stops showing up anywhere new.")) return;
    setBusy(true);
    try {
      await removeCustomAvatar(id);
      await reload();
      if (editingId === id) startCreate();
    } finally {
      setBusy(false);
    }
  }

  return (
    <ModalOverlay onClose={onClose}>
      <div className="modal-card avatar-powers-modal" onClick={(e) => e.stopPropagation()}>
        <div className="modal-head">
          <h2>Manage Cats</h2>
          <button className="icon-btn" onClick={onClose}>
            <X size={16} />
          </button>
        </div>
        <div className="modal-body">
          <p className="release-modal-hint">
            Add a new cat with an image URL, pick its rarity and where it's obtainable — no deploy
            needed. Only cats created here (not the built-in ones) can be edited or removed.
          </p>

          <div className="avatar-powers-group">
            <div className="avatar-powers-group-title">{editingId ? "Edit cat" : "New cat"}</div>
            <div className="level-settings-field">
              <span className="level-settings-field-label">Name</span>
              <input
                type="text" value={form.name} placeholder="e.g. Meow Somchai"
                onChange={(e) => setForm((f) => ({ ...f, name: e.target.value }))}
              />
            </div>
            <div className="level-settings-field">
              <span className="level-settings-field-label">Image</span>
              <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                {form.image && (
                  <img
                    src={form.image} alt="" className="avatar-powers-thumb"
                    onError={(e) => { e.currentTarget.style.visibility = "hidden"; }}
                    onLoad={(e) => { e.currentTarget.style.visibility = "visible"; }}
                  />
                )}
                <label className="btn-secondary" style={{ cursor: uploading ? "default" : "pointer", opacity: uploading ? 0.6 : 1 }}>
                  {uploading ? "Uploading…" : "Upload from computer"}
                  <input type="file" accept="image/*" onChange={handleFileUpload} disabled={uploading} style={{ display: "none" }} />
                </label>
              </div>
              <input
                type="text" value={form.image} placeholder="…or paste an image URL"
                onChange={(e) => setForm((f) => ({ ...f, image: e.target.value }))}
                style={{ marginTop: 8 }}
              />
            </div>
            <div className="level-settings-field">
              <span className="level-settings-field-label">Rarity</span>
              <select value={form.rarity} onChange={(e) => setForm((f) => ({ ...f, rarity: e.target.value }))}>
                <option value="common">Common</option>
                <option value="uncommon">Uncommon</option>
                <option value="rare">Rare</option>
                <option value="epic">Epic</option>
                <option value="legendary">Legendary</option>
              </select>
            </div>
            <div className="level-settings-field">
              <span className="level-settings-field-label">Availability</span>
              <select value={form.category} onChange={(e) => setForm((f) => ({ ...f, category: e.target.value }))}>
                <option value="prize">Prize pool (random unlock)</option>
                <option value="shop">Shop (buy with Meowtongs)</option>
                <option value="monthly">Monthly Challenge (Cat of the Month)</option>
              </select>
            </div>
            {form.category === "shop" && (
              <div className="level-settings-field">
                <span className="level-settings-field-label">Price (Meowtongs)</span>
                <input
                  type="number" min="0" value={form.price}
                  onChange={(e) => setForm((f) => ({ ...f, price: e.target.value }))}
                />
              </div>
            )}
            {form.category === "monthly" && (
              <div className="level-settings-field">
                <span className="level-settings-field-label">Month</span>
                <input
                  type="month" value={form.monthKey}
                  onChange={(e) => setForm((f) => ({ ...f, monthKey: e.target.value }))}
                />
                {/* Issue #351.1 — preview of which Solstice Banner this cat auto-features in (M+2 rule, corrected 2026-07-09), no separate banner-picker screen needed. */}
                {form.monthKey && (
                  <div className="mancat-banner-preview">
                    {(() => {
                      const bannerKey = getFeaturedBannerKeyForMonthCat(form.monthKey);
                      return isBannerLaunched(bannerKey)
                        ? `✨ Will be the featured Legendary in the ${bannerKey} Solstice Banner.`
                        : `Solstice Banners start with 2026-08 — this cat won't be a banner feature yet.`;
                    })()}
                  </div>
                )}
              </div>
            )}
            {/* Issue #391 — optional debut lock, independent of Availability:
                Don Thong/Kila Meowter (shopExclusive: false) already use this
                to stay out of the draw pool until 2 months after their
                banner closes (isAvatarLocked/getAvatarsByRarity), so this
                isn't tied to any one category. */}
            <div className="level-settings-field">
              <span className="level-settings-field-label">Locked until (optional)</span>
              <input
                type="month" value={form.lockedUntilMonthKey}
                onChange={(e) => setForm((f) => ({ ...f, lockedUntilMonthKey: e.target.value }))}
              />
              <div className="release-modal-hint">
                Hides this cat from ticket/banner draw pools (and the Shop, if applicable) until this month starts.
                Leave blank to make it available right away.
              </div>
            </div>
            {error && (
              <div className="release-modal-hint" style={{ color: "var(--danger, #c0392b)" }}>
                {error}
              </div>
            )}
            <div style={{ display: "flex", gap: 8 }}>
              <button className="btn-primary level-settings-save" onClick={handleSave} disabled={busy}>
                {editingId ? "Save changes" : "Create cat"}
              </button>
              {editingId && (
                <button className="btn-secondary" onClick={startCreate} disabled={busy}>
                  Cancel edit
                </button>
              )}
            </div>
          </div>

          <div className="avatar-powers-group">
            <div className="avatar-powers-group-title">Your custom cats</div>
            {loading && <div className="release-modal-hint">Loading…</div>}
            {!loading && cats.length === 0 && (
              <div className="release-modal-hint">No custom cats yet — create one above.</div>
            )}
            {cats.map((cat) => (
              <div key={cat.id} className="avatar-powers-row">
                <div className="avatar-powers-avatar">
                  <img src={cat.image} alt={cat.name} className="avatar-powers-thumb" />
                  <div>
                    <div className="avatar-powers-name">{cat.name}</div>
                    <div className="avatar-powers-rarity">
                      {RARITY_LABEL[cat.rarity] || cat.rarity}
                      {" · "}
                      {cat.shopExclusive ? `Shop (${getAvatarPrice(cat, {})})` : cat.monthlyExclusive ? `Monthly (${cat.monthKey})` : "Prize pool"}
                      {/* Issue #391 — surface the lock in the teacher-facing list too, not just the edit form */}
                      {cat.lockedUntilMonthKey && (isAvatarLocked(cat) ? ` · 🔒 locked until ${cat.lockedUntilMonthKey}` : ` · unlocked since ${cat.lockedUntilMonthKey}`)}
                    </div>
                  </div>
                </div>
                <div style={{ display: "flex", gap: 8 }}>
                  <button className="icon-btn" onClick={() => startEdit(cat)} disabled={busy} title="Edit">
                    <Pencil size={16} />
                  </button>
                  <button className="icon-btn" onClick={() => handleRemove(cat.id)} disabled={busy} title="Remove">
                    <Trash2 size={16} />
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </ModalOverlay>
  );
}

// Issue #234 — teacher can override the suggested Meowtongs reward for any
// achievement. The "suggestion" is just the difficulty-scaled `value` each
// achievement already ships with (#231) — shown as a placeholder/current
// value, editable at any time, never a hard lock.
function AchievementRewardsModal({ overrides, onClose, onSave }) {
  const [values, setValues] = useState(() => {
    const init = {};
    ACHIEVEMENTS.forEach((a) => { init[a.id] = String(getAchievementValue(a, overrides)); });
    return init;
  });
  const [busy, setBusy] = useState(false);

  function handleChange(id, v) {
    setValues((prev) => ({ ...prev, [id]: v }));
  }
  function handleReset(id, defaultValue) {
    setValues((prev) => ({ ...prev, [id]: String(defaultValue) }));
  }
  async function handleSave() {
    setBusy(true);
    try {
      const next = {};
      ACHIEVEMENTS.forEach((a) => {
        const n = Number(values[a.id]);
        if (Number.isFinite(n) && n >= 0 && n !== (a.value || 0)) next[a.id] = n;
      });
      await onSave(next);
    } finally {
      setBusy(false);
    }
  }

  const cats = Object.keys(ACH_CAT_LABELS).filter((c) => ACHIEVEMENTS.some((a) => a.cat === c));

  return (
    <ModalOverlay onClose={onClose}>
      <div className="modal-card avatar-powers-modal" onClick={(e) => e.stopPropagation()}>
        <div className="modal-head">
          <h2>Achievement Rewards</h2>
          <button className="icon-btn" onClick={onClose}>
            <X size={16} />
          </button>
        </div>
        <div className="modal-body">
          <p className="release-modal-hint">
            Each achievement suggests a Meowtongs reward scaled by difficulty — override any
            value below. Secret achievements are included (their titles stay hidden from
            students until unlocked, this screen is teacher-only).
          </p>
          {cats.map((catKey) => (
            <div className="avatar-powers-group" key={catKey}>
              <div className="avatar-powers-group-title">{ACH_CAT_LABELS[catKey]}</div>
              {ACHIEVEMENTS.filter((a) => a.cat === catKey).map((a) => (
                <div key={a.id} className="avatar-powers-row">
                  <div className="avatar-powers-avatar">
                    <div>
                      <div className="avatar-powers-name">{a.emoji} {a.title}</div>
                      <div className="avatar-powers-rarity">{a.desc} · suggested {a.value || 0}</div>
                    </div>
                  </div>
                  <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
                    <input
                      type="number" min="0" style={{ width: 80 }}
                      value={values[a.id]}
                      onChange={(e) => handleChange(a.id, e.target.value)}
                    />
                    {Number(values[a.id]) !== (a.value || 0) && (
                      <button className="icon-btn" title="Reset to suggested" onClick={() => handleReset(a.id, a.value || 0)}>
                        <RotateCcw size={14} />
                      </button>
                    )}
                  </div>
                </div>
              ))}
            </div>
          ))}
          <button className="btn-primary level-settings-save" onClick={handleSave} disabled={busy}>
            Save changes
          </button>
        </div>
      </div>
    </ModalOverlay>
  );
}

// Issue #235 — teacher creates weekly/monthly challenges from the criterion
// types the engine already supports, instead of a free-form condition. Same
// data-then-UI split as Manage Cats (#227/#228): validateCustomChallengeData
// throws teacher-facing messages this form just surfaces.
function ManageChallengesModal({ onClose }) {
  const [kind, setKind] = useState("weekly");
  const [store, setStore] = useState({ weekly: [], monthly: [] });
  const [loading, setLoading] = useState(true);
  const [title, setTitle] = useState("");
  const [criterion, setCriterion] = useState("");
  const [threshold, setThreshold] = useState("");
  const [error, setError] = useState("");
  const [busy, setBusy] = useState(false);

  async function reload() {
    setStore(await getCustomChallenges());
  }
  useEffect(() => { reload().finally(() => setLoading(false)); }, []);

  const criteriaOptions = kind === "weekly" ? WEEKLY_CRITERIA : MONTHLY_CRITERIA;

  function resetForm() {
    setTitle(""); setCriterion(""); setThreshold(""); setError("");
  }

  async function handleCreate() {
    setError("");
    setBusy(true);
    try {
      await addCustomChallenge(kind, { title, criterion, threshold });
      await reload();
      resetForm();
    } catch (e) {
      setError(e.message || "Something went wrong.");
    } finally {
      setBusy(false);
    }
  }

  async function handleRemove(k, id) {
    if (!window.confirm("Remove this challenge? It stops appearing in future weeks/months — students who already completed it keep the reward they earned.")) return;
    setBusy(true);
    try {
      await removeCustomChallenge(k, id);
      await reload();
    } finally {
      setBusy(false);
    }
  }

  return (
    <ModalOverlay onClose={onClose}>
      <div className="modal-card avatar-powers-modal" onClick={(e) => e.stopPropagation()}>
        <div className="modal-head">
          <h2>Manage Challenges</h2>
          <button className="icon-btn" onClick={onClose}>
            <X size={16} />
          </button>
        </div>
        <div className="modal-body">
          <p className="release-modal-hint">
            Create weekly or monthly challenges from the criteria the app already tracks — no
            deploy needed. Duplicate criterion + threshold combos aren't allowed.
          </p>

          <div className="avatar-powers-group">
            <div className="avatar-powers-group-title">New challenge</div>
            <div className="level-settings-field">
              <span className="level-settings-field-label">Type</span>
              <select value={kind} onChange={(e) => { setKind(e.target.value); setCriterion(""); }}>
                <option value="weekly">Weekly Challenge</option>
                <option value="monthly">Monthly Challenge</option>
              </select>
            </div>
            <div className="level-settings-field">
              <span className="level-settings-field-label">Title</span>
              <input
                type="text" value={title} placeholder="e.g. Vocabulary Marathon"
                onChange={(e) => setTitle(e.target.value)}
              />
            </div>
            <div className="level-settings-field">
              <span className="level-settings-field-label">Criterion</span>
              <select value={criterion} onChange={(e) => setCriterion(e.target.value)}>
                <option value="">—</option>
                {criteriaOptions.map((c) => <option key={c.key} value={c.key}>{c.label}</option>)}
              </select>
            </div>
            <div className="level-settings-field">
              <span className="level-settings-field-label">
                Threshold {criteriaOptions.find((c) => c.key === criterion)?.unit ? `(${criteriaOptions.find((c) => c.key === criterion)?.unit})` : ""}
              </span>
              <input
                type="number" min="1" value={threshold}
                onChange={(e) => setThreshold(e.target.value)}
              />
            </div>
            {error && (
              <div className="release-modal-hint" style={{ color: "var(--danger, #c0392b)" }}>
                {error}
              </div>
            )}
            <button className="btn-primary level-settings-save" onClick={handleCreate} disabled={busy || !title || !criterion || !threshold}>
              Create challenge
            </button>
          </div>

          <div className="avatar-powers-group">
            <div className="avatar-powers-group-title">Your custom weekly challenges</div>
            {loading && <div className="release-modal-hint">Loading…</div>}
            {!loading && store.weekly.length === 0 && <div className="release-modal-hint">None yet.</div>}
            {store.weekly.map((c) => (
              <div key={c.id} className="avatar-powers-row">
                <div className="avatar-powers-avatar">
                  <div>
                    <div className="avatar-powers-name">{c.emoji || "🎯"} {c.title}</div>
                    <div className="avatar-powers-rarity">
                      {WEEKLY_CRITERIA.find((w) => w.key === c.criterion)?.label} · {c.threshold}
                    </div>
                  </div>
                </div>
                <button className="icon-btn" onClick={() => handleRemove("weekly", c.id)} disabled={busy} title="Remove">
                  <Trash2 size={16} />
                </button>
              </div>
            ))}
          </div>

          <div className="avatar-powers-group">
            <div className="avatar-powers-group-title">Your custom monthly challenges</div>
            {loading && <div className="release-modal-hint">Loading…</div>}
            {!loading && store.monthly.length === 0 && <div className="release-modal-hint">None yet.</div>}
            {store.monthly.map((c) => (
              <div key={c.id} className="avatar-powers-row">
                <div className="avatar-powers-avatar">
                  <div>
                    <div className="avatar-powers-name">{c.emoji || "🎯"} {c.title}</div>
                    <div className="avatar-powers-rarity">
                      {MONTHLY_CRITERIA.find((m) => m.key === c.criterion)?.label} · {c.threshold}
                    </div>
                  </div>
                </div>
                <button className="icon-btn" onClick={() => handleRemove("monthly", c.id)} disabled={busy} title="Remove">
                  <Trash2 size={16} />
                </button>
              </div>
            ))}
          </div>
        </div>
      </div>
    </ModalOverlay>
  );
}

function StatCard({ label, value, icon: Icon, color }) {
  // Parse hex color to rgba for gradient background
  const hex = color.replace("#", "");
  const r = parseInt(hex.slice(0,2), 16);
  const g = parseInt(hex.slice(2,4), 16);
  const b = parseInt(hex.slice(4,6), 16);
  const bg = `linear-gradient(135deg, rgba(${r},${g},${b},0.55) 0%, rgba(${r},${g},${b},0.18) 100%)`;
  return (
    <div className="stat-card" style={{ background: bg, "--stat-color": color }} role="status" aria-label={`${label}: ${value}`}>
      <div className="stat-card-icon-col">
        <Icon size={28} aria-hidden="true" className="stat-card-icon" />
      </div>
      <div className="stat-card-data-col">
        <div className="stat-value">{value}</div>
        <div className="stat-label">{label}</div>
      </div>
    </div>
  );
}

// ---------------------------------------------------------------------------
// Word bank
// ---------------------------------------------------------------------------
// Issue #106 — Word bank pagination (batches of 15/20/25 instead of infinite scroll)
const WORD_BANK_PAGE_SIZE_KEY = "wordbank-page-size";
const WORD_BANK_PAGE_SIZES = [15, 20, 25];
const WORD_BANK_DEFAULT_PAGE_SIZE = 20;

function WordBankScreen({ words, wordsLoaded, profile, allCategories, onAdd, onEdit, onImport }) {
  const thaiFont = thaiFontForLevel(profile?.level);
  // onAdd / onEdit / onImport are null for students (teacher-only)
  const [query, setQuery] = useState("");
  const [categoryFilter, setCategoryFilter] = useState("all");
  const [showExportMenu, setShowExportMenu] = useState(false); // Issue #53 — export CSV/JSON
  const [pageSize, setPageSize] = useState(() => {
    const stored = Number(localStorage.getItem(WORD_BANK_PAGE_SIZE_KEY));
    return WORD_BANK_PAGE_SIZES.includes(stored) ? stored : WORD_BANK_DEFAULT_PAGE_SIZE;
  });
  const [page, setPage] = useState(1);

  const filtered = useMemo(() => {
    return words
      .filter((w) => {
        if (categoryFilter !== "all" && w.category !== categoryFilter) return false;
        if (query.trim()) {
          const q = query.trim().toLowerCase();
          return w.thai.includes(query.trim()) || w.english.toLowerCase().includes(q) || w.romanization.toLowerCase().includes(q);
        }
        return true;
      })
      .sort((a, b) => b.addedAt - a.addedAt);
  }, [words, categoryFilter, query]);

  // Reset to page 1 whenever the result set or page size changes, so the
  // teacher never lands on a stale/out-of-range page after filtering.
  useEffect(() => {
    setPage(1);
  }, [categoryFilter, query, pageSize]);

  const pageCount = Math.max(1, Math.ceil(filtered.length / pageSize));
  const safePage = Math.min(page, pageCount);
  const pageItems = useMemo(
    () => filtered.slice((safePage - 1) * pageSize, safePage * pageSize),
    [filtered, safePage, pageSize]
  );

  function handlePageSizeChange(size) {
    setPageSize(size);
    try { localStorage.setItem(WORD_BANK_PAGE_SIZE_KEY, String(size)); } catch (e) {}
  }

  return (
    <div className="screen-pad">
      <div className="bank-head-row">
        <h1 className="page-title small">Word bank</h1>
        {onAdd && (
          <div className="bank-head-btns">
            <div className="export-menu-wrap">
              <button className="export-fab" onClick={() => setShowExportMenu((v) => !v)}
                disabled={words.length === 0} title="Backup your word bank">
                ⬇ Export
              </button>
              {showExportMenu && (
                <div className="export-menu">
                  <button onClick={() => { exportWordsAsCSV(words); setShowExportMenu(false); }}>
                    Export as CSV
                  </button>
                  <button onClick={() => { exportWordsAsJSON(words); setShowExportMenu(false); }}>
                    Export as JSON
                  </button>
                </div>
              )}
            </div>
            <button className="import-fab" onClick={onImport}>⤴ Import PPT</button>
            <button className="add-fab" onClick={onAdd}>
              <Plus size={16} /> Add word
            </button>
          </div>
        )}
      </div>

      <div className="search-row">
        <Search size={14} className="search-ic" />
        <input className="search-input" placeholder="Search Thai, romanization, or English…" value={query} onChange={(e) => setQuery(e.target.value)} />
      </div>

      <div className="chip-row scroll">
        <Chip active={categoryFilter === "all"} onClick={() => setCategoryFilter("all")}>All categories</Chip>
        {(allCategories || CATEGORIES).map((c) => ({ ...c, _count: words.filter(w => w.category === c.id).length }))
          .sort((a, b) => b._count - a._count)
          .map((c) => (
          <Chip key={c.id} active={categoryFilter === c.id} color={c.color} onClick={() => setCategoryFilter(c.id)}>
            {c.name}
          </Chip>
        ))}
      </div>

      {!wordsLoaded && <WordBankSkeleton />}

      {wordsLoaded && filtered.length === 0 && (() => {
        const categoryIsEmpty = categoryFilter !== "all" && !words.some(w => w.category === categoryFilter);
        if (words.length === 0) {
          return (
            <EmptyState
              title="No words yet"
              subtitle="Your teacher will prepare them for you"
              image="/mascote-empty-bank.png"
              compact
            />
          );
        }
        if (categoryIsEmpty) {
          return (
            <EmptyState
              title="This category is empty"
              subtitle="No words registered here yet — try another category."
              image="/mascote-empty-category.png"
              compact
            />
          );
        }
        return (
          <EmptyState
            title="Nothing matches"
            subtitle="Try a different search or category filter."
            image="/mascote.png"
            compact
          />
        );
      })()}

      <div className="word-list">
        {pageItems.map((w) => {
          const cat = catById(w.category, allCategories || CATEGORIES);
          return (
            <button
              key={w.id}
              className={"word-row" + (!onEdit ? " read-only" : "")}
              onClick={() => onEdit && onEdit(w)}
              style={{ "--accent": cat?.color || "#888" }}
            >
              <div className="word-row-main">
                <span className="word-thai" style={{ fontFamily: thaiFont }}>{w.emoji && <span className="word-emoji">{w.emoji}</span>}{w.thai}</span>
                <span className="word-ro">{w.romanization}</span>
              </div>
              <div className="word-row-side">
                <span className="word-en">{w.english}</span>
                <span className="word-tags">
                  <span className="tag-pos">{w.pos}</span>
                  {w.classCode && <span className="tag-code">{w.classCode}</span>}
                </span>
              </div>
            </button>
          );
        })}
      </div>

      {wordsLoaded && filtered.length > 0 && (
        <div className="bank-pagination">
          <div className="bank-pagination-size">
            <span>Per page</span>
            {WORD_BANK_PAGE_SIZES.map((size) => (
              <button
                key={size}
                className={"bank-pagination-size-btn" + (pageSize === size ? " active" : "")}
                onClick={() => handlePageSizeChange(size)}
              >
                {size}
              </button>
            ))}
          </div>
          {pageCount > 1 && (
            <div className="bank-pagination-nav">
              <button className="nav-btn" onClick={() => setPage((p) => Math.max(1, p - 1))} disabled={safePage === 1}>
                <ChevronLeft size={16} />
              </button>
              <span className="bank-pagination-label">Page {safePage} of {pageCount}</span>
              <button className="nav-btn" onClick={() => setPage((p) => Math.min(pageCount, p + 1))} disabled={safePage === pageCount}>
                <ChevronRight size={16} />
              </button>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

function Chip({ active, onClick, children, color }) {
  return (
    <button className={"filter-chip" + (active ? " active" : "")} style={color ? { "--chip-color": color } : undefined} onClick={onClick}>
      {children}
    </button>
  );
}

// ---------------------------------------------------------------------------
// Custom dark-themed category dropdown (native <select> popups can't be
// themed cross-browser — they render with the OS default white list, which
// clashes with the app's dark UI. This is a fully custom listbox instead.)
// ---------------------------------------------------------------------------
function CategoryDropdown({ value, options, onChange, className }) {
  const [open, setOpen] = useState(false);
  const rootRef = useRef(null);
  const selected = options.find((o) => o.id === value);

  useEffect(() => {
    function handleOutside(e) {
      if (rootRef.current && !rootRef.current.contains(e.target)) setOpen(false);
    }
    function handleEscape(e) {
      if (e.key === "Escape") setOpen(false);
    }
    document.addEventListener("mousedown", handleOutside);
    document.addEventListener("keydown", handleEscape);
    return () => {
      document.removeEventListener("mousedown", handleOutside);
      document.removeEventListener("keydown", handleEscape);
    };
  }, []);

  return (
    <div className={"cat-dropdown" + (className ? " " + className : "")} ref={rootRef}>
      <button
        type="button"
        className={"cat-dropdown-trigger" + (open ? " open" : "")}
        onClick={() => setOpen((o) => !o)}
      >
        <span>{selected?.name || "Select category"}</span>
        <ChevronDown size={14} className={"cat-dropdown-chevron" + (open ? " open" : "")} />
      </button>
      {open && (
        <div className="cat-dropdown-panel" role="listbox">
          {options.map((o) => (
            <div
              key={o.id}
              role="option"
              aria-selected={o.id === value}
              className={"cat-dropdown-option" + (o.id === value ? " active" : "")}
              onClick={() => { onChange(o.id); setOpen(false); }}
            >
              {o.color && <span className="cat-dropdown-dot" style={{ background: o.color }} />}
              <span>{o.name}</span>
              {o.id === value && <Check size={13} className="cat-dropdown-check" />}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

// ---------------------------------------------------------------------------
// Add / edit word modal
// ---------------------------------------------------------------------------
function AddWordModal({ profile, existing, allCategories: propCats, words = [], classCodes = [], aiConfig, onClose, onSave, onDelete }) {
  const cats = propCats || CATEGORIES;
  const isEdit = !!existing;
  const [thai, setThai] = useState(existing?.thai || "");
  const [romanization, setRomanization] = useState(existing?.romanization || "");
  const [english, setEnglish] = useState(existing?.english || "");
  const [pos, setPos] = useState(existing?.pos || "noun");
  const [category, setCategory] = useState(existing?.category || cats[0].id);

  // verified/visibility removed — all words are shared and auto-verified
  const [emoji, setEmoji] = useState(existing?.emoji || "");

  const [aiState, setAiState] = useState("idle"); // idle | loading | done | error
  const [aiError, setAiError] = useState("");
  const debounceRef = useRef(null);

  // Issue #120 — classCode field (required for save)
  const [classCode, setClassCode] = useState(existing?.classCode || "");
  // Issue #120 — multi-sense split preview (teacher reviews before creating)
  const [splitPreview, setSplitPreview] = useState(null); // { senses: [], skipped: [] }
  const [splitSelected, setSplitSelected] = useState(new Set()); // indices of senses to create
  const [splitSaved, setSplitSaved] = useState(false); // tracks if split cards were created

  // AI Helper (issue #105) — separate state so it doesn't collide with the
  // add-word auto-suggestion flow above.
  const [aiHelperState, setAiHelperState] = useState("idle"); // idle | loading | done | split | error
  const [aiHelperError, setAiHelperError] = useState("");

  const fieldsTouchedManually = useRef(isEdit); // if editing, don't auto-fire AI on mount

  async function runAiSuggestion(word) {
    // AI works without personal keys via server proxy (/api/ai-enrich)
    setAiState("loading");
    setAiError("");
    try {
      const result = await suggestWordDetails(word, aiConfig);
      setRomanization(result.romanization);
      setEnglish(result.english);
      setPos(PARTS_OF_SPEECH.includes(result.pos) ? result.pos : "noun");
      if (result.emoji) setEmoji(result.emoji);
      setAiState("done");
    } catch (e) {
      setAiState("error");
      setAiError(e.message === "NO_KEY"
        ? "No AI keys configured — set them in Cloudflare Pages env vars or add a personal key in Settings."
        : "AI suggestion failed — fill in the fields manually. " + e.message);
    }
  }

  async function runAiHelper() {
    if (!thai.trim()) return;
    setAiHelperState("loading");
    setAiHelperError("");
    setSplitPreview(null);
    setSplitSaved(false);
    try {
      const { senses } = await suggestPosCategoryMulti(
        { thai: thai.trim(), english, romanization },
        cats,
        aiConfig
      );

      // Apply the FIRST sense to the current form (the one being edited)
      const [first, ...rest] = senses;
      if (first.pos) setPos(first.pos);
      if (first.categoryId) setCategory(first.categoryId);
      if (first.english) setEnglish(first.english);
      if (first.emoji) setEmoji(first.emoji);
      // Issue #137 — AI Helper now also verifies/fixes romanization (e.g. recovers a word
      // whose romanization field got corrupted with an emoji during PPT import).
      if (first.romanization) setRomanization(first.romanization);

      // Issue #120 — if the AI detected multiple distinct senses, show a preview
      // for the teacher to review (NOT auto-create). Check for duplicates including
      // synonyms (fuzzy match, same logic as PPT import).
      if (rest.length > 0) {
        const wordsOf = (s) => new Set(
          (s || '').toLowerCase().replace(/[^a-z\s]/g, '').split(/\s+/).filter(Boolean)
        );

        const skipped = [];
        const previewSenses = [];

        for (const sense of rest) {
          const senseEng = (sense.english || '').toLowerCase().trim();
          const sensePos = (sense.pos || '').toLowerCase().trim();
          const sWords = wordsOf(senseEng);

          // Fuzzy duplicate check — same as PPT import's isFuzzyDup
          let isDup = false;
          for (const w of words) {
            if (w.thai.trim() !== thai.trim()) continue;
            const wEng = (w.english || '').toLowerCase().trim();
            const wPos = (w.pos || '').toLowerCase().trim();
            // Exact match
            if (wEng === senseEng) { isDup = true; break; }
            // Same POS + gloss word overlap (synonym check)
            if (wPos === sensePos && wPos) {
              const wWords = wordsOf(wEng);
              const shared = [...sWords].filter(x => wWords.has(x)).length;
              const union = new Set([...sWords, ...wWords]).size || 1;
              if (shared > 0 && shared / union >= 0.2) { isDup = true; break; }
              // Single-word synonyms (e.g. "we" vs "us" — both pronouns, 1 word each)
              if (sWords.size <= 1 && wWords.size <= 1) { isDup = true; break; }
            }
          }

          if (isDup) {
            skipped.push(sense.english);
          } else {
            previewSenses.push(sense);
          }
        }

        if (previewSenses.length > 0) {
          // Show preview — teacher must confirm before cards are created
          setSplitPreview({ senses: previewSenses, skipped });
          setSplitSelected(new Set(previewSenses.map((_, i) => i))); // all selected by default
          setAiHelperState("split");
        } else if (skipped.length > 0) {
          // All remaining senses are duplicates
          setAiHelperState("done");
          setAiHelperError(`AI detected ${skipped.length} other sense${skipped.length > 1 ? 's' : ''} but all already exist: ${skipped.join(', ')}.`);
        } else {
          setAiHelperState("done");
        }
      } else {
        setAiHelperState("done");
      }
    } catch (e) {
      setAiHelperState("error");
      setAiHelperError(e.message === "NO_KEY"
        ? "No AI keys configured — set them in Cloudflare Pages env vars or add a personal key in Settings."
        : "AI Helper failed — pick manually. " + e.message);
    }
  }

  // Issue #120 — create the selected split-sense cards (called by the "Create cards" button)
  async function confirmSplitCreate() {
    if (!splitPreview) return;
    const toCreate = splitPreview.senses.filter((_, i) => splitSelected.has(i));
    for (const sense of toCreate) {
      const newWord = {
        id: newId(),
        emoji: sense.emoji || "\u{1F4DD}",
        thai: thai.trim(),
        romanization: (sense.romanization || romanization).trim(),
        english: sense.english,
        pos: sense.pos || "noun",
        category: sense.categoryId || cats[0]?.id || CATEGORIES[0].id,
        classCode: existing?.classCode || classCode.trim() || null,
        visibility: "shared",
        verified: true,
        owner: existing?.owner || profile.username,
        addedAt: Date.now(),
        lastSeenAt: null,
        srsInterval: 1,
        streakCount: 0,
        lastErrorType: null,
        practiceViewCount: 0,
      };
      await saveWordQuiet(newWord);
    }
    setSplitSaved(true);
    setAiHelperState("done");
  }

  // Save without closing the modal (for split-sense cards)
  async function saveWordQuiet(word) {
    const shared = word.visibility === "shared";
    const { srsInterval, streakCount, lastErrorType, practiceViewCount, ...cleanWord } = word;
    await storageSet(KEYS.word(cleanWord.id), cleanWord, shared);
    const idxKey = shared ? KEYS.sharedIndex : KEYS.privateIndex;
    const idx = (await storageGet(idxKey, shared)) || [];
    if (!idx.includes(cleanWord.id)) await storageSet(idxKey, [...idx, cleanWord.id], shared);
  }

  function handleThaiChange(value) {
    setThai(value);
    if (debounceRef.current) clearTimeout(debounceRef.current);
    if (isEdit) return; // don't auto-suggest while editing an existing word
    if (!value.trim()) {
      setAiState("idle");
      return;
    }
    debounceRef.current = setTimeout(() => runAiSuggestion(value.trim()), 700);
  }

  function handleSave() {
    if (!thai.trim() || !romanization.trim() || !english.trim() || !classCode.trim()) return;
    const word = {
      id: existing?.id || newId(),
      emoji: emoji.trim() || "📝",
      thai: thai.trim(),
      romanization: romanization.trim(),
      english: english.trim(),
      pos,
      category,
      classCode: classCode.trim(),
      visibility: "shared",
      verified: true,
      owner: existing?.owner || profile.username,
      addedAt: existing?.addedAt || Date.now(),
      lastSeenAt: existing?.lastSeenAt || null,
      srsInterval: existing?.srsInterval ?? 1,
      streakCount: existing?.streakCount ?? 0,
      lastErrorType: existing?.lastErrorType ?? null,
      practiceViewCount: existing?.practiceViewCount ?? 0,
    };
    onSave(word);
  }

  const canSave = thai.trim() && romanization.trim() && english.trim() && classCode.trim();

  return (
    <ModalOverlay onClose={onClose}>
      <div className="modal-card" onClick={(e) => e.stopPropagation()}>
        <div className="modal-head">
          <h2>{isEdit ? "Edit word" : "Add word"}</h2>
          <button className="icon-btn" onClick={onClose}>
            <X size={16} />
          </button>
        </div>

        <div className="modal-body">
          <Field label="Card icon (emoji)">
            <div style={{ display: "flex", gap: "8px", alignItems: "center" }}>
              <input
                className="modal-input"
                style={{ width: "60px", textAlign: "center", fontSize: "20px" }}
                value={emoji}
                onChange={e => setEmoji(e.target.value)}
                maxLength={2}
              />
              <span className="stg-hint" style={{ margin: 0 }}>Auto-set by AI — edit if needed</span>
            </div>
          </Field>

          <Field label="Thai">
            <input className="modal-input thai-input" value={thai} onChange={(e) => handleThaiChange(e.target.value)} placeholder="ขอบคุณ" autoFocus={!isEdit} />
          </Field>

          {!isEdit && (
            <div className={"ai-status " + aiState}>
              {aiState === "loading" && (
                <>
                  <Sparkles size={13} className="spin" /> AI is suggesting romanization, translation, and part of speech…
                </>
              )}
              {aiState === "done" && (
                <>
                  <Sparkles size={13} /> AI suggestion filled in below — please check it before saving.
                </>
              )}
              {aiState === "error" && (
                <>
                  <AlertCircle size={13} /> {aiError}
                </>
              )}
            </div>
          )}

          <Field label="Romanization (Paiboon+)">
            <input
              className="modal-input"
              value={romanization}
              onChange={(e) => setRomanization(e.target.value)}
              placeholder="khɔ̀ɔp-khun"
            />
          </Field>

          <Field label="English">
            <input
              className="modal-input"
              value={english}
              onChange={(e) => setEnglish(e.target.value)}
              placeholder="thank you"
            />
          </Field>

          {isEdit && (
            <div className="field-group">
              <button
                type="button"
                className="ai-helper-btn"
                onClick={runAiHelper}
                disabled={aiHelperState === "loading" || !thai.trim()}
              >
                <Sparkles size={13} className={aiHelperState === "loading" ? "spin" : ""} />
                {aiHelperState === "loading" ? "AI Helper is thinking…" : "AI Helper — suggest part of speech & category"}
              </button>
              {aiHelperState === "done" && (
                <div className="ai-status done">
                  <Sparkles size={13} /> AI suggestion applied below — please check it before saving.
                </div>
              )}
              {aiHelperState === "split" && splitPreview && (
                <div className="ai-split-preview">
                  <div className="ai-status done" style={{ marginBottom: 8 }}>
                    <Sparkles size={13} /> AI detected <strong>{splitPreview.senses.length + 1}</strong> distinct senses.
                    This card was updated to the first sense. Review the others below — uncheck any you don't want to create.
                  </div>
                  {splitPreview.skipped.length > 0 && (
                    <div className="ai-status" style={{ marginBottom: 8, fontSize: 11 }}>
                      <Check size={13} /> Skipped {splitPreview.skipped.length} existing: {splitPreview.skipped.map((e, i) => <><strong key={i}>"{e}"</strong>{i < splitPreview.skipped.length - 1 ? ", " : ""}</>)}
                    </div>
                  )}
                  {splitPreview.senses.map((s, i) => (
                    <label key={i} className="split-sense-row">
                      <input
                        type="checkbox"
                        checked={splitSelected.has(i)}
                        onChange={(e) => {
                          const next = new Set(splitSelected);
                          if (e.target.checked) next.add(i); else next.delete(i);
                          setSplitSelected(next);
                        }}
                      />
                      <span className="split-sense-emoji">{s.emoji || "📝"}</span>
                      <span className="split-sense-eng">{s.english}</span>
                      <span className="split-sense-pos">{s.pos}</span>
                    </label>
                  ))}
                  <button
                    type="button"
                    className="ai-helper-btn"
                    onClick={confirmSplitCreate}
                    disabled={splitSelected.size === 0 || splitSaved}
                    style={{ marginTop: 8 }}
                  >
                    <Check size={13} /> {splitSaved ? "Cards created ✓" : `Create ${splitSelected.size} card${splitSelected.size !== 1 ? "s" : ""}`}
                  </button>
                </div>
              )}
              {aiHelperState === "error" && (
                <div className="ai-status error">
                  <AlertCircle size={13} /> {aiHelperError}
                </div>
              )}
            </div>
          )}

          <Field label="Part of speech">
            <div className="chip-row">
              {PARTS_OF_SPEECH.map((p) => (
                <Chip
                  key={p}
                  active={pos === p}
                  onClick={() => setPos(p)}
                >
                  {p}
                </Chip>
              ))}
            </div>
          </Field>

          <Field label="Category">
            <CategoryDropdown value={category} options={cats} onChange={setCategory} />
          </Field>

          <Field label="Class code (required)">
            <input
              className="modal-input"
              value={classCode}
              onChange={(e) => setClassCode(e.target.value)}
              placeholder="e.g. S1C1"
              maxLength={12}
            />
            {classCodes.length > 0 && !classCode.trim() && (
              <div style={{ fontSize: 10.5, opacity: 0.5, marginTop: 4 }}>
                Existing codes: {classCodes.map(c => c.code).join(', ')}
              </div>
            )}
          </Field>

        </div>

        <div className="modal-footer">
          {isEdit && onDelete && (
            <button
              className="delete-btn"
              onClick={() => {
                if (confirm(`Delete this word?\n\n${thai} — "${english}"\n\nThis cannot be undone.`)) {
                  onDelete(existing);
                }
              }}
            >
              <Trash2 size={14} /> Delete
            </button>
          )}
          <button className="save-btn" disabled={!canSave} onClick={handleSave}>
            <Pencil size={14} /> {isEdit ? "Save changes" : "Add to bank"}
          </button>
        </div>
      </div>
    </ModalOverlay>
  );
}

function Field({ label, children }) {
  return (
    <div className="field-group">
      <div className="field-label">{label}</div>
      {children}
    </div>
  );
}

// ---------------------------------------------------------------------------
// Study Mode — dictionary-style flashcard browser
// ---------------------------------------------------------------------------
function StudyModeScreen({ words, wordsLoaded, progMap, profile, aiConfig, allCategories, onCalligraphyUpdate }) {
  const thaiFont = thaiFontForLevel(profile?.level);
  const showSpelling = BEGINNER_FONT_LEVELS.has(profile?.level);
  const [categoryFilter, setCategoryFilter] = useState("all");
  const [query, setQuery] = useState("");
  const [index, setIndex] = useState(0);
  const [flipped, setFlipped] = useState(false);
  const [viewMode, setViewMode] = useState("card"); // card | list
  const [spelling, setSpelling] = useState(null);
  const [spellingLoading, setSpellingLoading] = useState(false);
  const [wordImage, setWordImage] = useState(null);
  const [imageLoading, setImageLoading] = useState(false);
  // Issue #62 — Practice writing entry point (touch devices only, ADR-018)
  const isTouchCapable = useIsTouchCapable();
  const [practiceChars, setPracticeChars] = useState(null); // null = modal closed
  const [wordWritingSession, setWordWritingSession] = useState(null); // Issue #416
  const [navLock, setNavLock] = useState(false);
  const studyFlipTimer = useRef(null);

  const filtered = useMemo(() => {
    return words.filter((w) => {
      if (categoryFilter !== "all" && w.category !== categoryFilter) return false;
      if (query.trim()) {
        const q = query.trim().toLowerCase();
        return w.thai.includes(query.trim()) || w.english.toLowerCase().includes(q) || w.romanization.toLowerCase().includes(q);
      }
      return true;
    });
  }, [words, categoryFilter, query]);

  // Reset index when filter changes
  useEffect(() => {
    setIndex(0);
    setFlipped(false);
  }, [categoryFilter, query]);

  const current = filtered[index];
  const cat = current ? catById(current.category, allCategories || CATEGORIES) : null;

  // Issue #62 — practicable consonants for the current word, ranked by how
  // often they appear across the student's whole released vocabulary
  // (words prop is already getVisibleWords-filtered by the caller).
  const wordPracticeChars = useMemo(() => {
    if (!current) return [];
    return rankCharsByVocabFrequency(extractPracticableChars(current.english), words);
  }, [current, words]);

  // Fetch spelling breakdown when card is flipped (beginner levels only)
  useEffect(() => {
    if (!flipped || !showSpelling || !current) return;
    setSpelling(null);
    setSpellingLoading(true);
    generateSpelling(current.thai, current.id, aiConfig)
      .then(s => { setSpelling(s); setSpellingLoading(false); })
      .catch(() => setSpellingLoading(false));
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [flipped, current?.id, showSpelling]);

  // Fetch image from Wikimedia Commons when card is flipped — always, emoji is not used anymore
  useEffect(() => {
    if (!flipped || !current) return;
    setWordImage(null);
    setImageLoading(true);
    fetchWordImage(current.english, current.id, current.pos)
      .then(url => { setWordImage(url); setImageLoading(false); })
      .catch(() => setImageLoading(false));
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [flipped, current?.id]);

  // Issue #134 — animate flip-back before changing card content
  function advanceCard(dir) {
    if (navLock) return;
    setNavLock(true);
    setFlipped(false);
    studyFlipTimer.current = setTimeout(() => {
      setIndex((i) => Math.max(0, Math.min(filtered.length - 1, i + dir)));
      setNavLock(false);
    }, 520);
  }
  function prev() { advanceCard(-1); }
  function next() { advanceCard(1); }

  function handleKey(e) {
    if (navLock) return;
    if (e.key === "ArrowLeft") prev();
    if (e.key === "ArrowRight") next();
    if (e.key === " " || e.key === "Enter") { e.preventDefault(); setFlipped((f) => !f); }
  }

  useEffect(() => () => { if (studyFlipTimer.current) clearTimeout(studyFlipTimer.current); }, []);

  if (!wordsLoaded) return <div className="screen-pad"><div className="empty-state">Loading words…</div></div>;

  if (words.length === 0) return (
    <div className="screen-pad center-content">
      <EmptyState
        title="No words yet"
        subtitle="Your teacher will prepare them for you"
        image="/mascote-empty-bank.png"
        compact
      />
    </div>
  );

  return (
    <div className="screen-pad study-root" onKeyDown={handleKey} tabIndex={-1}>
      <SttUnsupportedNotice />
      <div className="study-header">
        <h1 className="page-title small">Study Mode</h1>
        <div className="view-toggle">
          <button className={viewMode === "card" ? "active" : ""} onClick={() => setViewMode("card")}>Cards</button>
          <button className={viewMode === "list" ? "active" : ""} onClick={() => setViewMode("list")}>List</button>
        </div>
      </div>

      {/* Search */}
      <div className="search-row" style={{ marginBottom: 10 }}>
        <Search size={14} className="search-ic" />
        <input className="search-input" placeholder="Search Thai, romanization or English…" value={query} onChange={(e) => { setQuery(e.target.value); }} />
        {query && <button className="search-clear" onClick={() => setQuery("")}><X size={13} /></button>}
      </div>

      {/* Category chips */}
      <div className="chip-row scroll" style={{ marginBottom: 14 }}>
        <Chip active={categoryFilter === "all"} onClick={() => setCategoryFilter("all")}>All</Chip>
        {CATEGORIES.map((c) => ({ ...c, _count: words.filter(w => w.category === c.id).length }))
          .sort((a, b) => b._count - a._count)
          .map((c) => (
          <Chip key={c.id} active={categoryFilter === c.id} color={c.color} onClick={() => setCategoryFilter(c.id)}>
            {c.name}
          </Chip>
        ))}
      </div>

      {filtered.length === 0 && (() => {
        const categoryIsEmpty = categoryFilter !== "all" && !words.some(w => w.category === categoryFilter);
        if (categoryIsEmpty) {
          return (
            <EmptyState
              title="This category is empty"
              subtitle="No words registered here yet — try another category."
              image="/mascote-empty-category.png"
              compact
            />
          );
        }
        return (
          <EmptyState
            title="Nothing matches"
            subtitle="Try a different search or category filter."
            image="/mascote.png"
            compact
          />
        );
      })()}

      {/* CARD VIEW */}
      {viewMode === "card" && filtered.length > 0 && current && (
        <>
          <div className="study-counter">{index + 1} / {filtered.length}</div>

          {/* Flashcard */}
          <div
            className={"study-card" + (flipped ? " flipped" : "")}
            style={{ "--accent": cat?.color || "#E8A33D" }}
            onClick={() => !navLock && setFlipped((f) => !f)}
            role="button"
            tabIndex={0}
          >
            <div className="study-card-inner">

              {/* FRONT — Thai only, maximum size */}
              <div className="study-face study-front">
                <div className="study-category-tag">{cat?.name}</div>
                <div className="study-thai-xl" style={{ fontFamily: thaiFont }}>{current.thai}</div>
                <TtsButton text={current.thai} />
                {/* Issue #138 — POS shown on the front too, so the student has a memory
                    hook (noun/verb/etc.) before flipping, not just after. */}
                <div className="study-pos-badge study-pos-badge-front">{current.pos}</div>
                <div className="study-tap-hint">tap to flip</div>
              </div>

              {/* BACK — fixed 15%/70%/15% proportions (category/content/english) — issue #136, #255 */}
              <div className="study-face study-back">
                <div className="study-category-tag">{cat?.name}</div>
                <div className="study-view-count-corner">
                  <Eye size={11} />
                  <span>{(progMap[current.id] || mkProg()).count}×</span>
                </div>

                <div className="study-back-top">
                  <div className="study-back-visual">
                    {wordImage && wordImage !== "NONE"
                      ? <img src={wordImage} alt={current.english} className="card-visual-img" loading="lazy" />
                      : imageLoading ? <span className="card-visual-placeholder">…</span> : null}
                  </div>
                  <div className="study-back-word">
                    <div className="study-thai-sm" style={{ fontFamily: thaiFont }}>{current.thai}</div>
                    <TtsButton text={current.thai} />
                    {showSpelling && (
                      <div className="study-spelling" style={{ fontFamily: thaiFont }}>
                        {spellingLoading ? "…" : spelling}
                      </div>
                    )}
                    <div className="study-ro">{current.romanization}</div>
                  </div>
                </div>

                <div className="study-back-bottom">
                  <div className="study-pos-badge">{current.pos}</div>
                  <div className="study-en">{current.english}</div>
                </div>

              </div>

            </div>
          </div>

          {/* Issue #62 — touch devices only (ADR-018): tracing with a mouse
              doesn't validate stroke shape meaningfully, so desktop gets no
              entry point at all, not a degraded one. */}
          {flipped && isTouchCapable && wordPracticeChars.length > 0 && (
            <button
              className="save-btn study-practice-writing-btn"
              onClick={(e) => { e.stopPropagation(); setPracticeChars(wordPracticeChars); }}
            >
              <Pencil size={14} /> Practice writing
            </button>
          )}
          {/* Issue #416 — word writing entry point: touch only (ADR-018),
              word must be SRS-mastered and have at least 1 stroke char */}
          {flipped && isTouchCapable && isWordMastered(progMap, current?.id) && wordPracticeChars.length > 0 && (
            <button
              className="btn-secondary study-practice-writing-btn"
              onClick={(e) => { e.stopPropagation(); setWordWritingSession([current]); }}
            >
              <Pencil size={14} /> Write this word
            </button>
          )}

          {/* Issue #199 — pronunciation panel moved OUTSIDE the flip-card.
              It used to live inside .study-back (position:absolute, fixed
              height), so once scored/error content grew taller than the
              card face it overflowed downward and visually covered the
              nav arrows right below — on some phones (reported: Oppo A3
              Pro 5G) this made the "next card" arrow untappable. */}
          {flipped && detectSTT() && (
            <div className="study-pron-block">
              <PronunciationPractice key={current.id} targetWord={current.thai} thaiFont={thaiFont} />
            </div>
          )}

          {/* Navigation */}
          <div className="study-nav">
            <button className="nav-btn" onClick={prev} disabled={index === 0}><ChevronLeft size={18} /></button>
            <button className="nav-btn flip" onClick={() => setFlipped((f) => !f)}><RotateCcw size={15} /></button>
            <button className="nav-btn" onClick={next} disabled={index === filtered.length - 1}><ChevronRight size={18} /></button>
          </div>

          <p className="study-hint-keys">← → to navigate · space to flip</p>
        </>
      )}

      {/* LIST VIEW */}
      {viewMode === "list" && (
        <div className="word-list">
          {filtered.map((w, i) => {
            const c = catById(w.category, allCategories || CATEGORIES);
            return (
              <div
                key={w.id}
                className={"word-row study-list-row" + (i === index ? " selected" : "")}
                style={{ "--accent": c?.color || "#888" }}
                onClick={() => { setIndex(i); setFlipped(false); setViewMode("card"); }}
              >
                <div className="word-row-main">
                  <span className="word-thai" style={{ fontFamily: thaiFont }}>{w.emoji && <span className="word-emoji">{w.emoji}</span>}{w.thai}</span>
                  <span className="word-ro">{w.romanization}</span>
                </div>
                <div className="word-row-side">
                  <span className="word-en">{w.english}</span>
                  <span className="word-tags">
                    <span className="tag-pos">{w.pos}</span>
                    <span className="view-count-mini"><Eye size={10} /> {(progMap[w.id] || mkProg()).count}</span>
                    </span>
                </div>
              </div>
            );
          })}
        </div>
      )}

      {/* Issue #62 — Practice writing flow, opened from the button above */}
      {practiceChars && (
        <CalligraphyPracticeModal
          chars={practiceChars}
          onClose={() => setPracticeChars(null)}
          onCalligraphyUpdate={onCalligraphyUpdate}
        />
      )}
      {/* Issue #416 — word writing session, single word from current flashcard */}
      {wordWritingSession && (
        <WordCalligraphySession
          words={wordWritingSession}
          onClose={() => setWordWritingSession(null)}
          onCalligraphyUpdate={onCalligraphyUpdate}
        />
      )}
    </div>
  );
}

// ---------------------------------------------------------------------------
// Practice Mode — main screen
// ---------------------------------------------------------------------------
// Shared by Practice Mode and (Furo 1 fix) Sunday Test: today's lesson counts
// toward the daily streak the same way regardless of which screen completed it.
// profile/powersConfig são opcionais (issue #184/#220 — congelar streak).
// Sem eles, o comportamento é idêntico ao de antes (nenhuma proteção).
async function computeAndSaveStreak(profile = null, powersConfig = null) {
  const tStr = todayStr();
  const yStr = yesterdayStr();
  const cur = await storageGet(STREAK_KEY, false) || { count: 0, lastDate: null, best: 0 };

  let newCount;
  let freezeUsed = false;
  if (cur.lastDate === yStr) {
    newCount = cur.count + 1;
  } else if (cur.lastDate === tStr) {
    newCount = cur.count;
  } else if (profile && daysAgo(cur.lastDate) === 2) {
    // Exatamente 1 dia perdido — só aqui a proteção de streak freeze pode
    // agir (nunca em gaps maiores). Não afeta em nada o requisito de
    // completar a sessão de HOJE, que já aconteceu pra chegarmos até aqui.
    const freeze = await tryConsumeStreakFreeze(profile, powersConfig);
    if (freeze.used) { newCount = cur.count + 1; freezeUsed = true; }
    else newCount = 1;
  } else {
    newCount = 1;
  }

  const newBest   = Math.max(cur.best || 0, newCount);
  const newStreak = { count: newCount, lastDate: tStr, best: newBest };
  await storageSet(STREAK_KEY, newStreak, false);

  // Issue #181 — track the highest streak reached within the CURRENT
  // calendar month too (separate from all-time `best`), so the "Gatinho do
  // Mês" 14-day gate can be checked without any all-time streak history.
  const monthKey = getMonthKey();
  const monthBestKey = MONTH_STREAK_BEST_KEY(monthKey);
  const prevMonthBest = await storageGet(monthBestKey, false) || 0;
  if (newCount > prevMonthBest) await storageSet(monthBestKey, newCount, false);

  return { ...newStreak, freezeUsed }; // freezeUsed used by #718 Dawn Ticket streak trigger
}

// ---------------------------------------------------------------------------
// Issue #167 — Coins system
//   Formula: % correct in a session × multiplier = coins earned
//     Practice Mode completion  → 0.6x (issue #198.1 — halved from 1.2x)
//     Sunday Test completion    → 1x   (issue #198.1 — halved from 2x)
//     Weekly streak (every 7th consecutive day) → avg % correct of that
//     week's streak-qualifying sessions × 1.5 (issue #198.1 — halved from
//     3x; bonus on top of the per-session coins)
// ---------------------------------------------------------------------------
const COINS_KEY     = "coins-balance";        // personal: total coins accumulated (integer)
const DAILY_PCT_KEY = (date) => `daily-pct:${date}`; // personal: % correct of the session that counted toward that day's streak

// Issue #198.1 — economy rebalance (owner decision 2026-07-06): a 100%
// dedicated student was farming ~1.340 Meowtongs/week, considered too high.
// Every multiplier below is HALVED (new weekly ceiling: ~670 Meowtongs —
// 420 Practice + 100 Sunday Test + 150 weekly-streak bonus at a 100%
// accuracy every day). Do not change without re-checking issue #198.
const COIN_MULTIPLIER = {
  practice:   0.6,
  sundayTest: 1,
  streakWeek: 1.5,
};

function coinsFromPct(pct, multiplier) {
  return Math.round((pct || 0) * multiplier);
}

// Issue #282 — this is the ONE function every coin credit/debit in the app
// goes through (sessions, achievements, gacha, avatar shop, teacher gifts,
// weekly bonus...). It used to do `(await storageGet(COINS_KEY, false)) || 0`
// — storageGet returns null on ANY failure (dropped network, stale/expired
// session after a backgrounded mobile tab resumes, RLS hiccup), and that
// `|| 0` treated "read failed" identically to "balance is legitimately 0".
// A transient failure at the exact moment a credit fired (e.g. the
// visibilitychange-triggered poll claiming a pending teacher gift right as
// the tab regains focus and the session is still re-establishing) would
// silently overwrite the student's real balance with just that one delta —
// same failure class already fixed for loadRoster in #251. Now: use the
// safe variant and refuse to touch storage at all if the read failed —
// return null so every caller can tell "confirmed new balance" apart from
// "unknown, don't trust it, don't display it, don't persist it".
const COINS_LEDGER_KEY = "coins-ledger"; // personal: append-only audit trail of every credit/debit (issue #313)
const DAILY_REWARD_PENDING_KEY = "daily-reward-pending"; // { type, value, label, earnedAt, todayKey, collected, doubled }
const COINS_LEDGER_CAP = 200;

// Issue #313 (follow-up of ADR-014) — best-effort audit trail. ADR-014 fixed
// the *prevention* side of coin-balance corruption (storageGetSafe everywhere)
// but left no way to *reconstruct* a balance if some other, not-yet-seen path
// corrupts it again. This never blocks or rolls back the real credit — a
// ledger write failure is swallowed (logged, not thrown) since the ledger is
// a safety net, not the source of truth. Same storageGetSafe read-modify-
// write discipline as the rest of the codebase (#251/#282/#56).
async function appendCoinsLedgerEntry(delta, reason, balanceAfter) {
  const { value: existing, error } = await storageGetSafe(COINS_LEDGER_KEY, false);
  if (error) { console.error("[appendCoinsLedgerEntry] read failed, skipping ledger write:", error); return; }
  const prevLog = Array.isArray(existing) ? existing : [];
  const nextLog = [...prevLog, { delta, reason: reason || "unknown", balanceAfter, at: Date.now() }].slice(-COINS_LEDGER_CAP);
  const ok = await storageSet(COINS_LEDGER_KEY, nextLog, false);
  if (!ok) console.error("[appendCoinsLedgerEntry] write failed — ledger entry lost, balance unaffected");
}

// Issue #313 — added an optional `reason` (human-readable label, e.g.
// "Practice session", "Gacha Moonrise Ticket reward") so every entry going
// through the ledger below is self-explanatory without needing to trace
// back to the call site. Defaults to "unknown" for any caller that doesn't
// pass one — never a hard requirement, since the balance credit itself must
// never be blocked by ledger bookkeeping.
async function creditCoins(amount, reason) {
  const { value, error } = await storageGetSafe(COINS_KEY, false);
  if (error) {
    console.error("[creditCoins] aborting — could not read current balance:", error);
    return null;
  }
  const cur = value || 0;
  if (!amount) return cur;
  const updated = cur + amount;
  const ok = await storageSet(COINS_KEY, updated, false);
  if (!ok) {
    console.error("[creditCoins] write failed — balance NOT updated, still", cur);
    return null;
  }
  await appendCoinsLedgerEntry(amount, reason, updated);
  // #856 — log coins earned (gains only, not spends)
  if (amount > 0) appendDailyLog(COINS_WEEK_LOG_KEY, { amount }).catch(() => {});
  // #857 — log coins earned during Golden Abundance event
  if (amount > 0 && isGoldenAbundanceActive()) appendDailyLog(GA_COINS_LOG_KEY, { amount }).catch(() => {});
  // Mirror wallet to shared_kv so teacher view stays current
  const _u = getCurrentUsername();
  if (_u) mirrorStudentWallet(_u).catch(() => {});
  return updated;
}

// #855/#856 — generic daily-log appender: reads [{date,...}], upserts today's entry by merging numeric fields
async function appendDailyLog(key, fields) {
  const today = todayStr();
  const log = (await storageGet(key, false)) || [];
  const idx = log.findIndex(e => e.date === today);
  if (idx >= 0) {
    const merged = { ...log[idx] };
    for (const [k, v] of Object.entries(fields)) merged[k] = (merged[k] || 0) + v;
    log[idx] = merged;
  } else {
    log.push({ date: today, ...Object.fromEntries(Object.entries(fields).map(([k, v]) => [k, v])) });
  }
  await storageSet(key, log, false);
}

// Issue #346 — Transactions tab helpers: group the flat ledger array into
// day buckets (most recent day first, most recent entry within a day
// first) for a bank-statement-style display, with "Today"/"Yesterday"
// labels like the rest of the app already does for dates (see #251 roster
// dates, ProgressScreen's `fmt`).
function groupLedgerByDay(entries) {
  const byDay = new Map(); // dayKey -> { dayLabel, entries: [] }
  const now = new Date();
  const todayKey = now.toDateString();
  const yesterday = new Date(now); yesterday.setDate(now.getDate() - 1);
  const yesterdayKey = yesterday.toDateString();

  // Newest first overall, so walk the source array in reverse.
  for (let i = entries.length - 1; i >= 0; i--) {
    const entry = entries[i];
    const d = new Date(entry.at);
    const dayKey = d.toDateString();
    if (!byDay.has(dayKey)) {
      let dayLabel;
      if (dayKey === todayKey) dayLabel = "Today";
      else if (dayKey === yesterdayKey) dayLabel = "Yesterday";
      else dayLabel = d.toLocaleDateString('en', { month: 'short', day: 'numeric', year: d.getFullYear() !== now.getFullYear() ? 'numeric' : undefined });
      byDay.set(dayKey, { dayLabel, entries: [] });
    }
    byDay.get(dayKey).entries.push(entry);
  }
  return Array.from(byDay.values());
}

function formatTxnTime(at) {
  return new Date(at).toLocaleTimeString('en', { hour: 'numeric', minute: '2-digit' });
}

// Called right after a session's streak day is registered (Practice Mode
// always; Sunday Test only when the student accepts the streak swap).
// When the streak hits a multiple of 7, credit the weekly bonus based on
// the average % correct across the last 7 streak-qualifying days.
// Issue #182 — returns the coins delta actually credited (0 if the bonus
// didn't fire), so callers can surface it in a Meowtongs-earned toast.
async function maybeCreditStreakWeekBonus(newStreak) {
  if (!newStreak || !newStreak.count || newStreak.count % 7 !== 0) return 0;
  const dates = [];
  for (let i = 0; i < 7; i++) {
    const d = new Date();
    d.setDate(d.getDate() - i);
    dates.push(`${d.getFullYear()}-${pad2(d.getMonth()+1)}-${pad2(d.getDate())}`);
  }
  const pcts = [];
  for (const date of dates) {
    const p = await storageGet(DAILY_PCT_KEY(date), false);
    if (typeof p === "number") pcts.push(p);
  }
  if (pcts.length === 0) return 0;
  const avgPct = pcts.reduce((a, b) => a + b, 0) / pcts.length;
  const delta = coinsFromPct(avgPct, COIN_MULTIPLIER.streakWeek);
  await creditCoins(delta, "Streak Week Bonus");
  return delta;
}

// ---------------------------------------------------------------------------
// Issue #198.2/#198.3 — Gacha Ticket system: an alternative acquisition path
// for Rare/Epic avatars beyond direct Shop purchase, funded by Meowtongs.
// Buy a ticket in the Shop (Gacha tab), then "open" it for a weighted
// random reward. Every probability table below is copied verbatim from the
// economy decisions locked in issue #198 (owner sign-off 2026-07-06) — do
// NOT tune a percentage here without updating that issue first.
// ---------------------------------------------------------------------------
const GACHA_TICKETS_KEY = "gacha-tickets"; // personal: { rare, epic, banner, dawn } — unopened ticket counts (#718 dawn = Dawn Ticket)

// Issue #347 — Wish History + pity system for the Rare/Epic Gacha.
const GACHA_HISTORY_KEY = "gacha-pull-history"; // personal: append-only, one entry per ticket opened
const GACHA_HISTORY_CAP = 100;
const GACHA_PITY_KEY = "gacha-pity"; // personal: { rare: number, epic: number } — consecutive opens without that ticket's jackpot
// Soft-pity starts climbing the jackpot odds; hard-pity guarantees it. Values
// are deliberately much shorter than a real-money gacha (see #347 rationale):
// worst-case base jackpot rate is already 3% and a 100%-dedicated student
// caps out around ~670 Meowtongs/week (#198.1) — a Genshin-scale 74-90 pull
// hard pity would never actually be reached, so it'd protect nobody.
// Issue #379 — `banner` (Solstice Ticket) added, same softStart/hardCap as
// Rare per #351's own suggestion ("igual Rare, ajustável"). Crucially this
// track is PERSISTENT across different banner windows/months (#351 decision
// 3) — it only resets on a real jackpot hit, never on a new banner opening
// or the window closing. That fall-out is automatic here: nothing in this
// file ever resets GACHA_PITY_KEY's "banner" field except updateGachaPity
// itself being called with hitJackpot=true.
const GACHA_PITY = {
  rare:   { softStart: 6,  hardCap: 10 },
  epic:   { softStart: 5,  hardCap: 8  },
  banner: { softStart: 6,  hardCap: 10 },
  dawn:   { softStart: 30, hardCap: 45 }, // #718 — hard pity 45 → guaranteed Legendary
};

async function getGachaPity() {
  const { value } = await storageGetSafe(GACHA_PITY_KEY, false);
  return value || { rare: 0, epic: 0, banner: 0, dawn: 0 };
}

// Read-modify-write, same storageGetSafe discipline as the rest of the
// codebase (#251/#282/#56/#313) — a failed read must abort the write
// instead of silently resetting the other ticket kind's counter to 0.
async function updateGachaPity(kind, hitJackpot) {
  const { value, error } = await storageGetSafe(GACHA_PITY_KEY, false);
  if (error) { console.error("[updateGachaPity] read failed, skipping pity update:", error); return; }
  const cur = value || { rare: 0, epic: 0, banner: 0, dawn: 0 };
  const next = { ...cur, [kind]: hitJackpot ? 0 : (cur[kind] || 0) + 1 };
  const ok = await storageSet(GACHA_PITY_KEY, next, false);
  if (!ok) console.error("[updateGachaPity] write failed — pity counter not updated");
}

// Reweights a scenario table so `jackpotKey`'s odds climb linearly from its
// own base weight (at pityCount === softStart) up to a full 100 (guaranteed)
// at pityCount === hardCap, borrowing weight proportionally from every other
// row so percentages still sum to 100. Below softStart, table is untouched.
function applyPityBoost(table, jackpotKey, pityCount, softStart, hardCap) {
  if (pityCount < softStart) return table;
  if (pityCount >= hardCap) return [[jackpotKey, 100]];
  const progress = (pityCount - softStart) / (hardCap - softStart);
  const base = table.find(([k]) => k === jackpotKey)?.[1] || 0;
  const boosted = base + (100 - base) * progress;
  const othersBaseTotal = 100 - base;
  const scale = othersBaseTotal > 0 ? (100 - boosted) / othersBaseTotal : 0;
  return table.map(([k, pct]) => (k === jackpotKey ? [k, boosted] : [k, pct * scale]));
}

// Append-only "Wish History" entry — one per ticket opened, jackpot or not,
// mirroring the exact same pattern as appendCoinsLedgerEntry (#313).
async function appendGachaHistoryEntry(entry) {
  const { value: existing, error } = await storageGetSafe(GACHA_HISTORY_KEY, false);
  if (error) { console.error("[appendGachaHistoryEntry] read failed, skipping history write:", error); return; }
  const prevLog = Array.isArray(existing) ? existing : [];
  const nextLog = [...prevLog, { ...entry, at: Date.now() }].slice(-GACHA_HISTORY_CAP);
  const ok = await storageSet(GACHA_HISTORY_KEY, nextLog, false);
  if (!ok) console.error("[appendGachaHistoryEntry] write failed — history entry lost");
}

const RARE_TICKET_PRICE = 1200;  // #510
const EPIC_TICKET_PRICE = 2500;  // #510
const BANNER_TICKET_PRICE = 2000; // Issue #378 — Solstice Ticket, purchasable only during an active banner window (#377) — #510

// Issue #198.4 — display metadata for the Gacha tab's buy cards.
// Issue #378 — added `banner` (Solstice Ticket). Its "open" flow (pity/draw
// table) isn't wired up yet — that's #379 — this entry only powers the buy
// card + inventory count for now.
const GACHA_TICKET_CATALOG = {
  rare:   { id: "rare",   name: "Moonrise Ticket",  image: "/tickets/rare-ticket.png",     price: RARE_TICKET_PRICE,   ringClass: "avatar-ring-rare"   },
  epic:   { id: "epic",   name: "Starlight Ticket",  image: "/tickets/epic-ticket.png",     price: EPIC_TICKET_PRICE,   ringClass: "avatar-ring-epic"   },
  banner: { id: "banner", name: "Solstice Ticket",   image: "/tickets/solstice-ticket.png", price: BANNER_TICKET_PRICE, ringClass: "avatar-ring-banner" },
  dawn:   { id: "dawn",   name: "Dawn Ticket",       image: "/tickets/dawn-ticket.png",     price: 0,                   ringClass: "avatar-ring-banner" }, // #718 — Hearthbound event, earned not bought
};

// ---------------------------------------------------------------------------
