// #702 — daily_login_bonus: active when ANY unlocked avatar has this power assigned.
// Unlike other passives this does NOT require the cat to be equipped — possession is enough.
function getDailyLoginBonusActive(profile, powersConfig) {
  if (!profile || !powersConfig) return false;
  const unlocked = new Set([
    ...(profile.unlockedAvatars || []),
    ...(profile.avatar ? [profile.avatar] : []),
  ]);
  return [...unlocked].some(avatarId => {
    const assignment = (powersConfig || {})[avatarId];
    return assignment?.passive === "daily_login_bonus" || assignment?.passive2 === "daily_login_bonus";
  });
}

async function getGachaTickets() {
  return (await storageGet(GACHA_TICKETS_KEY, false)) || { rare: 0, epic: 0, banner: 0 };
}

// Buys 1 ticket with coins — no odds involved yet, that's a separate "open"
// step so the student can hold onto tickets and open them whenever they want.
// Issue #184 / #220 — Fase 3: discountFraction (soma de todos os poderes
// gachaTicketDiscount ativos agora) é aplicado no preço antes de cobrar.
async function buyGachaTicket(kind, coins, discountFraction = 0) {
  const basePrice = GACHA_TICKET_CATALOG[kind]?.price;
  if (!basePrice) return { ok: false, reason: "invalid-ticket" };
  // Issue #378 — Solstice Ticket only buyable during its own active banner
  // window (#377's getActiveBanner). Defense in depth: StoreScreen also
  // hides/disables the buy card outside the window, but this blocks any
  // other call path too (e.g. a stale tab left open across the window edge).
  if (kind === "banner") {
    const banner = getActiveBanner(new Date());
    if (!banner || !isBannerLaunched(banner.bannerKey)) {
      return { ok: false, reason: "banner-inactive" };
    }
  }
  const price = Math.max(0, Math.round(basePrice * (1 - Math.min(1, discountFraction || 0))));
  if ((coins || 0) < price) return { ok: false, reason: "insufficient-coins", price };
  const tickets = await getGachaTickets();
  const updated = { ...tickets, [kind]: (tickets[kind] || 0) + 1 };
  await storageSet(GACHA_TICKETS_KEY, updated, false);
  const newCoins = await creditCoins(-price, `Gacha Ticket purchase (${kind})`);
  // creditCoins already mirrors coins; mirror again to capture ticket gain too
  { const _u = getCurrentUsername(); if (_u) mirrorStudentWallet(_u).catch(() => {}); }
  return { ok: true, tickets: updated, newCoins, price, basePrice };
}

// Issue #380-followup (2026-07-09 owner decision) — Solstice Ticket banners
// debut brand-new Rare avatars that must NOT leak into the general Rare
// Ticket/Starlight Ticket/banner-fallback draw pools (nor count toward "owns all
// Rares" exhaustion logic) until `lockedUntilMonthKey` has passed — 2
// calendar months after the banner that featured them closes, same
// "genuinely time-limited debut" spirit as #351. A teacher can still gift
// one anytime (AvatarGiftModal reads getFullAvatarCatalog()/getPrizePoolAvatars
// directly, not through this function, so gifting is never gated by the
// lock) — only the RANDOM draw pools and the "owns everything" checks below
// route through getAvatarsByRarity, so that's the one place this needs to
// live. getActiveBannerFeaturedAvatars looks avatars up by id directly
// (never through here), so a locked Rare stays fully drawable during the
// one banner window it was actually featured in.
function isAvatarLocked(avatar, date = new Date()) {
  return !!avatar.lockedUntilMonthKey && getMonthKey(date) < avatar.lockedUntilMonthKey;
}

function getAvatarsByRarity(rarity, catalog = getFullAvatarCatalog(), date = new Date()) {
  return catalog.filter(a => a.rarity === rarity && !a.isDefault && !isAvatarLocked(a, date));
}

// Whether the student owns every avatar currently shipped in this rarity
// tier. A tier with nothing shipped yet is vacuously "complete" (never
// blocks a roll on an empty pool that doesn't exist yet).
function ownsAllOfRarity(rarity, profile) {
  const pool = getAvatarsByRarity(rarity);
  if (pool.length === 0) return true;
  const owned = new Set(profile.unlockedAvatars || []);
  return pool.every(a => owned.has(a.id));
}

function pickRandomUnownedAvatar(rarity, profile) {
  const owned = new Set(profile.unlockedAvatars || []);
  const pool = getAvatarsByRarity(rarity).filter(a => !owned.has(a.id));
  if (pool.length === 0) return null;
  return pool[Math.floor(Math.random() * pool.length)];
}

// Weighted table walk — table is an array of [key, pct] pairs, pct 0-100.
function rollWeightedTable(table) {
  const r = Math.random() * 100;
  let acc = 0;
  for (const [key, pct] of table) {
    acc += pct;
    if (r < acc) return key;
  }
  return table[table.length - 1][0]; // float-rounding safety net
}

// ---- Moonrise Ticket — 4 scenarios (issue #198, "Bilhete Raro") ----
const RARE_TICKET_TABLES = {
  A: [["jackpot_rare", 3], ["avatar_uncommon", 7], ["avatar_common", 10], ["coins_1500", 10], ["coins_1250", 15], ["coins_1000", 20], ["coins_750", 20], ["coins_500", 15]],
  B: [["jackpot_rare", 5], ["avatar_uncommon", 10], ["coins_1500", 13], ["coins_1250", 17], ["coins_1000", 20], ["coins_750", 20], ["coins_500", 15]],
  C: [["jackpot_rare", 5], ["avatar_common", 13], ["coins_1500", 11], ["coins_1250", 16], ["coins_1000", 20], ["coins_750", 20], ["coins_500", 15]],
  D: [["jackpot_rare", 8], ["coins_1500", 15], ["coins_1250", 19], ["coins_1000", 23], ["coins_750", 20], ["coins_500", 15]],
};

// A = neither Common nor Uncommon fully owned. B = Common exhausted only.
// C = Uncommon exhausted only. D = both exhausted.
function getRareTicketScenario(profile) {
  const allCommon   = ownsAllOfRarity("common", profile);
  const allUncommon = ownsAllOfRarity("uncommon", profile);
  if (allCommon && allUncommon) return "D";
  if (allUncommon) return "C";
  if (allCommon) return "B";
  return "A";
}

function resolveRareOutcome(key, profile) {
  if (key === "jackpot_rare")    return { avatar: pickRandomUnownedAvatar("rare", profile) };
  if (key === "avatar_uncommon") return { avatar: pickRandomUnownedAvatar("uncommon", profile), coins: 200 };
  if (key === "avatar_common")   return { avatar: pickRandomUnownedAvatar("common", profile), coins: 750 };
  return { coins: parseInt(key.split("_")[1], 10) }; // coins_NNNN
}

// Opens 1 Rare ticket. Returns:
//  - { ok:true, blocked:true } when the Rare pool is fully owned — caller
//    must ask the student to keep (keepRareTicket, no-op) or refund
//    (refundRareTicket) instead of auto-resolving anything.
//  - { ok:true, avatar, coins, newCoins, profile } otherwise — reward
//    already applied (coins credited, avatar merged + roster mirrored).
async function openRareTicket(profile, { simulate = false } = {}) {
  // Issue #240 — teacher-only preview mode: run the exact same weighted
  // roll, but never touch the real ticket inventory, coins or avatar
  // collection. `simulate` short-circuits every storageSet/creditCoins call
  // below so nothing about the account is actually changed by the roll.
  const tickets = simulate ? { rare: 1 } : await getGachaTickets();
  if (!simulate && (tickets.rare || 0) <= 0) return { ok: false, reason: "no-ticket" };
  if (ownsAllOfRarity("rare", profile)) return { ok: true, blocked: true };

  const scenario = getRareTicketScenario(profile);
  let table = RARE_TICKET_TABLES[scenario];

  // Issue #347 — pity: preview rolls never read/touch the real counter, so
  // a teacher's "Preview Gacha" test can't influence (or be influenced by)
  // the student's actual pity progress.
  let pityCount = 0;
  if (!simulate) {
    const pity = await getGachaPity();
    pityCount = pity.rare || 0;
    table = applyPityBoost(table, "jackpot_rare", pityCount, GACHA_PITY.rare.softStart, GACHA_PITY.rare.hardCap);
  }
  const key = rollWeightedTable(table);
  let { avatar, coins: coinReward } = resolveRareOutcome(key, profile);

  // Defensive net (should never trigger — the scenario already guarantees an
  // unowned avatar for whichever slot the roll lands on): never leave a roll
  // with nothing to show, refund the ticket price instead.
  if ((key === "jackpot_rare" || key === "avatar_uncommon" || key === "avatar_common") && !avatar) {
    coinReward = (coinReward || 0) + RARE_TICKET_PRICE;
  }
  const hitJackpot = key === "jackpot_rare" && !!avatar;

  if (!simulate) {
    await storageSet(GACHA_TICKETS_KEY, { ...tickets, rare: tickets.rare - 1 }, false);
    { const _u = getCurrentUsername(); if (_u) mirrorStudentWallet(_u).catch(() => {}); }
  }

  let updatedProfile = profile;
  if (avatar) {
    updatedProfile = { ...profile, unlockedAvatars: [...(profile.unlockedAvatars || []), avatar.id] };
    if (!simulate) {
      await storageSet(KEYS.profile, updatedProfile, false);
      await mirrorUnlockedAvatarsToRoster(profile.username, updatedProfile.unlockedAvatars, profile);
    }
  }
  const newCoins = (!simulate && coinReward) ? await creditCoins(coinReward, "Gacha Moonrise Ticket reward") : null;

  if (!simulate) {
    await updateGachaPity("rare", hitJackpot);
    await appendGachaHistoryEntry({ kind: "rare", key, avatarId: avatar?.id || null, coins: coinReward || 0, rarity: avatar?.rarity || null });
  }

  return {
    ok: true, avatar: avatar || null, coins: coinReward || 0, newCoins,
    profile: simulate ? profile : updatedProfile, simulate,
    pityCount: simulate ? undefined : (hitJackpot ? 0 : pityCount + 1),
  };
}

// Student chose to hold onto a blocked Rare ticket rather than resolve it —
// no-op, ticket stays in inventory for a future Rare avatar drop.
function keepRareTicket() {
  return { ok: true, kept: true };
}

// Student chose the refund instead — consumes the ticket, credits back the
// full 2.000 coin price.
async function refundRareTicket() {
  const tickets = await getGachaTickets();
  if ((tickets.rare || 0) <= 0) return { ok: false, reason: "no-ticket" };
  await storageSet(GACHA_TICKETS_KEY, { ...tickets, rare: tickets.rare - 1 }, false);
  const newCoins = await creditCoins(RARE_TICKET_PRICE, "Gacha Moonrise Ticket refund");
  return { ok: true, coins: RARE_TICKET_PRICE, newCoins };
}

