function AchievementUnlockMoment({ achievement: a, onDismiss }) {
  return (
    <div className="ach-moment-overlay" onClick={onDismiss}>
      <div className="ach-moment-burst" style={{ "--ach-color": a.color }} />
      {/* Issue #201 — card itself is tappable-to-dismiss now (no more stopPropagation);
          it already reads as a button (rounded golden card), so tapping it should act like one. */}
      <div className="ach-moment-card" style={{ "--ach-color": a.color }}>
        <div className="ach-moment-super">Achievement Unlocked!</div>
        <div className="ach-moment-emoji">{a.emoji}</div>
        <div className="ach-moment-ring" />
        <div className="ach-moment-title">{a.title}</div>
        <div className="ach-moment-desc">{a.desc}</div>
        <div className="ach-moment-cat">{ACH_CAT_LABELS[a.cat]}</div>
        <button className="ach-moment-btn" onClick={onDismiss}>Awesome! 🎉</button>
      </div>
    </div>
  );
}

