// Issue #55 — Auto-dismiss helper for teacher toasts
function TeacherToastAutoDismiss({ toasts, onDismiss }) {
  useEffect(() => {
    if (toasts.length === 0) return;
    const timers = toasts.map(t =>
      setTimeout(() => onDismiss(t.id), 5000)
    );
    return () => timers.forEach(clearTimeout);
  }, [toasts, onDismiss]);
  return null;
}

// ---------------------------------------------------------------------------
// Issue #162 — Avatar unlock reveal (full-screen moment)
// Mirrors the achievement unlock UI (AchievementUnlockMoment) but shows the
// drawn avatar's artwork instead of an emoji.
// ---------------------------------------------------------------------------
// Issue #537 — Golden Abundance double reward moment.
// Plays immediately on mount (no suspense/orbit — it's a bonus, not a gacha
// reveal). SFX preloaded as a singleton so there's no perceptible delay.
const GA_COLOR = "#D4AF37";
function GoldenAbundanceMoment({ total, onDismiss, onFly, soundEnabled = true }) {
  const coinImgRef = useRef(null);
  const [flying, setFlying] = useState(false);

  useEffect(() => {
    if (soundEnabled) playGoldenAbundanceSfx();
  }, [soundEnabled]);

  useEffect(() => {
    if (!flying) return;
    const t = setTimeout(onDismiss, 900);
    return () => clearTimeout(t);
  }, [flying, onDismiss]);

  function handleDismiss() {
    if (flying) return;
    const imgEl   = coinImgRef.current;
    const avatarEl = document.querySelector(".topbar-pill-coins");
    if (imgEl && avatarEl && onFly) {
      const iRect = imgEl.getBoundingClientRect();
      const aRect = avatarEl.getBoundingClientRect();
      onFly({ originX: iRect.left + iRect.width / 2, originY: iRect.top + iRect.height / 2,
              dx: (aRect.left + aRect.width / 2) - (iRect.left + iRect.width / 2),
              dy: (aRect.top  + aRect.height / 2) - (iRect.top  + iRect.height / 2) });
      playCoinSound(total);
    }
    setFlying(true);
  }

  return (
    <div className="ach-moment-overlay" onClick={handleDismiss}>
      <div className="ach-moment-burst" style={{ "--ach-color": GA_COLOR }} />
      <div className="ach-moment-card ga-moment-card">
        <div className="ga-moment-header">✨ Golden Abundance</div>
        <div className="ga-moment-sub">Double Rewards Week</div>
        <img ref={coinImgRef} src="/coins/catcoin.png" alt="Meowtongs" className="avatar-moment-img" />
        <div className="ach-moment-ring" style={{ "--ach-color": GA_COLOR }} />
        <div className="ga-moment-total">+{total} <span className="meowtong-thai">แมวทอง</span></div>
        <div className="ga-moment-note">Your reward, doubled!</div>
        <button className="ach-moment-btn ga-moment-btn" onClick={e => { e.stopPropagation(); handleDismiss(); }}>
          Amazing! ✨
        </button>
      </div>
    </div>
  );
}

const AVATAR_UNLOCK_COLOR = "#E8A33D"; // saffron — matches the streak/celebration accent

function AvatarUnlockMoment({ grant, onDismiss, soundEnabled = true, powersConfig = {} }) {
  const { criterion, avatar, exhausted, origin, ticketKind } = grant;
  const kindKey = avatar?.rarity || "common";
  // #579 — only gacha ticket opens get the orb/cinematic sequence;
  // reward grants (criteria, level-up, monthly cat, gift, lesson) go straight to reveal
  const skipOrbs = exhausted || origin !== "gacha";
  const [stage, setStage, cancelGachaTimers] = useGachaRevealSequence(kindKey, { skip: skipOrbs, sound: soundEnabled });
  const kindStage = getGachaKindStage(kindKey);
  // Issue #442 v3 — common/uncommon show blurred silhouette during colorStage
  const isLowRarity = kindKey === "common" || kindKey === "uncommon";
  // #802 — track mount time to enforce minimum ticket visibility before skip is allowed
  const mountTimeRef = React.useRef(Date.now());

  function handleOverlayClick() {
    if (stage !== "revealed") {
      // #802 — block skip during first 800ms of charging so the ticket is always visible
      if (stage === "charging" && Date.now() - mountTimeRef.current < 800) return;
      cancelGachaTimers();
      setStage("revealed");
      return;
    }
    onDismiss();
  }

  if (exhausted) {
    return (
      <div className="ach-moment-overlay" onClick={onDismiss}>
        <div className="ach-moment-burst" style={{ "--ach-color": AVATAR_UNLOCK_COLOR }} />
        <div className="ach-moment-card" style={{ "--ach-color": AVATAR_UNLOCK_COLOR }}>
          <div className="ach-moment-super">Milestone reached!</div>
          <img src="/mascote.png" alt="" className="avatar-moment-img" />
          <div className="ach-moment-ring" />
          <div className="ach-moment-title">Collection complete!</div>
          <div className="ach-moment-desc">{criterion.desc} — you already own every avatar in the prize pool 🐾</div>
          <div className="ach-moment-cat">Avatar</div>
          <button className="ach-moment-btn" onClick={onDismiss}>Awesome! 🎉</button>
        </div>
      </div>
    );
  }

  // Issue #442 v4 — ALL openings look identical during charging (neutral suspense color)
  const revealed = stage === "revealed";
  const isCharging = stage === "charging";
  const isColorStage = stage === "colorStage";
  const isHighRarity = ["rare", "epic", "legendary"].includes(kindKey);
  // charging: neutral silver-grey for all; colorStage+: rarity color
  const particleColor = (isCharging || isColorStage) ? GACHA_SUSPENSE_COLOR : kindStage.color;
  // charging: base speed; colorStage: fast (rare+) or fade/slow (common/uncommon)
  const particleMod = !isCharging && isColorStage ? " gacha-orbit-particle--fast" : "";
  const showSilhouette = isLowRarity && isColorStage && avatar?.image;
  const ticketImgSrc = !skipOrbs && ticketKind ? GACHA_TICKET_IMGS[ticketKind] : null;
  const [ticketAnimStyle] = useState(() => _TICKET_ANIM_STYLES[Math.floor(Math.random() * _TICKET_ANIM_STYLES.length)]);
  const RARITY_ORDER_C = ["common", "uncommon", "rare", "epic", "legendary"];
  const starsLit = RARITY_ORDER_C.indexOf(kindKey) + 1 || 1;
  if (!avatar) return null;
  const assignment = powersConfig[avatar.id] || null;
  const equippedSlots = ["simple", "special", "passive", "passive2"].filter(s => assignment?.[s]);

  return (
    <div className="ach-moment-overlay" onClick={handleOverlayClick} style={revealed ? {} : { padding: 0 }}>
      <div className="ach-moment-burst" style={{ "--ach-color": particleColor }} />
      {!revealed ? (
        <>
          {ticketImgSrc && (
            <img src={ticketImgSrc} alt="" aria-hidden="true" className={"gacha-ticket-dissolve gacha-ticket-dissolve--" + ticketAnimStyle} />
          )}
          <div className={"gacha-orb-wrap" + (isCharging && ticketImgSrc ? " gacha-orb-wrap--ticket" : "")}>
            {isCharging && <div className="gacha-orb-wind" style={{ "--gacha-glow-color": GACHA_SUSPENSE_COLOR }} />}
            <div className="gacha-orb" style={{ "--gacha-glow-color": particleColor }} />
            {GACHA_PARTICLE_ANGLES.map((angle, i) => (
              <div
                key={i}
                className={"gacha-orbit-particle" + particleMod}
                style={{ "--angle": angle, "--i": i, "--gacha-glow-color": particleColor, "--r": `${90 + (i % 3) * 22}px` }}
              />
            ))}
            {showSilhouette && (
              <img src={avatar.image} alt="" aria-hidden="true" className="gacha-silhouette" />
            )}
          </div>
          <div className="gacha-tap-hint">Tap to skip animation</div>
          {stage === "flash" && (
            <div className="gacha-cinematic-flash" style={{ "--gacha-glow-color": kindStage.color, "--gacha-flash-s": `${kindStage.flashMs}ms` }} />
          )}
        </>
      ) : (
        <div className="gacha-cinematic-reveal">
          <div className="ach-moment-super">New avatar unlocked!</div>
          <div className="gacha-cinematic-stars">
            {RARITY_ORDER_C.map((_, i) => (
              <span key={i} className={"gacha-cinematic-star" + (i < starsLit ? " gacha-cinematic-star--lit" : "")} style={{ "--gacha-glow-color": kindStage.color }}>★</span>
            ))}
          </div>
          <div className="gacha-cinematic-img-wrap">
            <div className="gacha-cinematic-halo" style={{ "--gacha-glow-color": kindStage.color }} />
            <img src={avatar.image} alt={avatar.name} className="gacha-cinematic-img" style={{ "--gacha-glow-color": kindStage.color }} />
          </div>
          <div className="ach-moment-title">{avatar.name}</div>
          <div className="ach-moment-cat">{RARITY_LABEL[kindKey] || "Common"}</div>
          {equippedSlots.length > 0 && (
            <div className="gacha-cinematic-powers">
              {equippedSlots.map(slot => {
                const power = getPowerById(assignment[slot]);
                if (!power) return null;
                return (
                  <div key={slot} className="gacha-cinematic-power-chip">
                    <span>{power.name}</span>
                    <span className="gacha-cinematic-power-type">{power.mechanic === "passive" ? "Passive" : "Consumable"}</span>
                  </div>
                );
              })}
            </div>
          )}
          <button className="ach-moment-btn" style={{ "--ach-color": kindStage.color }} onClick={onDismiss}>Awesome! 🎉</button>
        </div>
      )}
    </div>
  );
}

// ---------------------------------------------------------------------------
// Issue #182 — Meowtongs (แมวทอง / coins) shared constants.
// ---------------------------------------------------------------------------
const MEOWTONGS_COLOR = "#E8A33D"; // saffron — same family as the streak/coins accent
const COIN_PARTICLE_COUNT = 6;

// Issue #182 — top-level layer for the coin-shower particles. Rendered as a
// sibling of the toast stack (NOT nested inside .ach-toast), because
// .ach-toast runs a transform-based entrance animation with fill-mode
// "both" — that permanently makes it a containing block for any
// position:fixed descendant (and it also clips via overflow:hidden), which
// would trap the particles instead of letting them fly across the screen.
function CoinFlyLayer({ groups, onGroupDone }) {
  return (
    <>
      {groups.map(g => (
        <div
          key={g.id}
          className="coin-fly-particles"
          style={{ left: g.originX, top: g.originY, "--dx": `${g.dx}px`, "--dy": `${g.dy}px` }}
        >
          {Array.from({ length: COIN_PARTICLE_COUNT }).map((_, i) => (
            <img
              key={i}
              src="/coins/catcoin.png"
              alt=""
              className="coin-fly-particle"
              style={{ "--idx": i }}
              onAnimationEnd={i === COIN_PARTICLE_COUNT - 1 ? () => onGroupDone(g.id) : undefined}
            />
          ))}
        </div>
      ))}
    </>
  );
}

